                                    <div className="grid grid-cols-3 sm:grid-cols-4 lg:grid-cols-5 gap-3">
                                        {items.map(bed => {
                                            const isAvailable = bed.status === 'available';
                                            const isSelected = selectedBed?.id === bed.id;
                                            return (
                                                <div 
                                                  key={bed.id} 
