            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1.5">{t('billing_modal_create_items_label')}</label>
            <div className="space-y-2 max-h-60 overflow-y-auto pr-1">
              {createForm.items.map((item, index) => (
                <div key={index} className="flex flex-col sm:flex-row gap-2 items-start sm:items-center bg-slate-50 dark:bg-slate-900 p-2 rounded-lg border border-slate-100 dark:border-slate-800">
                    <select className="w-full sm:w-1/3 text-xs p-2 rounded border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white" onChange={(e) => handleCatalogSelect(index, e.target.value)} defaultValue=""><option value="" disabled>{t('billing_modal_create_quick_add')}</option>{catalogItems.map((c, i) => <option key={i} value={c.label}>{c.label}</option>)}</select>
                    <Input placeholder={t('billing_modal_create_item_placeholder')} value={item.description} onChange={e => handleItemChange(index, 'description', e.target.value)} className="flex-1" />
                    <div className="flex gap-2 w-full sm:w-auto">
                        <Input placeholder="0.00" type="number" value={item.amount} onChange={e => handleItemChange(index, 'amount', e.target.value)} className="w-24" />
                        <button type="button" onClick={() => handleRemoveItem(index)} className="text-red-500 p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg"><Trash2 size={16}/></button>
                    </div>
                </div>
              ))}
            </div>
            <Button size="sm" variant="secondary" onClick={handleAddItem} className="mt-2 w-full" icon={Plus}>{t('billing_modal_create_add_item_button')}</Button>
          </div>
          <div className="grid grid-cols-2 gap-4 border-t dark:border-slate-700 pt-4">
            <div>
              <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t('billing_modal_create_tax_rate')}</label>
              <select className="w-full rounded-xl border border-slate-300 dark:border-slate-700 p-2.5 text-sm bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value={createForm.selectedTaxId} onChange={e => setCreateForm({...createForm, selectedTaxId: e.target.value})}>
                <option value="">{t('billing_modal_create_none')}</option>
                {taxRates.filter(t => t.isActive).map(t => (<option key={t.id} value={t.id}>{language === 'ar' ? t.name_ar : t.name_en} ({t.rate}%)</option>))}
              </select>
            </div>
            <div className="text-right flex flex-col justify-center">
              <span className="block text-xs text-slate-500 dark:text-slate-400 uppercase font-bold tracking-wider">{t('billing_modal_create_total_label')}</span>
              <span className="text-3xl font-bold text-primary-600">${(() => { const subtotal = createForm.items.reduce((sum, i) => sum + (parseFloat(i.amount) || 0), 0); const taxRate = taxRates.find(t => t.id === parseInt(createForm.selectedTaxId)); const tax = taxRate ? (subtotal * taxRate.rate) / 100 : 0; return (subtotal + tax).toFixed(2); })()}</span>
            </div>
          </div>
          <div className="flex justify-end pt-4 border-t dark:border-slate-700 gap-3"><Button type="button" variant="secondary" onClick={() => setIsCreateModalOpen(false)}>{t('cancel')}</Button><Button type="submit" disabled={isProcessing || !createForm.patientId}>{isProcessing ? t('processing') : t('billing_modal_create_generate_button')}</Button></div>
        </form>
      </Modal>

      <Modal isOpen={isPaymentModalOpen} onClose={() => setIsPaymentModalOpen(false)} title={t('billing_modal_payment_title')}>
        {payingBill && (
          <form onSubmit={handlePaymentSubmit} className="space-y-6">
            <div className="text-center p-6 bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-inner">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{t('billing_modal_payment_balance_due')}</p>
                <p className="text-5xl font-black text-slate-900 dark:text-white font-mono tracking-tighter">${(payingBill.totalAmount - (payingBill.paidAmount || 0)).toLocaleString()}</p>
            </div>
            <Select label={t('billing_modal_payment_method')} value={paymentForm.method} onChange={e => setPaymentForm({...paymentForm, method: e.target.value})} required className="text-slate-900 dark:text-white">
                {getFilteredPaymentMethods().map(p => (<option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>))}
            </Select>
            <div className="space-y-4">
                {paymentForm.method.toLowerCase() === 'cash' && (<><Input label={t('billing_table_header_amount')} type="number" value={paymentForm.amount} onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})} required /><Textarea label={t('patients_modal_action_notes')} rows={2} value={paymentForm.notes} onChange={e => setPaymentForm({...paymentForm, notes: e.target.value})} /></>)}
                {paymentForm.method.toLowerCase() === 'insurance' && (<div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-900/30 animate-in slide-in-from-top-2"><Input label={t('billing_table_header_amount')} type="number" value={paymentForm.amount} onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})} required className="md:col-span-2" /><div className="md:col-span-2"><Select label={t('patients_modal_form_insurance_provider')} value={paymentForm.insuranceProvider} onChange={e => setPaymentForm({...paymentForm, insuranceProvider: e.target.value})} required className="text-slate-900 dark:text-white"><option value="">{t('patients_modal_form_insurance_provider_select')}</option>{insuranceProviders.map(p => <option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>)}</Select></div><Input label={t('patients_modal_form_insurance_policy')} value={paymentForm.policyNumber} onChange={e => setPaymentForm({...paymentForm, policyNumber: e.target.value})} required /><Input label={t('patients_modal_form_insurance_expiry')} type="date" value={paymentForm.expiryDate} onChange={e => setPaymentForm({...expiryDate, expiryDate: e.target.value})} required /></div>)}
                {paymentForm.method.toLowerCase() !== 'cash' && paymentForm.method.toLowerCase() !== 'insurance' && (<div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 animate-in slide-in-from-top-2"><Input label={t('billing_table_header_amount')} type="number" value={paymentForm.amount} onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})} required className="md:col-span-2" /><Input label={t('billing_modal_payment_ref')} value={paymentForm.transactionId} onChange={e => setPaymentForm({...paymentForm, transactionId: e.target.value})} required /><Input label={t('date')} type="date" value={paymentForm.date} onChange={e => setPaymentForm({...paymentForm, date: e.target.value})} required /></div>)}
            </div>
            <div className="flex justify-end pt-4 border-t dark:border-slate-700 gap-3"><Button type="button" variant="secondary" onClick={() => setIsPaymentModalOpen(false)}>{t('cancel')}</Button><Button type="submit" icon={isProcessing ? undefined : CheckCircle} disabled={isProcessing}>{isProcessing ? t('processing') : t('billing_modal_payment_confirm_button')}</Button></div>
          </form>
        )}
      </Modal>

      <Modal isOpen={isExpenseModalOpen} onClose={() => setIsExpenseModalOpen(false)} title={editingExpenseId ? "Update Expense Entry" : t('billing_modal_expense_title')}>
        <form onSubmit={handleExpenseSubmit} className="space-y-4">
          <Select label={t('billing_modal_expense_category')} value={expenseForm.category} onChange={e => setExpenseForm({...expenseForm, category: e.target.value})} required className="text-slate-900 dark:text-white">
            <option value="General">{t('billing_modal_expense_cat_general')}</option>
            <option value="Pharmacy Refill">Pharmacy Inventory Refill</option>
            <option value="Laboratory Supplies">Lab Reagents & Consumables</option>
            <option value="Medical Supplies">{t('billing_modal_expense_cat_supplies')}</option>
            <option value="Staff Salaries">Staff Monthly Salaries</option>
            <option value="Facility Rent">Facility / Real Estate Rent</option>
            <option value="Utilities">{t('billing_modal_expense_cat_utilities')}</option>
            <option value="Facility Maintenance">{t('billing_modal_expense_cat_maintenance')}</option>
            <option value="Medical Equipment">{t('billing_modal_expense_cat_equipment')}</option>
          </Select>
          <div className="grid grid-cols-2 gap-4">
            <Input label={t('billing_modal_expense_amount')} type="number" required value={expenseForm.amount} onChange={e => setExpenseForm({...expenseForm, amount: e.target.value})} />
            <Input label={t('date')} type="date" required value={expenseForm.date} onChange={e => setExpenseForm({...expenseForm, date: e.target.value})} />
          </div>
          <Select label={t('billing_modal_expense_method')} value={expenseForm.method} onChange={e => setExpenseForm({...expenseForm, method: e.target.value})} required className="text-slate-900 dark:text-white">
            {getFilteredPaymentMethods().length === 0 ? <option value="">No methods configured</option> : getFilteredPaymentMethods().map(p => (<option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>))}
          </Select>
          <Textarea label={t('billing_modal_expense_description')} rows={3} required value={expenseForm.description} onChange={e => setExpenseForm({...expenseForm, description: e.target.value})} />
          <div className="flex justify-end pt-4 gap-3 border-t dark:border-slate-700">
            <Button type="button" variant="secondary" onClick={() => setIsExpenseModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit" disabled={isProcessing}>{isProcessing ? t('processing') : (editingExpenseId ? t('save') : t('billing_modal_expense_save'))}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={!!selectedBill} onClose={() => setSelectedBill(null)} title={t('billing_modal_preview_title')}>
        {selectedBill && (<div><InvoiceView bill={selectedBill} /><div className="mt-6 flex justify-end gap-3 no-print"><Button variant="secondary" onClick={() => setSelectedBill(null)}>{t('close')}</Button><Button icon={Printer} onClick={() => window.print()}>{t('billing_modal_preview_print_button')}</Button></div></div>)}
      </Modal>
      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({ ...confirmState, isOpen: false })} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message} />
    </div>
  );
};

const getTypeColor = (type: string) => {
    switch (type) {
      case 'Admission': return 'orange';
      case 'Operation': return 'red';
      case 'Lab Test': return 'purple';
      case 'Appointment': return 'blue';
      case 'Procedure': return 'cyan';
      default: return 'gray';
    }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Plus, Search, Briefcase, Clock, 
  Calendar, DollarSign, Wallet,
  Loader2, Edit, Trash2, MapPin,
  LogIn, LogOut, CheckCircle, XCircle
} from 'lucide-react';
import { api } from '../services/api';
import { MedicalStaff, Attendance, LeaveRequest, PayrollRecord, FinancialAdjustment } from '../types';
import { hasPermission, Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';
import { useHeader } from '../context/HeaderContext';

const DAYS_OF_WEEK_EN = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
const DAYS_OF_WEEK_AR = ['إث', 'ثل', 'أر', 'خم', 'جم', 'سب', 'أح'];

const roleDepartmentMap: Record<string, string[]> = {
  doctor: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Dermatology', 'Radiology', 'Anesthesiology', 'Internal Medicine'],
  nurse: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Internal Medicine'],
  technician: ['Radiology', 'Laboratory'],
  anesthesiologist: ['Anesthesiology', 'General Surgery'],
  pharmacist: ['Pharmacy'],
  hr_manager: ['Administration', 'HR'],
  accountant: ['Finance', 'Administration'],
  manager: ['Administration', 'Management'],
  staff: ['Administration', 'Maintenance', 'Security', 'Support Services', 'Finance', 'IT Support'],
  medical_assistant: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'General Surgery', 'Internal Medicine'],
  receptionist: ['Administration', 'Front Desk']
};

export const Staff = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'directory' | 'attendance' | 'leaves' | 'payroll' | 'financials'>('directory');
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const { user: currentUser } = useAuth();
  const [loading, setLoading] = useState(true);

  const DAYS_OF_WEEK = language === 'ar' ? DAYS_OF_WEEK_AR : DAYS_OF_WEEK_EN;
  const canManageHR = hasPermission(currentUser, Permissions.MANAGE_HR);

  // Sync Header
  useHeader(
    t('staff_title'),
    t('staff_subtitle'),
    <div className="flex gap-2">
      {activeTab === 'directory' && canManageHR && <Button onClick={() => openStaffModal()} icon={Plus}>{t('staff_add_employee_button')}</Button>}
      {activeTab === 'leaves' && <Button icon={Plus} onClick={() => setIsLeaveModalOpen(true)}>{t('staff_leave_request')}</Button>}
      {activeTab === 'payroll' && canManageHR && <Button icon={DollarSign} onClick={handleGeneratePayroll}>{t('staff_generate_payroll')}</Button>}
      {activeTab === 'financials' && canManageHR && <Button icon={Plus} onClick={() => setIsAdjustmentModalOpen(true)}>{t('staff_financial_add_entry')}</Button>}
    </div>
  );

  // Tab specific data
  const [attendance, setAttendance] = useState<Attendance[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>([]);
  const [payroll, setPayroll] = useState<PayrollRecord[]>([]);
  const [financials, setFinancials] = useState<FinancialAdjustment[]>([]);

  // Catalogs for dropdowns
  const [departments, setDepartments] = useState<any[]>([]);
  const [specializations, setSpecializations] = useState<any[]>([]);
  const [banks, setBanks] = useState<any[]>([]);

  // UI States
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false); 
  const [isAdjustmentModalOpen, setIsAdjustmentModalOpen] = useState(false); 
  const [isLeaveModalOpen, setIsLeaveModalOpen] = useState(false); 
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]); 
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7)); 

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  const [staffForm, setStaffForm] = useState<any>({});
  const [adjForm, setAdjForm] = useState({ staffId: '', type: 'bonus', amount: '', reason: '', date: new Date().toISOString().split('T')[0] });
  const [leaveForm, setLeaveForm] = useState({ staffId: '', type: 'sick', startDate: '', endDate: '', reason: '' });
  const [attendanceModal, setAttendanceModal] = useState<any>(null);

  const loadData = async (isBackground = false) => {
    if (!isBackground) setLoading(true);
    try {
      const [data, depts, specs, bankData] = await Promise.all([
        api.getStaff(), api.getDepartments(), api.getSpecializations(), api.getBanks()
      ]);
      setStaff(Array.isArray(data) ? data : []);
      setDepartments(Array.isArray(depts) ? depts : []);
      setSpecializations(Array.isArray(specs) ? specs : []);
      setBanks(Array.isArray(bankData) ? bankData : []);
    } catch (e) { console.error(e); } finally { if (!isBackground) setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  useEffect(() => {
    const fetchTabData = async () => {
        if (activeTab === 'attendance') setAttendance(await api.getAttendance(selectedDate));
        else if (activeTab === 'leaves') setLeaves(await api.getLeaves());
        else if (activeTab === 'payroll') setPayroll(await api.getPayroll(selectedMonth));
        else if (activeTab === 'financials') setFinancials(await api.getFinancials('all'));
    };
    if(activeTab !== 'directory') fetchTabData();
  }, [activeTab, selectedDate, selectedMonth]);

  const handleCreateStaff = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessStatus('processing');
    const { bankName, bankAccount, ...restOfForm } = staffForm;
    const payload = { ...restOfForm, bankDetails: { bankName, bankAccount } };
    try {
      if (staffForm.id) await api.updateStaff(staffForm.id, payload);
      else await api.addStaff(payload);
      setProcessStatus('success');
      await loadData(true);
      setTimeout(() => { setIsModalOpen(false); setProcessStatus('idle'); }, 500);
    } catch (err: any) { setProcessStatus('error'); setProcessMessage(err.response?.data?.error || t('staff_save_fail')); }
  };

  const openStaffModal = (s?: MedicalStaff) => {
      let bankDetailsParsed = { bankName: '', bankAccount: '' };
      if (s?.bankDetails) {
          if (typeof s.bankDetails === 'object' && s.bankDetails !== null) bankDetailsParsed = { bankName: s.bankDetails.bankName, bankAccount: s.bankDetails.bankAccount };
          else if (typeof s.bankDetails === 'string') bankDetailsParsed = { bankName: s.bankDetails, bankAccount: '' };
      }
      setStaffForm(s ? { ...s, address: s.address || '', ...bankDetailsParsed } : { fullName: '', type: 'doctor', status: 'active', baseSalary: '', availableDays: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'], availableTimeStart: '09:00', availableTimeEnd: '17:00', consultationFee: '', joinDate: new Date().toISOString().split('T')[0], address: '', ...bankDetailsParsed });
      setIsModalOpen(true);
  };

  const toggleDay = (day: string) => {
      const currentDays = staffForm.availableDays || [];
      const dayEN = DAYS_OF_WEEK_EN[DAYS_OF_WEEK.indexOf(day)];
      setStaffForm({ ...staffForm, availableDays: currentDays.includes(dayEN) ? currentDays.filter((d: string) => d !== dayEN) : [...currentDays, dayEN] });
  };

  const filteredDepartments = useMemo(() => {
    if (!staffForm.type) return departments;
    const allowedDepts = roleDepartmentMap[staffForm.type];
    return !allowedDepts ? departments : departments.filter(d => allowedDepts.includes(d.name_en));
  }, [staffForm.type, departments]);

  const filteredSpecializations = useMemo(() => {
    return !staffForm.type ? specializations : specializations.filter(s => !s.related_role || s.related_role === staffForm.type);
  }, [staffForm.type, specializations]);

  const handleCheckIn = (staffMember: MedicalStaff) => {
    setConfirmState({
        isOpen: true, title: t('staff_attendance_confirm'), message: t('staff_attendance_checkin_confirm', {name: staffMember.fullName, time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}),
        action: async () => {
            setProcessStatus('processing');
            try {
                const now = new Date();
                const timeString = now.toTimeString().slice(0, 5);
                await api.markAttendance({ staffId: staffMember.id, date: selectedDate, status: staffMember.availableTimeStart && timeString > staffMember.availableTimeStart ? 'late' : 'present', checkIn: timeString });
                setAttendance(await api.getAttendance(selectedDate));
                setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) { setProcessStatus('error'); setProcessMessage(e.message || t('staff_attendance_mark_fail')); }
        }
    });
  };

  const handleCheckOut = (record: Attendance) => {
    setConfirmState({
        isOpen: true, title: t('staff_attendance_confirm'), message: t('staff_attendance_checkout_confirm', {name: record.staffName}),
        action: async () => {
            setProcessStatus('processing');
            try {
                await api.markAttendance({ staffId: record.staffId, date: record.date, status: record.status, checkOut: new Date().toTimeString().slice(0, 5) });
                setAttendance(await api.getAttendance(selectedDate));
                setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) { setProcessStatus('error'); }
        }
    });
  };

  const openAttendanceModal = (staffId: number, staffName: string, status: any) => {
      const existing = attendance.find(a => a.staffId === staffId);
      setAttendanceModal({ isOpen: true, staffId, staffName, status: existing?.status || status, checkIn: existing?.checkIn || '', checkOut: existing?.checkOut || '' });
  };

  const handleAttendanceSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      try {
          await api.markAttendance({ staffId: attendanceModal.staffId, date: selectedDate, status: attendanceModal.status, checkIn: attendanceModal.checkIn || null, checkOut: attendanceModal.checkOut || null });
          setAttendance(await api.getAttendance(selectedDate));
          setProcessStatus('success'); setTimeout(() => { setProcessStatus('idle'); setAttendanceModal(null); }, 500);
      } catch (err: any) { setProcessStatus('error'); }
  };

  const handleLeaveRequest = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      try {
        await api.requestLeave(leaveForm);
        setLeaves(await api.getLeaves());
        setProcessStatus('success'); setTimeout(() => { setIsLeaveModalOpen(false); setProcessStatus('idle'); }, 1000);
      } catch (e: any) { setProcessStatus('error'); }
  };

  const updateLeaveStatus = (id: number, status: string) => {
      setConfirmState({
        isOpen: true, title: status === 'approved' ? t('hr_approve') : t('hr_reject'), message: t('confirm'),
        action: async () => {
            setProcessStatus('processing');
            try {
                await api.updateLeaveStatus(id, status);
                setLeaves(await api.getLeaves());
                setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) { setProcessStatus('error'); }
        }
      });
  };

  const handleGeneratePayroll = () => {
      setConfirmState({
          isOpen: true, title: t('staff_tab_payroll'), message: t('staff_generate_payroll_confirm', {month: selectedMonth}),
          action: async () => {
              setProcessStatus('processing');
              try {
                  await api.generatePayroll({ month: selectedMonth });
                  setPayroll(await api.getPayroll(selectedMonth));
                  setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
              } catch(e: any) { setProcessStatus('error'); }
          }
      });
  };

  const handleMarkPaid = (record: PayrollRecord) => {
      setConfirmState({
          isOpen: true, title: t('confirm'), message: t('staff_payroll_paid_confirm', {name: record.staffName}),
          action: async () => {
              setProcessStatus('processing');
              try {
                  await api.updatePayrollStatus(record.id, 'paid');
                  setPayroll(await api.getPayroll(selectedMonth));
                  setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
              } catch(e: any) { setProcessStatus('error'); }
          }
      });
  };

  const handleAdjustmentSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      try {
        await api.addAdjustment({ ...adjForm, amount: parseFloat(adjForm.amount) });
        setFinancials(await api.getFinancials('all'));
        setProcessStatus('success'); setTimeout(() => { setIsAdjustmentModalOpen(false); setProcessStatus('idle'); }, 1000);
      } catch (e: any) { setProcessStatus('error'); }
  };

  const sortedStaff = staff.filter(s => s.fullName.toLowerCase().includes(searchTerm.toLowerCase())).sort((a, b) => (a.status === 'active' ? -1 : 1));

  return (
    <div className="space-y-6">
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <><Loader2 className="w-16 h-16 text-primary-600 animate-spin mb-4" /><h3 className="font-bold">{t('processing')}</h3></>}
            {processStatus === 'success' && <><CheckCircle size={48} className="text-green-600 mb-4" /><h3 className="font-bold">{t('success')}</h3></>}
            {processStatus === 'error' && <><XCircle size={48} className="text-red-600 mb-4" /><h3 className="font-bold">{t('patients_process_title_failed')}</h3><p className="text-sm text-red-500 mt-2">{processMessage}</p><Button variant="secondary" className="mt-4 w-full" onClick={() => setProcessStatus('idle')}>{t('close')}</Button></>}
          </div>
        </div>
      )}

      <div className="flex bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-x-auto w-fit">
          {[
              { id: 'directory', label: t('staff_tab_directory'), icon: Briefcase },
              { id: 'attendance', label: t('staff_tab_attendance'), icon: Clock },
              { id: 'leaves', label: t('staff_tab_leaves'), icon: Calendar },
              { id: 'payroll', label: t('staff_tab_payroll'), icon: DollarSign },
              { id: 'financials', label: t('staff_tab_financials'), icon: Wallet },
          ].map(tab => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}><tab.icon size={16} /> {tab.label}</button>
          ))}
      </div>

      {activeTab === 'directory' && (
          <div className="animate-in fade-in">
              <div className="relative w-full sm:w-72 mb-6"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" /><input type="text" placeholder={t('staff_search_placeholder')} className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/></div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{sortedStaff.map(person => (<div key={person.id} className="bg-white dark:bg-slate-800 p-5 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm hover:shadow-md transition-all group"><div className="flex justify-between items-start mb-4"><div className="flex items-center gap-3"><div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg text-white bg-slate-400`}>{person.fullName.charAt(0)}</div><div><h3 className="font-bold text-slate-800 dark:text-white line-clamp-1">{person.fullName}</h3><Badge color="blue">{t(`staff_role_${person.type}`)}</Badge></div></div><div className={`w-2 h-2 rounded-full ${person.status === 'active' ? 'bg-green-500' : 'bg-gray-300'}`}></div></div><div className="space-y-2 text-sm text-slate-500 dark:text-slate-400 mb-4"><div className="flex items-center gap-2"><Briefcase size={14}/> {person.department || t('patients_modal_view_na')}</div><div className="flex items-center gap-2"><MapPin size={14}/> {person.phone || t('patients_modal_view_na')}</div></div>{canManageHR && <Button variant="outline" className="w-full" onClick={() => openStaffModal(person)}>{t('edit')}</Button>}</div>))}</div>
          </div>
      )}

      {activeTab === 'attendance' && (
          <div className="animate-in fade-in space-y-4">
              <div className="flex justify-end"><Input type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} className="w-auto" /></div>
              <div className="bg-white dark:bg-slate-800 rounded-xl border overflow-hidden"><table className="w-full text-sm text-left"><thead className="bg-slate-50 dark:bg-slate-900"><tr><th className="px-4 py-3">{t('staff_form_role_title')}</th><th className="px-4 py-3">{t('status')}</th><th className="px-4 py-3">{t('staff_attendance_time')}</th><th className="px-4 py-3">Check Out</th>{canManageHR && <th className="px-4 py-3 text-right">{t('actions')}</th>}</tr></thead><tbody className="divide-y">{staff.filter(s => s.status === 'active').map(s => { const record = attendance.find(a => a.staffId === s.id); return (<tr key={s.id} className="hover:bg-slate-50"><td><div className="px-4 py-3"><div className="font-bold">{s.fullName}</div><div className="text-xs text-slate-400">{t(`staff_role_${s.type}`)}</div></div></td><td className="px-4 py-3">{record ? <Badge color={record.status === 'present' ? 'green' : 'yellow'}>{record.status}</Badge> : '-'}</td><td className="px-4 py-3 font-mono">{record?.checkIn || '-'}</td><td className="px-4 py-3 font-mono">{record?.checkOut || '-'}</td>{canManageHR && <td className="px-4 py-3 text-right"><div className="flex justify-end gap-2">{!record?.checkIn && <Button size="sm" onClick={() => handleCheckIn(s)}>In</Button>}{record?.checkIn && !record?.checkOut && <Button size="sm" variant="secondary" onClick={() => handleCheckOut(record)}>Out</Button>}<Button size="sm" variant="ghost" onClick={() => openAttendanceModal(s.id, s.fullName, 'present')}><Edit size={14}/></Button></div></td>}</tr>)})}</tbody></table></div>
          </div>
      )}

      {activeTab === 'leaves' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in">
              {leaves.length === 0 ? <p className="col-span-full text-center text-slate-400 py-10">{t('staff_no_leaves')}</p> : leaves.map(leave => (<div key={leave.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl border shadow-sm relative overflow-hidden"><div className={`absolute top-0 left-0 w-1 h-full ${leave.status === 'approved' ? 'bg-green-500' : 'bg-yellow-500'}`}></div><div className="flex justify-between items-start mb-2"><h4 className="font-bold">{leave.staffName}</h4><Badge color={leave.status === 'approved' ? 'green' : 'yellow'}>{leave.status}</Badge></div><div className="text-sm text-slate-500"><p>{leave.type} • {new Date(leave.startDate).toLocaleDateString()} - {new Date(leave.endDate).toLocaleDateString()}</p><p className="italic mt-2">"{leave.reason}"</p></div>{canManageHR && leave.status === 'pending' && <div className="flex gap-2 mt-4"><Button size="sm" className="flex-1 bg-green-600 border-none text-white" onClick={() => updateLeaveStatus(leave.id, 'approved')}>{t('hr_approve')}</Button><Button size="sm" variant="danger" className="flex-1" onClick={() => updateLeaveStatus(leave.id, 'rejected')}>{t('hr_reject')}</Button></div>}</div>))}
          </div>
      )}

      {activeTab === 'payroll' && (
          <div className="animate-in fade-in space-y-4">
              <div className="flex justify-start"><Input type="month" value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-auto" /></div>
              <div className="overflow-x-auto bg-white dark:bg-slate-800 rounded-xl border"><table className="min-w-full text-sm text-left"><thead className="bg-slate-50 dark:bg-slate-900"><tr><th className="px-4 py-3">{t('staff_form_role_title')}</th><th className="px-4 py-3 text-right">{t('staff_payroll_base')}</th><th className="px-4 py-3 text-right font-bold">{t('staff_payroll_net')}</th><th className="px-4 py-3 text-center">{t('status')}</th>{canManageHR && <th className="px-4 py-3"></th>}</tr></thead><tbody className="divide-y">{payroll.length === 0 ? <tr><td colSpan={5} className="text-center py-8">{t('staff_payroll_empty')}</td></tr> : payroll.map(p => (<tr key={p.id}><td><div className="px-4 py-3 font-medium">{p.staffName}</div></td><td className="px-4 py-3 text-right font-mono">${p.baseSalary.toLocaleString()}</td><td className="px-4 py-3 text-right font-mono font-bold">${p.netSalary.toLocaleString()}</td><td className="px-4 py-3 text-center"><Badge color={p.status === 'paid' ? 'green' : 'yellow'}>{p.status}</Badge></td><td className="px-4 py-3 text-right">{p.status === 'draft' && <Button size="sm" onClick={() => handleMarkPaid(p)}>Pay</Button>}</td></tr>))}</tbody></table></div>
          </div>
      )}

      {activeTab === 'financials' && (
          <div className="bg-white dark:bg-slate-800 rounded-xl border overflow-hidden animate-in fade-in"><table className="min-w-full text-sm text-left"><thead className="bg-slate-50 dark:bg-slate-900"><tr><th className="px-4 py-3">{t('date')}</th><th className="px-4 py-3">{t('staff_form_role_title')}</th><th className="px-4 py-3">{t('appointments_form_type')}</th><th className="px-4 py-3 text-right">{t('billing_table_header_amount')}</th></tr></thead><tbody className="divide-y">{financials.map(f => (<tr key={f.id}><td className="px-4 py-3">{new Date(f.date).toLocaleDateString()}</td><td className="px-4 py-3 font-medium">{f.staffName}</td><td className="px-4 py-3"><Badge color={f.type === 'bonus' ? 'green' : 'red'}>{f.type}</Badge></td><td className={`px-4 py-3 text-right font-mono font-bold ${f.type === 'bonus' ? 'text-green-600' : 'text-red-600'}`}>${f.amount.toLocaleString()}</td></tr>))}</tbody></table></div>
      )}

      {/* MODALS */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={staffForm.id ? t('staff_edit_employee') : t('staff_add_employee_button')}>
        <form onSubmit={handleCreateStaff} className="space-y-4 max-h-[80vh] overflow-y-auto pr-2 custom-scrollbar">
          <div className="grid grid-cols-2 gap-4"><Input label={t('patients_modal_form_fullName')} required value={staffForm.fullName} onChange={e => setStaffForm({...staffForm, fullName: e.target.value})} /><Select label={t('staff_form_role')} value={staffForm.type} onChange={e => setStaffForm({...staffForm, type: e.target.value})}><option value="doctor">{t('staff_role_doctor')}</option><option value="nurse">{t('staff_role_nurse')}</option><option value="technician">{t('staff_role_technician')}</option></Select></div>
          <div className="grid grid-cols-2 gap-4"><Select label={t('staff_form_department')} value={staffForm.department || ''} onChange={e => setStaffForm({...staffForm, department: e.target.value})}><option value="">Select...</option>{departments.map((d: any) => <option key={d.id} value={d.name_en}>{d.name_en}</option>)}</Select><Select label={t('staff_form_specialization')} value={staffForm.specialization || ''} onChange={e => setStaffForm({...staffForm, specialization: e.target.value})}><option value="">Select...</option>{specializations.map((s: any) => <option key={s.id} value={s.name_en}>{s.name_en}</option>)}</Select></div>
          <div className="grid grid-cols-2 gap-4"><Input label={t('staff_form_base_salary')} type="number" required value={staffForm.baseSalary} onChange={e => setStaffForm({...staffForm, baseSalary: e.target.value})} /><Input label={t('staff_form_consultation_fee')} type="number" value={staffForm.consultationFee} onChange={e => setStaffForm({...staffForm, consultationFee: e.target.value})} /></div>
          <div className="pt-4 border-t"><h4 className="text-sm font-bold text-slate-500 mb-2">{t('staff_form_availability')}</h4><div className="flex flex-wrap gap-2 mb-3">{DAYS_OF_WEEK.map((day) => (<button key={day} type="button" onClick={() => toggleDay(day)} className={`w-8 h-8 rounded-full text-xs font-bold ${ (staffForm.availableDays || []).includes(DAYS_OF_WEEK_EN[DAYS_OF_WEEK.indexOf(day)]) ? 'bg-primary-600 text-white' : 'bg-slate-100'}`}>{day}</button>))}</div><div className="grid grid-cols-2 gap-4"><Input label={t('staff_form_start_time')} type="time" value={staffForm.availableTimeStart} onChange={e => setStaffForm({...staffForm, availableTimeStart: e.target.value})} /><Input label={t('staff_form_end_time')} type="time" value={staffForm.availableTimeEnd} onChange={e => setStaffForm({...staffForm, availableTimeEnd: e.target.value})} /></div></div>
          <div className="flex justify-end pt-4 gap-3 border-t"><Button type="button" variant="secondary" onClick={() => setIsModalOpen(false)}>{t('cancel')}</Button><Button type="submit">{t('save')}</Button></div>
        </form>
      </Modal>

      <Modal isOpen={!!attendanceModal} onClose={() => setAttendanceModal(null)} title={t('staff_modal_attendance_title')}>
          {attendanceModal && (<form onSubmit={handleAttendanceSubmit} className="space-y-4"><div className="bg-slate-50 p-3 rounded-lg text-center"><p className="font-bold">{attendanceModal.staffName}</p></div><Select label={t('status')} value={attendanceModal.status} onChange={e => setAttendanceModal({...attendanceModal, status: e.target.value})}><option value="present">Present</option><option value="late">Late</option><option value="absent">Absent</option></Select><div className="grid grid-cols-2 gap-4"><Input label="In" type="time" value={attendanceModal.checkIn} onChange={e => setAttendanceModal({...attendanceModal, checkIn: e.target.value})} /><Input label="Out" type="time" value={attendanceModal.checkOut} onChange={e => setAttendanceModal({...attendanceModal, checkOut: e.target.value})} /></div><div className="flex justify-end pt-4 gap-3"><Button type="button" variant="secondary" onClick={() => setAttendanceModal(null)}>{t('cancel')}</Button><Button type="submit">{t('save')}</Button></div></form>)}
      </Modal>

      <Modal isOpen={isLeaveModalOpen} onClose={() => setIsLeaveModalOpen(false)} title={t('staff_leave_request')}><form onSubmit={handleLeaveRequest} className="space-y-4"><Select label={t('staff_form_role_title')} required value={leaveForm.staffId} onChange={e => setLeaveForm({...leaveForm, staffId: e.target.value})}><option value="">Select Employee...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}</Select><div className="grid grid-cols-2 gap-4"><Input label="Start" type="date" required value={leaveForm.startDate} onChange={e => setLeaveForm({...leaveForm, startDate: e.target.value})} /><Input label="End" type="date" required value={leaveForm.endDate} onChange={e => setLeaveForm({...leaveForm, endDate: e.target.value})} /></div><Textarea label={t('appointments_form_reason')} required value={leaveForm.reason} onChange={e => setLeaveForm({...leaveForm, reason: e.target.value})} /><Button type="submit" className="w-full">{t('submit')}</Button></form></Modal>

      <Modal isOpen={isAdjustmentModalOpen} onClose={() => setIsAdjustmentModalOpen(false)} title={t('staff_financial_add_entry')}><form onSubmit={handleAdjustmentSubmit} className="space-y-4"><Select label={t('staff_form_role_title')} required value={adjForm.staffId} onChange={e => setAdjForm({...adjForm, staffId: e.target.value})}><option value="">Select Employee...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}</Select><Select label="Type" value={adjForm.type} onChange={e => setAdjForm({...adjForm, type: e.target.value})}><option value="bonus">Bonus</option><option value="fine">Fine</option></Select><Input label="Amount" type="number" required value={adjForm.amount} onChange={e => setAdjForm({...adjForm, amount: e.target.value})} /><Textarea label="Reason" required value={adjForm.reason} onChange={e => setAdjForm({...adjForm, reason: e.target.value})} /><Button type="submit" className="w-full">{t('save')}</Button></form></Modal>

      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({ ...confirmState, isOpen: false })} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message}/>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, Button, Badge, Modal, Input, Textarea } from '../components/UI';
import { FlaskConical, CheckCircle, Search, Clock, FileText, User, ChevronRight, Activity, History as HistoryIcon, Save } from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

export const Laboratory = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<'queue' | 'history'>('queue');
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  // Sync Header
  useHeader(t('lab_title'), t('lab_subtitle'));

  // Modal State
  const [isProcessModalOpen, setIsProcessModalOpen] = useState(false);
  const [selectedReq, setSelectedReq] = useState<any>(null);
  const [resultForm, setResultForm] = useState({ notes: '', results: '' });
  const [processStatus, setProcessStatus] = useState('idle');

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await api.getPendingLabRequests(); 
      setRequests(Array.isArray(data) ? data : []);
    } catch (e) { console.error(e); } 
    finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  const openProcessModal = (req: any) => {
    setSelectedReq(req);
    setResultForm({ notes: '', results: '' });
    setIsProcessModalOpen(true);
  };

  const handleComplete = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedReq) return;
    setProcessStatus('processing');
    try {
      await api.completeLabRequest(selectedReq.id, resultForm);
      setProcessStatus('success');
      await loadData();
      setTimeout(() => { setIsProcessModalOpen(false); setProcessStatus('idle'); }, 1000);
    } catch (error) { alert(t('lab_save_error')); setProcessStatus('idle'); }
  };

  const filteredRequests = requests.filter(r => {
    const matchesSearch = r.patientName?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesTab = activeTab === 'queue' ? (r.status === 'pending' || r.status === 'confirmed') : (r.status === 'completed');
    return matchesSearch && matchesTab;
  });

  return (
    <div className="space-y-6">
      <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-lg w-fit">
          <button onClick={() => setActiveTab('queue')} className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeTab === 'queue' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}><FlaskConical size={16}/> {t('lab_tab_queue')} <span className="bg-orange-100 text-orange-700 dark:bg-orange-900 text-xs px-2 py-0.5 rounded-full ml-1">{requests.filter(r => r.status !== 'completed').length}</span></button>
          <button onClick={() => setActiveTab('history')} className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 ${activeTab === 'history' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}><HistoryIcon size={16}/> {t('lab_tab_history')}</button>
      </div>

      <Card className="!p-4"><div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" /><input type="text" placeholder={t('lab_search_placeholder')} className="pl-10 w-full sm:w-96 rounded-lg border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 py-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/></div></Card>

      <div className="grid grid-cols-1 gap-4">
        {loading ? <div className="text-center py-20 text-slate-400">{t('lab_loading')}</div> : filteredRequests.length === 0 ? (<div className="text-center py-20 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-xl"><FlaskConical size={48} className="mx-auto mb-4 text-slate-300 dark:text-slate-600" /><p className="text-slate-500 dark:text-slate-400 font-medium">{t('lab_empty', {tab: activeTab === 'queue' ? t('lab_tab_queue') : t('lab_tab_history')})}</p></div>) : 
        filteredRequests.map(req => (<div key={req.id} className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-all flex flex-col sm:flex-row gap-6 items-start sm:items-center group"><div className="flex flex-col items-center justify-center p-3 bg-slate-50 dark:bg-slate-900 rounded-lg min-w-[80px] border border-slate-100 dark:border-slate-700"><span className="text-xs font-bold text-slate-400 uppercase">{new Date(req.created_at).toLocaleString('default', { month: 'short' })}</span><span className="text-xl font-bold text-slate-800 dark:text-slate-200">{new Date(req.created_at).getDate()}</span><span className="text-xs text-slate-400">{new Date(req.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span></div><div className="flex-1"><div className="flex items-center gap-3 mb-1"><h3 className="text-lg font-bold text-slate-800 dark:text-white">{req.patientName}</h3>{req.status === 'completed' ? <Badge color="green"><CheckCircle size={12} className="inline mr-1"/>{t('lab_card_results_ready')}</Badge> : req.status === 'confirmed' ? <Badge color="blue">{t('lab_card_paid')}</Badge> : <Badge color="yellow">{t('lab_card_payment_pending')}</Badge>}</div><p className="text-sm text-slate-500 dark:text-slate-400">{req.testNames || 'Multiple Tests'}</p></div><div className="text-right"><span className="text-xs text-slate-400">{t('config_field_cost')}</span><p className="text-xl font-bold text-slate-800 dark:text-white">${req.projected_cost.toLocaleString()}</p></div><div className="sm:ml-auto">{req.status === 'confirmed' && <Button onClick={() => openProcessModal(req)} icon={Activity}>{t('lab_card_enter_results')}</Button>}{req.status === 'pending' && <div className="text-sm text-orange-600 font-medium flex items-center gap-2 bg-orange-50 p-3 rounded-lg border border-orange-100"><Clock size={16}/><span>{t('lab_card_awaiting_payment')}</span></div>}{req.status === 'completed' && <Button variant="secondary" icon={FileText} onClick={() => openProcessModal(req)}>{t('lab_view_results')}</Button>}</div></div>))
        }
      </div>

      <Modal isOpen={isProcessModalOpen} onClose={() => setIsProcessModalOpen(false)} title={`${t('lab_modal_title')} - ${selectedReq?.patientName}`}>
        <form onSubmit={handleComplete} className="space-y-4"><div><h4 className="font-bold mb-2">{selectedReq?.testNames}</h4><Textarea label={t('lab_modal_findings')} placeholder={t('lab_modal_findings_placeholder')} rows={6} value={resultForm.results} onChange={e => setResultForm({...resultForm, results: e.target.value})} required={selectedReq?.status !== 'completed'} disabled={selectedReq?.status === 'completed'} /></div><Textarea label={t('lab_modal_notes')} placeholder={t('lab_modal_notes_placeholder')} rows={2} value={resultForm.notes} onChange={e => setResultForm({...resultForm, notes: e.target.value})} disabled={selectedReq?.status === 'completed'} /><div className="pt-4 flex justify-end gap-3"><Button type="button" variant="secondary" onClick={() => setIsProcessModalOpen(false)}>{t('close')}</Button>{selectedReq?.status !== 'completed' && (<Button type="submit" icon={Save} disabled={processStatus === 'processing'}>{processStatus === 'processing' ? t('processing') : t('lab_modal_save_button')}</Button>)}</div></form>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, Button, Badge, Modal, Input, Select, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Activity, CheckCircle, Clock, User, Syringe, Plus, Trash2, 
  Calculator, Save, ChevronRight, AlertTriangle, Stethoscope, 
  Package, Zap, Calendar, DollarSign, ChevronDown, ChevronUp, FileText, Briefcase, Search, History, Filter
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

const FEE_RATIOS: Record<string, number> = {
  'anesthesiologist': 0.5,
  'assistant': 0.5,
  'nurse': 0.33,
  'technician': 0.25
};

export const Operations = () => {
  const { t } = useTranslation();
  const [ops, setOps] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [staff, setStaff] = useState<any[]>([]);
  const [activeTab, setActiveTab] = useState<'requests' | 'schedule' | 'history'>('requests');
  const [searchTerm, setSearchTerm] = useState('');

  // Sync Header
  useHeader(t('operations_title'), t('operations_subtitle'));

  const [isEstimateModalOpen, setIsEstimateModalOpen] = useState(false);
  const [selectedOp, setSelectedOp] = useState<any>(null);
  const [expandedSection, setExpandedSection] = useState<string>('team');
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  const [costForm, setCostForm] = useState({ surgeonFee: 0, theaterFee: 0, participants: [] as any[], consumables: [] as any[], equipment: [] as any[], others: [] as any[] });
  const [processStatus, setProcessStatus] = useState('idle');

  const loadData = async () => {
    setLoading(true);
    try {
      const [opsData, staffData] = await Promise.all([api.getScheduledOperations(), api.getStaff()]);
      setOps(opsData); setStaff(staffData);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  const openEstimateModal = (op: any) => {
    let initialSurgeonFee = 0;
    if (op.doctor_id) {
        const doctor = staff.find(s => s.id === op.doctor_id);
        if (doctor) initialSurgeonFee = doctor.consultationFee * 5;
    }
    setCostForm({ surgeonFee: initialSurgeonFee, theaterFee: initialSurgeonFee, participants: [], consumables: [], equipment: [], others: [] });
    setSelectedOp(op);
    setIsEstimateModalOpen(true);
  };

  const handleSurgeonFeeChange = (val: string) => {
    const newFee = parseFloat(val) || 0;
    setCostForm(prev => ({ ...prev, surgeonFee: newFee, theaterFee: newFee, participants: prev.participants.map(p => ({ ...p, fee: Math.round(newFee * (FEE_RATIOS[p.role] || 0)) })) }));
  };

  const addParticipant = () => {
    setCostForm(prev => ({ ...prev, participants: [...prev.participants, { id: Date.now(), role: 'nurse', staffId: '', name: '', fee: Math.round(prev.surgeonFee * 0.33) }] }));
  };

  const updateParticipant = (index: number, field: string, value: any) => {
    setCostForm(prev => {
      const updatedList = [...prev.participants];
      const item = { ...updatedList[index] };
      if (field === 'role') { item.role = value; item.fee = Math.round(prev.surgeonFee * (FEE_RATIOS[value] || 0)); item.staffId = ''; }
      else if (field === 'staffId') { item.staffId = value; item.name = staff.find(s => s.id.toString() === value)?.fullName || ''; }
      else if (field === 'fee') item.fee = parseFloat(value) || 0;
      updatedList[index] = item; return { ...prev, participants: updatedList };
    });
  };

  const calculateTotal = () => {
    const partSum = costForm.participants.reduce((sum, p) => sum + p.fee, 0);
    const conSum = costForm.consumables.reduce((sum, i) => sum + i.cost, 0);
    const eqSum = costForm.equipment.reduce((sum, i) => sum + i.cost, 0);
    const otSum = costForm.others.reduce((sum, i) => sum + i.cost, 0);
    return costForm.surgeonFee + costForm.theaterFee + partSum + conSum + eqSum + otSum;
  };

  const handleProcessSubmit = async () => {
    if (!selectedOp) return;
    setProcessStatus('processing');
    try { await api.processOperationRequest(selectedOp.id, { details: costForm, totalCost: calculateTotal() }); setProcessStatus('success'); setIsEstimateModalOpen(false); loadData(); } catch (e) { alert("Failed to process request"); } finally { setProcessStatus('idle'); }
  };

  const handleCompleteOp = (opId: number) => {
    setConfirmState({ isOpen: true, title: t('operations_dialog_complete_title'), message: t('operations_dialog_complete_message'), action: async () => { try { await api.completeOperation(opId); loadData(); } catch (e) { alert("Failed to update status"); } } });
  };

  const filteredOps = ops.filter(op => { const search = searchTerm.toLowerCase(); return op.patientName.toLowerCase().includes(search) || op.operation_name.toLowerCase().includes(search); });

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row gap-3 w-full lg:w-auto">
          <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" /><input type="text" placeholder={t('operations_search_placeholder')} className="pl-9 pr-4 py-2 w-full sm:w-64 rounded-lg border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none transition-all shadow-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/></div>
          <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-lg shrink-0 overflow-x-auto"><button onClick={() => setActiveTab('requests')} className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'requests' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}><FileText size={16}/> {t('operations_tab_requests')} <span className="bg-primary-100 text-primary-700 text-xs px-2 py-0.5 rounded-full ml-1">{filteredOps.filter(o => o.status === 'requested').length}</span></button><button onClick={() => setActiveTab('schedule')} className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'schedule' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}><Calendar size={16}/> {t('operations_tab_schedule')}</button><button onClick={() => setActiveTab('history')} className={`px-4 py-2 text-sm font-medium rounded-md transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === 'history' ? 'bg-white dark:bg-slate-800 text-primary-600 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}><History size={16}/> {t('operations_tab_history')}</button></div>
      </div>

      {activeTab === 'requests' && (<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">{filteredOps.filter(o => o.status === 'requested' || o.status === 'pending_payment').map(op => (<Card key={op.id} className="relative group border-l-4 border-l-yellow-400"><div className="flex justify-between items-start mb-3"><Badge color={op.status === 'pending_payment' ? 'blue' : 'yellow'}>{op.status === 'pending_payment' ? t('operations_card_awaiting_payment') : t('operations_card_needs_estimation')}</Badge><span className="text-xs text-slate-400">{new Date(op.created_at).toLocaleDateString()}</span></div><h3 className="font-bold text-lg mb-1">{op.operation_name}</h3><p className="text-sm text-slate-500 mb-4">{op.patientName} • Dr. {op.doctorName}</p>{op.status === 'pending_payment' ? (<div className="bg-slate-50 p-3 rounded-lg flex justify-between items-center"><span className="text-sm font-medium">Est. Cost</span><span className="font-bold text-lg">${op.projected_cost.toLocaleString()}</span></div>) : (<Button className="w-full" onClick={() => openEstimateModal(op)} icon={Calculator}>{t('operations_card_process_button')}</Button>)}</Card>))}</div>)}
      {activeTab === 'schedule' && (<Card className="!p-0 overflow-hidden"><table className="min-w-full divide-y"><thead className="bg-slate-50"><tr><th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase">{t('status')}</th><th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase">{t('date')}</th><th className="px-6 py-4 text-left text-xs font-medium text-gray-500 uppercase">{t('operations_schedule_header_procedure')}</th><th className="px-6 py-4 text-right text-xs font-medium text-gray-500 uppercase">{t('actions')}</th></tr></thead><tbody className="bg-white divide-y">{filteredOps.filter(o => o.status === 'confirmed').map(op => (<tr key={op.id} className="hover:bg-slate-50"><td className="px-6 py-4"><Badge color="green">Confirmed</Badge></td><td className="px-6 py-4 text-sm text-gray-500">{new Date(op.created_at).toLocaleDateString()}</td><td className="px-6 py-4"><div className="font-bold">{op.operation_name}</div><div className="text-xs text-slate-400">{op.patientName}</div></td><td className="px-6 py-4 text-right"><Button size="sm" variant="outline" onClick={() => handleCompleteOp(op.id)}>Complete</Button></td></tr>))}</tbody></table></Card>)}

      <Modal isOpen={isEstimateModalOpen} onClose={() => setIsEstimateModalOpen(false)} title={t('operations_modal_title')}>
        <div className="space-y-6 max-h-[85vh] overflow-y-auto pr-2 custom-scrollbar"><div className="bg-slate-900 text-white p-4 rounded-xl shadow-lg flex justify-between items-center sticky top-0 z-10"><div><h4 className="font-bold text-lg">{selectedOp?.operation_name}</h4><p className="text-xs text-slate-400">Dr. {selectedOp?.doctorName}</p></div><div className="text-right"><span className="block text-xs uppercase text-slate-400 font-bold">{t('ops_total_estimate')}</span><span className="text-2xl font-bold text-green-400">${calculateTotal().toLocaleString()}</span></div></div><div className="space-y-4"><Input label={t('operations_modal_surgeon_fee')} type="number" value={costForm.surgeonFee} onChange={e => handleSurgeonFeeChange(e.target.value)} /><Input label={t('operations_modal_theater_fee')} type="number" value={costForm.theaterFee} onChange={e => setCostForm({...costForm, theaterFee: parseFloat(e.target.value) || 0})} /><div className="space-y-3 pt-2"><div className="flex justify-between items-center"><h5 className="text-sm font-bold uppercase">{t('operations_modal_additional_staff')}</h5><Button size="sm" variant="secondary" onClick={addParticipant} icon={Plus} /></div>{costForm.participants.map((p, idx) => (<div key={p.id} className="flex gap-2 items-center bg-slate-50 p-2 rounded-lg border"><select className="w-1/3 rounded-md border-slate-300 text-xs py-1.5" value={p.role} onChange={e => updateParticipant(idx, 'role', e.target.value)}>{Object.keys(FEE_RATIOS).map(r => <option key={r} value={r}>{r}</option>)}</select><select className="flex-1 rounded-md border-slate-300 text-xs py-1.5" value={p.staffId} onChange={e => updateParticipant(idx, 'staffId', e.target.value)}><option value="">Select Staff...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}</select><input type="number" className="w-20 rounded-md border-slate-300 text-xs py-1.5 px-2 font-bold" value={p.fee} onChange={e => updateParticipant(idx, 'fee', e.target.value)} /><button onClick={() => setCostForm(prev => ({...prev, participants: prev.participants.filter((_,i)=>i!==idx)}))} className="text-slate-400 hover:text-red-500"><Trash2 size={14}/></button></div>))}</div></div><div className="pt-4 border-t flex justify-end gap-3 sticky bottom-0 bg-white py-2"><Button variant="secondary" onClick={() => setIsEstimateModalOpen(false)}>{t('cancel')}</Button><Button onClick={handleProcessSubmit} disabled={processStatus === 'processing'} icon={Save}>{processStatus === 'processing' ? t('processing') : t('operations_modal_invoice_button')}</Button></div></div>
      </Modal>

      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({ ...confirmState, isOpen: false })} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message}/>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Select, Input } from '../components/UI';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area, PieChart, Pie, Cell, Legend, LineChart, Line
} from 'recharts';
import { 
  TrendingUp, Users, Calendar, DollarSign, Download, 
  Activity, PieChart as PieChartIcon, ArrowUpRight, ArrowDownRight, Filter, CheckCircle,
  FilePlus, ClipboardList, Briefcase, Clock, CreditCard, Shield
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

export const Reports = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<'financial' | 'operational' | 'demographics' | 'records'>('financial');
  const [rangeType, setRangeType] = useState('30');
  const [customRange, setCustomRange] = useState({ start: '', end: '' });
  const [loading, setLoading] = useState(true);

  const [bills, setBills] = useState<any[]>([]);
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // Date Logic for Header Actions
  const dateRange = useMemo(() => {
    if (rangeType === 'custom') {
        const start = customRange.start ? new Date(customRange.start + 'T00:00:00') : new Date(0); 
        const end = customRange.end ? new Date(customRange.end + 'T23:59:59.999') : new Date();
        return { start, end };
    }
    const end = new Date(); const start = new Date();
    start.setDate(end.getDate() - parseInt(rangeType));
    start.setHours(0,0,0,0); end.setHours(23,59,59,999);
    return { start, end };
  }, [rangeType, customRange]);

  const handleExport = () => {
    const csvContent = "data:text/csv;charset=utf-8," + [['Report', 'Start', 'End'], [activeTab, dateRange.start.toLocaleDateString(), dateRange.end.toLocaleDateString()]].map(e => e.join(',')).join('\n');
    const link = document.createElement("a"); link.setAttribute("href", encodeURI(csvContent)); link.setAttribute("download", `report_${activeTab}.csv`); document.body.appendChild(link); link.click(); document.body.removeChild(link);
  };

  // Sync Header
  useHeader(t('reports_title'), t('reports_subtitle'), <Button variant="outline" icon={Download} onClick={handleExport}>{t('reports_export_button')}</Button>);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [b, a, p, t_data, s] = await Promise.all([api.getBills(), api.getAppointments(), api.getPatients(), api.getTransactions(), api.getStaff()]);
        setBills(b || []); setAppointments(a || []); setPatients(p || []); setTransactions(t_data || []); setStaff(s || []);
      } catch (e) { console.error(e); } finally { setLoading(false); }
    };
    fetchData();
  }, []);

  const filterByDate = (data: any[], dateField: string) => data.filter(item => { if (!item[dateField]) return false; const d = new Date(item[dateField]); return d >= dateRange.start && d <= dateRange.end; });

  const financialStats = useMemo(() => {
    const fb = filterByDate(bills, 'date');
    const trMap = new Map();
    fb.forEach(b => { const key = new Date(b.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }); trMap.set(key, (trMap.get(key) || 0) + (b.paidAmount || 0)); });
    return { totalRevenue: fb.reduce((sum, b) => sum + (b.paidAmount || 0), 0), totalInvoices: fb.length, revenueTrend: Array.from(trMap).map(([name, value]) => ({ name, value })) };
  }, [bills, dateRange]);

  if (loading) return <div className="flex justify-center items-center h-96 text-slate-400">{t('loading')}</div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white dark:bg-slate-800 p-4 rounded-xl border shadow-sm">
        <div className="flex flex-wrap gap-3 items-center">
          <div className="relative"><Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" /><select className="pl-9 pr-4 py-2 bg-slate-50 dark:bg-slate-900 border rounded-lg text-sm" value={rangeType} onChange={e => setRangeType(e.target.value)}><option value="7">{t('reports_time_week')}</option><option value="30">{t('reports_time_month')}</option><option value="custom">{t('reports_time_custom')}</option></select></div>
          {rangeType === 'custom' && (<div className="flex items-center gap-2 animate-in fade-in"><Input type="date" value={customRange.start} onChange={e => setCustomRange({...customRange, start: e.target.value})} className="!py-2 w-36"/><span className="text-slate-400">-</span><Input type="date" value={customRange.end} onChange={e => setCustomRange({...customRange, end: e.target.value})} className="!py-2 w-36"/></div>)}
        </div>
        <div className="flex gap-1 bg-slate-100 p-1 rounded-lg">
          {['financial', 'operational', 'demographics'].map(tab => (<button key={tab} onClick={() => setActiveTab(tab as any)} className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${activeTab === tab ? 'bg-white shadow text-primary-600' : 'text-slate-500'}`}>{tab.toUpperCase()}</button>))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <Card className="text-center"><p className="text-xs text-slate-400 uppercase font-bold">{t('reports_card_revenue')}</p><h3 className="text-3xl font-black text-emerald-600 mt-1">${financialStats.totalRevenue.toLocaleString()}</h3></Card>
          <Card className="text-center"><p className="text-xs text-slate-400 uppercase font-bold">Total Events</p><h3 className="text-3xl font-black text-slate-800 dark:text-white mt-1">{financialStats.totalInvoices}</h3></Card>
          <Card className="text-center"><p className="text-xs text-slate-400 uppercase font-bold">Period</p><h3 className="text-sm font-bold text-slate-500 mt-3">{dateRange.start.toLocaleDateString()} - {dateRange.end.toLocaleDateString()}</h3></Card>
      </div>

      <Card title={t('reports_chart_revenue_trend')} className="h-96">
        <ResponsiveContainer width="100%" height="100%"><AreaChart data={financialStats.revenueTrend}><CartesianGrid strokeDasharray="3 3" vertical={false}/><XAxis dataKey="name" tick={{fontSize: 10}}/><YAxis tick={{fontSize: 10}}/><Tooltip/><Area type="monotone" dataKey="value" stroke="#10b981" fill="#ecfdf5"/></AreaChart></ResponsiveContainer>
      </Card>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Modal, Badge } from '../components/UI';
import { 
  Search, Calendar, Filter, Database, FileText, User, Users, 
  DollarSign, Bed, Activity, Download, Eye, ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight,
  FileSpreadsheet, Printer, ChevronDown
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

interface SystemRecord {
  id: string; originalId: number; type: 'Patient' | 'Appointment' | 'Bill' | 'Admission'; reference: string; date: string; primaryEntity: string; associateEntity?: string; status: string; value?: number; details?: any;
}

export const Records = () => {
  const { t } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [records, setRecords] = useState<SystemRecord[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('All');
  const [dateRange, setDateRange] = useState({ start: '', end: '' });
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(10);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedRecord, setSelectedRecord] = useState<SystemRecord | null>(null);

  const handleExportExcel = () => {
    const csvContent = "data:text/csv;charset=utf-8," + filteredRecords.map(r => [r.type, r.date, r.reference, r.primaryEntity, r.status].join(',')).join('\n');
    const link = document.createElement("a"); link.setAttribute("href", encodeURI(csvContent)); link.setAttribute("download", `records.csv`); document.body.appendChild(link); link.click(); document.body.removeChild(link); setShowExportMenu(false);
  };

  // Sync Header
  useHeader(
    t('records_title'),
    t('records_subtitle'),
    <div className="relative" ref={exportMenuRef}>
      <Button variant="outline" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
        {t('records_export_button')} <ChevronDown size={14} className={`ml-2 ${showExportMenu ? 'rotate-180' : ''}`} />
      </Button>
      {showExportMenu && (
        <div className="absolute right-0 mt-2 w-48 bg-white dark:bg-slate-800 rounded-xl shadow-lg border z-50 overflow-hidden animate-in fade-in zoom-in-95">
          <button onClick={() => { window.print(); setShowExportMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 text-sm hover:bg-slate-50 dark:hover:bg-slate-700"><Printer size={16} /><span>Export to PDF</span></button>
          <button onClick={handleExportExcel} className="w-full flex items-center gap-3 px-4 py-3 text-sm hover:bg-slate-50 dark:hover:bg-slate-700 border-t"><FileSpreadsheet size={16} className="text-green-600" /><span>Export to Excel</span></button>
        </div>
      )}
    </div>
  );

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [pts, apts, bills, admissions] = await Promise.all([api.getPatients(), api.getAppointments(), api.getBills(), api.getActiveAdmissions()]);
        const all: SystemRecord[] = [];
        (pts || []).forEach((p: any) => all.push({ id: `p-${p.id}`, originalId: p.id, type: 'Patient', reference: p.patientId, date: p.createdAt, primaryEntity: p.fullName, status: p.type, details: p }));
        (apts || []).forEach((a: any) => all.push({ id: `a-${a.id}`, originalId: a.id, type: 'Appointment', reference: a.appointmentNumber, date: a.datetime, primaryEntity: a.patientName, status: a.status, details: a }));
        (bills || []).forEach((b: any) => all.push({ id: `b-${b.id}`, originalId: b.id, type: 'Bill', reference: b.billNumber, date: b.date, primaryEntity: b.patientName, status: b.status, value: b.totalAmount, details: b }));
        setRecords(all.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
      } catch (e) { console.error(e); } finally { setLoading(false); }
    };
    fetchData();
  }, []);

  const filteredRecords = useMemo(() => records.filter(r => {
      const matchesSearch = r.reference.toLowerCase().includes(searchTerm.toLowerCase()) || r.primaryEntity.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = filterType === 'All' || r.type === filterType;
      return matchesSearch && matchesType;
  }), [records, searchTerm, filterType]);

  const paginatedRecords = filteredRecords.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  return (
    <div className="space-y-6">
      <Card className="!p-0 overflow-hidden">
        <div className="p-4 bg-slate-50 dark:bg-slate-900 border-b flex flex-col md:flex-row gap-4">
          <div className="relative flex-1"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" /><input type="text" placeholder={t('records_search_placeholder')} className="pl-9 pr-4 py-2 w-full rounded-lg border text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/></div>
          <select className="px-4 py-2 rounded-lg border text-sm" value={filterType} onChange={e => setFilterType(e.target.value)}><option value="All">{t('records_filter_all')}</option><option value="Patient">Patients</option><option value="Appointment">Appointments</option><option value="Bill">Invoices</option></select>
        </div>
        <div className="overflow-x-auto"><table className="min-w-full divide-y"><thead className="bg-white"><tr><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Ref</th><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Date</th><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Entity</th><th className="px-6 py-3 text-center text-xs font-bold text-slate-500 uppercase">Status</th><th className="px-6 py-3 text-right"></th></tr></thead><tbody className="bg-white divide-y">{paginatedRecords.map(r => (<tr key={r.id} className="hover:bg-slate-50"><td><div className="px-6 py-4"><p className="font-bold text-sm">{r.reference}</p><p className="text-[10px] text-slate-400 uppercase">{r.type}</p></div></td><td className="px-6 py-4 text-sm text-slate-600">{new Date(r.date).toLocaleDateString()}</td><td className="px-6 py-4 text-sm font-medium">{r.primaryEntity}</td><td className="px-6 py-4 text-center"><Badge color="blue">{r.status}</Badge></td><td className="px-6 py-4 text-right"><Button size="sm" variant="ghost" icon={Eye} onClick={() => { setSelectedRecord(r); setIsModalOpen(true); }}>View</Button></td></tr>))}</tbody></table></div>
      </Card>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={`${selectedRecord?.type} Details`}>
        {selectedRecord && (<div className="space-y-4"><div className="p-4 bg-slate-50 rounded-xl border"><h3>{selectedRecord.primaryEntity}</h3><p className="text-sm text-slate-500">{selectedRecord.reference} • {new Date(selectedRecord.date).toLocaleString()}</p></div><div className="bg-slate-900 text-green-400 p-4 rounded-xl text-xs font-mono overflow-auto max-h-60"><pre>{JSON.stringify(selectedRecord.details, null, 2)}</pre></div></div>)}
      </Modal>
    </div>
  );
};

