        ))}
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-b-xl shadow-sm border border-t-0 p-6 min-h-[400px]">
        {activeTab === 'general' && (
          <form onSubmit={handleSaveSettings} className="max-w-xl space-y-6 animate-in fade-in">
