    amount: '',
    method: '',
    date: new Date().toISOString().split('T')[0],
    notes: '',
    insuranceProvider: '',
    policyNumber: '',
    expiryDate: '',
    transactionId: ''
  });

  // Refund Form State
  const [refundForm, setRefundForm] = useState({
    amount: '',
    method: '',
    reason: 'Service Cancelled',
    date: new Date().toISOString().split('T')[0],
    customReason: ''
  });

  // Expense Form State
  const [expenseForm, setExpenseForm] = useState({
    category: 'General',
    amount: '',
    method: '',
    date: new Date().toISOString().split('T')[0],
    description: ''
  });

  const getBillType = (bill: Bill): string => {
    const desc = bill.items?.map(i => i.description.toLowerCase()).join(' ') || '';
    if (desc.includes('admission') || desc.includes('accommodation') || desc.includes('deposit')) return 'Admission';
    if (desc.includes('surgery') || desc.includes('operation')) return 'Operation';
    if (desc.includes('lab') || desc.includes('test')) return 'Lab Test';
    if (desc.includes('appointment') || desc.includes('consultation') || desc.includes('follow-up')) return 'Appointment';
    if (desc.includes('service') || desc.includes('procedure') || desc.includes('dressing') || desc.includes('injection')) return 'Procedure';
    return 'General';
  };

  const translateBillType = (type: string) => {
    switch(type) {
        case 'Admission': return t('nav_admissions');
        case 'Operation': return t('nav_operations');
        case 'Lab Test': return t('nav_laboratory');
        case 'Appointment': return t('nav_appointments');
        case 'Procedure': return t('billing_type_procedure');
        default: return t('billing_type_general');
    }
  };

  const translateStatus = (status: string) => {
    switch(status.toLowerCase()) {
        case 'paid': return t('billing_status_paid');
        case 'pending': return t('billing_status_pending');
        case 'partial': return t('billing_status_partial');
        case 'refunded': return t('billing_status_refunded');
        case 'overdue': return t('billing_status_overdue');
        default: return status;
    }
  };

  const loadData = async () => {
    setLoading(true);
    const safeFetch = async (promise: Promise<any>, fallback: any) => {
        try { return await promise; } catch (e) { return fallback; }
    };

    try {
      const [b, p, pm, taxes, labs, services, trans, ins, ops, beds] = await Promise.all([
        safeFetch(api.getBills(), []), 
        safeFetch(api.getPatients(), []),
        safeFetch(api.getPaymentMethods(), []),
        safeFetch(api.getTaxRates(), []),
        safeFetch(api.getLabTests(), []),
        safeFetch(api.getNurseServices(), []),
        safeFetch(api.getTransactions(), []),
        safeFetch(api.getInsuranceProviders(), []),
        safeFetch(api.getOperations(), []),
        safeFetch(api.getBeds(), [])
      ]);

      setBills(Array.isArray(b) ? b : []);
      setPatients(Array.isArray(p) ? p : []);
      setPaymentMethods(Array.isArray(pm) ? pm : []);
      setTaxRates(Array.isArray(taxes) ? taxes : []);
      setTransactions(Array.isArray(trans) ? trans : []);
      setInsuranceProviders(Array.isArray(ins) ? ins : []);

      const catalog = [
        ...(Array.isArray(labs) ? labs.map((l: any) => ({ label: `${t('nav_laboratory')}: ${language === 'ar' ? l.name_ar : l.name_en}`, cost: l.cost })) : []),
        ...(Array.isArray(services) ? services.map((s: any) => ({ label: `${t('billing_type_procedure')}: ${language === 'ar' ? s.name_ar : s.name_en}`, cost: s.cost })) : []),
        ...(Array.isArray(ops) ? ops.map((o: any) => ({ label: `${t('nav_operations')}: ${language === 'ar' ? o.name_ar : o.name_en}`, cost: o.base_cost })) : []),
        ...(Array.isArray(beds) ? beds.map((bd: any) => ({ label: `${t('admissions_care_daily_rate')}: ${bd.roomNumber} (${bd.type})`, cost: bd.costPerDay })) : [])
      ];
      setCatalogItems(catalog);

      const billsArr = Array.isArray(b) ? b : [];
      const total = billsArr.reduce((acc, curr) => acc + (curr.paidAmount || 0), 0);
      const pending = billsArr.reduce((acc, curr) => acc + ((curr.totalAmount || 0) - (curr.paidAmount || 0)), 0);
      const paidCount = billsArr.filter(x => x.status === 'paid').length;

      const revenueByTypeMap: Record<string, number> = {};
      billsArr.forEach(bill => {
        const type = getBillType(bill);
        revenueByTypeMap[type] = (revenueByTypeMap[type] || 0) + (bill.paidAmount || 0);
      });
      const revenueByType = Object.entries(revenueByTypeMap).map(([name, value]) => ({name, value})).sort((a,b) => b.value - a.value);

      setStats({ totalRevenue: total, pendingAmount: pending, paidInvoices: paidCount, revenueByType });

      const transArr = Array.isArray(trans) ? trans : [];
      const income = transArr.filter(tx => tx.type === 'income').reduce((sum, tx) => sum + tx.amount, 0);
      const expense = transArr.filter(tx => tx.type === 'expense').reduce((sum, tx) => sum + tx.amount, 0);
      setTreasuryStats({ income, expenses: expense, net: income - expense });

    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, [language]);

  const getFilteredPaymentMethods = () => {
      return paymentMethods.filter(p => p.isActive);
  };

  const handleAddItem = () => {
    setCreateForm({ ...createForm, items: [...createForm.items, { description: '', amount: '' }] });
  };

  const handleRemoveItem = (index: number) => {
    setCreateForm({ ...createForm, items: createForm.items.filter((_, i) => i !== index) });
  };

  const handleItemChange = (index: number, field: 'description' | 'amount', value: string) => {
    const newItems = [...createForm.items];
    newItems[index] = { ...newItems[index], [field]: value };
    setCreateForm({ ...createForm, items: newItems });
  };

  const handleCatalogSelect = (index: number, value: string) => {
    if (!value) return;
    const item = catalogItems.find(i => i.label === value);
    if (item) {
        const newItems = [...createForm.items];
        newItems[index] = { description: item.label, amount: item.cost.toString() };
        setCreateForm({ ...createForm, items: newItems });
    }
  };

  const handleCreateSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!createForm.patientId) return;

    let formattedItems = createForm.items
      .filter(i => i.description && i.amount)
      .map(i => ({ description: i.description, amount: parseFloat(i.amount) }));

    if (formattedItems.length > 0) {
      setIsProcessing(true);
      let total = formattedItems.reduce((sum, i) => sum + i.amount, 0);
      if (createForm.selectedTaxId) {
          const tax = taxRates.find(t => t.id === parseInt(createForm.selectedTaxId));
          if (tax) {
              const taxAmount = (total * tax.rate) / 100;
              formattedItems.push({ description: `${t('billing_invoice_tax')}: ${language === 'ar' ? tax.name_ar : tax.name_en} (${tax.rate}%)`, amount: parseFloat(taxAmount.toFixed(2)) });
              total += taxAmount;
          }
      }

      try {
        await api.createBill({ 
          patientId: parseInt(createForm.patientId), 
          patientName: createForm.patientName, 
          totalAmount: total, 
          items: formattedItems 
        });
        setIsCreateModalOpen(false);
        setCreateForm({ patientId: '', patientName: '', items: [{ description: '', amount: '' }], selectedTaxId: '' });
        setPatientSearch('');
        loadData();
      } catch(e) { console.error(e); } finally { setIsProcessing(false); }
    }
  };

  const openPaymentModal = (bill: Bill) => {
    setPayingBill(bill);
    const patient = patients.find(p => p.id === bill.patientId);
    const remaining = bill.totalAmount - (bill.paidAmount || 0);

    let defaultMethod = '';
    const activePMs = getFilteredPaymentMethods();
    if (activePMs.length > 0) {
        const cashMethod = activePMs.find(p => p.name_en.toLowerCase() === 'cash');
        const insuranceMethod = activePMs.find(p => p.name_en.toLowerCase() === 'insurance');

        if (patient?.hasInsurance && insuranceMethod) defaultMethod = insuranceMethod.name_en;
        else if (cashMethod) defaultMethod = cashMethod.name_en;
        else defaultMethod = activePMs[0].name_en;
    }

    setPaymentForm({ 
        amount: remaining.toString(), 
        method: defaultMethod,
        date: new Date().toISOString().split('T')[0],
        notes: '',
        transactionId: '',
        insuranceProvider: patient?.hasInsurance ? patient?.insuranceDetails?.provider || '' : '',
        policyNumber: patient?.hasInsurance ? patient?.insuranceDetails?.policyNumber || '' : '',
        expiryDate: patient?.hasInsurance ? patient?.insuranceDetails?.expiryDate || '' : []
    });
    setIsPaymentModalOpen(true);
  };

  const handlePaymentSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!payingBill) return;
    setIsProcessing(true);
    const payload: any = { amount: parseFloat(paymentForm.amount), method: paymentForm.method, date: paymentForm.date, details: { notes: paymentForm.notes } };
    if (paymentForm.method.toLowerCase() === 'insurance') {
        payload.details = { ...payload.details, provider: paymentForm.insuranceProvider, policyNumber: paymentForm.policyNumber, expiryDate: paymentForm.expiryDate };
    } else if (paymentForm.method.toLowerCase() !== 'cash') {
        payload.details = { ...payload.details, transactionId: paymentForm.transactionId };
    }

    try {
      await api.recordPayment(payingBill.id, payload);
      setIsPaymentModalOpen(false);
      setPayingBill(null);
      loadData();
    } catch (err: any) { 
        alert(err.response?.data?.error || t('billing_payment_failed')); 
    } finally { 
        setIsProcessing(false); 
    }
  };

  const openRefundModal = (bill: Bill) => {
    setRefundingBill(bill);
    const activePMs = getFilteredPaymentMethods();
    const defaultMethod = activePMs.find(p => p.name_en.toLowerCase() === 'cash')?.name_en || (activePMs[0]?.name_en || 'Cash');

    setRefundForm({ amount: bill.paidAmount.toString(), method: defaultMethod, reason: 'Service Cancelled', date: new Date().toISOString().split('T')[0], customReason: '' });
    setIsRefundModalOpen(true);
  };

  const handleRefundSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!refundingBill) return;
    setIsProcessing(true);
    try {
        const finalReason = refundForm.reason === 'Other' ? refundForm.customReason : refundForm.reason;
        await api.processRefund(refundingBill.id, { amount: parseFloat(refundForm.amount), method: refundForm.method, reason: finalReason, date: refundForm.date });
        setIsRefundModalOpen(false);
        setRefundingBill(null);
        loadData();
    } catch (err: any) { 
        alert(err.response?.data?.error || t('billing_refund_failed')); 
    } finally { 
        setIsProcessing(false); 
    }
  };

  const handleCancelService = (bill: Bill) => {
    setConfirmState({
      isOpen: true,
      title: t('appointments_cancel_dialog_title'),
      message: t('appointments_cancel_dialog_message'),
      action: async () => {
        setIsProcessing(true);
        try { await api.cancelService(bill.id); loadData(); } catch (e) { alert(t('billing_cancel_service_failed')); } finally { setIsProcessing(false); }
      }
    });
  };

  const handleExpenseSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsProcessing(true);
      try {
          const payload = { ...expenseForm, amount: parseFloat(expenseForm.amount) };
          if (editingExpenseId) {
            await api.updateExpense(editingExpenseId, payload);
          } else {
            await api.addExpense(payload);
          }
          setIsExpenseModalOpen(false);
          setEditingExpenseId(null);
          loadData();
      } catch(err: any) { 
          alert(err.response?.data?.error || (editingExpenseId ? "Failed to update expense." : t('billing_expense_failed'))); 
      } finally { 
          setIsProcessing(false); 
      }
  };

  const openExpenseModal = (tx?: Transaction) => {
      const activePMs = getFilteredPaymentMethods();
      const cashMethod = activePMs.find(p => p.name_en.toLowerCase() === 'cash')?.name_en || (activePMs[0]?.name_en || 'Cash');

      if (tx) {
        setEditingExpenseId(tx.id);
        setExpenseForm({
            category: tx.category || 'General',
            amount: tx.amount.toString(),
            method: tx.method || cashMethod,
            date: tx.date ? (tx.date.includes('T') ? tx.date.split('T')[0] : tx.date.split(' ')[0]) : new Date().toISOString().split('T')[0],
            description: tx.description || ''
        });
      } else {
        setEditingExpenseId(null);
        setExpenseForm({ 
            category: 'General', 
            amount: '', 
            method: cashMethod, 
            date: new Date().toISOString().split('T')[0], 
            description: '' 
        });
      }
      setIsExpenseModalOpen(true);
  };

  const formatDateSafely = (dateStr: any) => {
      if (!dateStr) return 'N/A';
      const normalizedStr = typeof dateStr === 'string' ? dateStr.replace(' ', 'T') : dateStr;
      const d = new Date(normalizedStr);
      if (isNaN(d.getTime())) return 'N/A';
      if (d.getFullYear() <= 1970 && d.getMonth() === 0 && d.getDate() === 1) return 'N/A';
      return d.toLocaleDateString();
  };

  const filteredBills = useMemo(() => {
    return bills.filter(bill => {
      const matchesSearch = bill.patientName.toLowerCase().includes(searchTerm.toLowerCase()) || bill.billNumber.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = filterType === 'all' || getBillType(bill) === filterType;
      let matchesDate = true;
      if (dateRange.start) matchesDate = matchesDate && new Date(bill.date) >= new Date(dateRange.start);
      if (dateRange.end) { const endDate = new Date(dateRange.end); endDate.setHours(23, 59, 59, 999); matchesDate = matchesDate && new Date(bill.date) <= endDate; }
      return matchesSearch && matchesType && matchesDate;
    });
  }, [bills, searchTerm, filterType, dateRange]);

  const totalPages = Math.ceil(filteredBills.length / itemsPerPage);
  const paginatedBills = filteredBills.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
        const matchesSearch = (t.description && t.description.toLowerCase().includes(treasurySearch.toLowerCase())) || (t.category && t.category.toLowerCase().includes(treasurySearch.toLowerCase()));
        const matchesType = treasuryFilter === 'all' || t.type === treasuryFilter;
        let matchesDate = true;
        if (treasuryDate.start) matchesDate = matchesDate && new Date(t.date) >= new Date(treasuryDate.start);
        if (treasuryDate.end) { const endDate = new Date(treasuryDate.end); endDate.setHours(23, 59, 59, 999); matchesDate = matchesDate && new Date(t.date) <= endDate; }
        return matchesSearch && matchesType && matchesDate;
    });
  }, [transactions, treasurySearch, treasuryFilter, treasuryDate]);

  const totalTreasuryPages = Math.ceil(filteredTransactions.length / itemsPerPage);
  const paginatedTransactions = filteredTransactions.slice((treasuryPage - 1) * itemsPerPage, treasuryPage * itemsPerPage);

  const filteredPatientsForInvoice = useMemo(() => {
    if (!patientSearch) return [];
    return patients.filter(p => 
      p.fullName.toLowerCase().includes(patientSearch.toLowerCase()) || 
      p.patientId.toLowerCase().includes(patientSearch.toLowerCase())
    ).slice(0, 5);
  }, [patients, patientSearch]);

  const InvoiceView = ({ bill }: { bill: Bill }) => {
    const taxItem = bill.items.find(i => i.description.toLowerCase().includes('tax'));
    const subtotal = bill.items.filter(i => !i.description.toLowerCase().includes('tax')).reduce((sum, i) => sum + i.amount, 0);
    const taxAmount = taxItem ? taxItem.amount : 0;
    const hospitalName = localStorage.getItem('h_name') || 'AllCare Hospital';
    const [hospitalInfo, setHospitalInfo] = useState<any>({});
    useEffect(() => { api.getPublicSettings().then(setHospitalInfo); }, []);

    return (
        <div className="p-10 bg-white min-h-[600px] text-slate-800 font-sans" id="invoice-print">
            <div className="flex justify-between items-start border-b-2 border-slate-100 pb-8 mb-8">
                <div className="flex flex-col gap-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-primary-600 text-white p-2.5 rounded-xl shadow-lg">
                            <Wallet size={28}/>
                        </div>
                        <div>
                            <h1 className="text-2xl font-bold text-slate-900">{t('billing_invoice_title')}</h1>
                            <p className="text-slate-500 font-mono text-sm">#{bill.billNumber}</p>
                        </div>
                    </div>
                    <div className="flex gap-2 mt-2">
                        <Badge color={bill.status === 'paid' ? 'green' : 'red'}>{translateStatus(bill.status)}</Badge>
                        <Badge color="gray">{translateBillType(getBillType(bill))}</Badge>
                    </div>
                </div>
                <div className="text-right">
                    <h2 className="text-xl font-bold text-primary-600">{hospitalName}</h2>
                    <div className="text-sm text-slate-500 mt-2 space-y-1">
                        <p>{hospitalInfo.hospitalAddress || 'Atbara'}</p>
                        <p>{hospitalInfo.hospitalPhone || '-'}</p>
                    </div>
                </div>
            </div>
            <div className="grid grid-cols-2 gap-8 mb-10 bg-slate-50 p-6 rounded-2xl border border-slate-100">
                <div>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-wider mb-2">{t('billing_invoice_billed_to')}</p>
                    <p className="font-bold text-lg text-slate-900">{bill.patientName}</p>
                    <p className="text-slate-500 text-sm mt-1">{t('patients_table_header_patient')} ID: <span className="font-mono">#{bill.patientId}</span></p>
                </div>
                <div className="text-right">
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-wider mb-2">{t('billing_invoice_date')}</p>
                    <p className="font-bold text-lg text-slate-900">{formatDateSafely(bill.date)}</p>
                </div>
            </div>
            <table className="w-full mb-8">
                <thead>
                    <tr className="border-b border-slate-200">
                        <th className="text-left py-4 px-2 font-bold text-xs text-slate-500 uppercase">{t('billing_invoice_description')}</th>
                        <th className="text-right py-4 px-2 font-bold text-xs text-slate-500 uppercase">{t('billing_table_header_amount')}</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                    {bill.items.map((item, i) => (
                        <tr key={i}>
                            <td className="py-4 px-2 text-sm font-medium">{item.description}</td>
                            <td className="py-4 px-2 text-right font-bold font-mono">${item.amount.toFixed(2)}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
            <div className="flex justify-end">
                <div className="w-full max-sm:max-w-none max-w-sm space-y-3 bg-slate-50 p-6 rounded-2xl border border-slate-100">
                    <div className="flex justify-between text-slate-600 text-sm"><span>{t('billing_invoice_subtotal')}</span><span className="font-mono">${subtotal.toFixed(2)}</span></div>
                    {taxAmount > 0 && <div className="flex justify-between text-slate-600 text-sm"><span>{t('billing_invoice_tax')}</span><span className="font-mono">${taxAmount.toFixed(2)}</span></div>}
                    <div className="h-px bg-slate-200 my-2"></div>
                    <div className="flex justify-between text-slate-900 font-bold text-lg"><span>{t('billing_invoice_total')}</span><span className="font-mono">${bill.totalAmount.toFixed(2)}</span></div>
                    <div className="flex justify-between text-emerald-600 font-bold text-sm"><span>{t('billing_invoice_paid')}</span><span className="font-mono">-${(bill.paidAmount || 0).toFixed(2)}</span></div>
                    {bill.totalAmount > bill.paidAmount && <div className="flex justify-between text-red-600 font-bold text-xl pt-2 border-t border-slate-200 mt-2"><span>{t('billing_invoice_balance')}</span><span className="font-mono">${(bill.totalAmount - (bill.paidAmount || 0)).toFixed(2)}</span></div>}
                </div>
            </div>
        </div>
    );
  };

  const isAccountant = currentUser?.role === 'accountant' || currentUser?.role === 'admin';

  return (
    <div className="space-y-6">
      <div className="flex bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 w-fit mb-6 overflow-x-auto">
          {[
              { id: 'invoices', label: t('billing_tab_invoices'), icon: FileText },
              { id: 'treasury', label: t('billing_tab_treasury'), icon: Landmark },
          ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200'}`}
              >
                  <tab.icon size={18} /> {tab.label}
              </button>
          ))}
      </div>

      {activeTab === 'invoices' && (
        <div className="animate-in fade-in space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card><h4 className="text-xs font-bold text-slate-500 uppercase">{t('billing_stat_revenue')}</h4><p className="text-3xl font-bold text-emerald-600 mt-2">${stats.totalRevenue.toLocaleString()}</p></Card>
                <Card><h4 className="text-xs font-bold text-slate-500 uppercase">{t('billing_stat_pending')}</h4><p className="text-3xl font-bold text-orange-500 mt-2">${stats.pendingAmount.toLocaleString()}</p></Card>
                <Card><h4 className="text-xs font-bold text-slate-500 uppercase">{t('billing_stat_paid')}</h4><p className="text-3xl font-bold text-slate-800 dark:text-white mt-2">{stats.paidInvoices}</p></Card>
            </div>

            <Card className="!p-0 border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
                <div className="p-4 border-b border-slate-200 dark:border-slate-700 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between">
                  <div className="flex flex-col sm:flex-row gap-2 w-full md:w-auto">
                    <div className="relative w-full sm:w-64"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" /><input type="text" placeholder={t('billing_search_placeholder')} className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none" value={searchTerm} onChange={e => { setSearchTerm(e.target.value); setCurrentPage(1); }}/></div>
                    <div className="relative w-full sm:w-auto"><Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 pointer-events-none" /><select className="pl-9 pr-8 py-2 w-full rounded-lg border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-sm appearance-none cursor-pointer text-slate-900 dark:text-white" value={filterType} onChange={e => { setFilterType(e.target.value); setCurrentPage(1); }}><option value="all">{t('patients_filter_type_all')}</option><option value="Appointment">{t('nav_appointments')}</option><option value="Lab Test">{t('nav_laboratory')}</option><option value="Admission">{t('nav_admissions')}</option><option value="Operation">{t('nav_operations')}</option><option value="Procedure">{t('billing_type_procedure')}</option><option value="General">{t('billing_type_general')}</option></select></div>
                  </div>
                </div>

                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                    <thead className="bg-slate-50 dark:bg-slate-900">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('billing_table_header_info')}</th>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('patients_table_header_patient')}</th>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('billing_table_header_status')}</th>
                        <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('billing_table_header_paid_progress')}</th>
                        <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">{t('billing_table_header_amount')}</th>
                        <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">{t('billing_table_header_actions')}</th>
                      </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                      {loading ? <tr><td colSpan={6} className="text-center py-10 text-slate-400">{t('billing_table_loading')}</td></tr> : 
                       paginatedBills.length === 0 ? <tr><td colSpan={6} className="text-center py-10 text-slate-400">{t('billing_table_empty')}</td></tr> : 
                       paginatedBills.map(bill => {
                        const paidPercent = bill.totalAmount > 0 ? (bill.paidAmount / bill.totalAmount) * 100 : 0;
                        return (
                          <tr key={bill.id}>
                            <td className="px-6 py-4 whitespace-nowrap"><div className="font-bold">{bill.billNumber}</div><div className="text-sm text-slate-500">{formatDateSafely(bill.date)}</div></td>
                            <td className="px-6 py-4 whitespace-nowrap"><div className="text-sm font-medium">{bill.patientName}</div><div className="text-xs text-slate-500">ID: {bill.patientId}</div></td>
                            <td className="px-6 py-4 whitespace-nowrap"><div className="flex flex-col gap-1"><Badge color={bill.status === 'paid' ? 'green' : bill.status === 'partial' ? 'yellow' : 'red'}>{translateStatus(bill.status)}</Badge><Badge color={getTypeColor(getBillType(bill)) as any}>{translateBillType(getBillType(bill))}</Badge></div></td>
                            <td className="px-6 py-4 whitespace-nowrap min-w-[150px]"><div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-2.5"><div className="bg-primary-500 h-2.5 rounded-full" style={{ width: `${paidPercent}%` }}></div></div><p className="text-right text-[10px] mt-1 text-slate-500">${(bill.paidAmount || 0).toLocaleString()} / ${(bill.totalAmount || 0).toLocaleString()}</p></td>
                            <td className="px-6 py-4 whitespace-nowrap text-right font-mono font-bold">${bill.totalAmount.toLocaleString()}</td>
                            <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                <div className="flex justify-end gap-2">
                                    <Button size="sm" variant="outline" icon={FileText} onClick={() => setSelectedBill(bill)}>{t('billing_action_view_invoice')}</Button>
                                    {canManageBilling && (<>{(bill.status === 'pending' || bill.status === 'partial') && <Button size="sm" onClick={() => openPaymentModal(bill)}>{t('billing_action_pay')}</Button>}</>)}
                                </div>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
                {!loading && <div className="flex justify-between items-center p-4 border-t border-slate-200 dark:border-slate-700"><span className="text-sm text-slate-500">{t('patients_pagination_showing')} {paginatedBills.length} {t('patients_pagination_of')} {filteredBills.length}</span><div className="flex gap-2"><Button size="sm" variant="secondary" onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} icon={ChevronLeft}>{t('billing_pagination_prev')}</Button><Button size="sm" variant="secondary" onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} icon={ChevronRight}>{t('billing_pagination_next')}</Button></div></div>}
            </Card>
        </div>
      )}

      {activeTab === 'treasury' && (
          <div className="space-y-6 animate-in fade-in">
              <Card className="!p-0 border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
                  <div className="p-4 bg-slate-50 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-700 flex flex-col md:flex-row gap-4 items-center">
                      <div className="flex items-center gap-2 flex-1"><Landmark size={18} className="text-slate-500"/> <h3 className="font-bold text-slate-800 dark:text-white">{t('billing_treasury_transactions')}</h3></div>
                      <div className="flex gap-2 items-center"><select className="px-3 py-1.5 rounded-lg border border-slate-300 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500 outline-none text-slate-900 dark:text-white" value={treasuryFilter} onChange={(e) => setTreasuryFilter(e.target.value)}><option value="all">{t('patients_filter_type_all')}</option><option value="income">{t('billing_treasury_type_income')}</option><option value="expense">{t('billing_treasury_type_expense')}</option></select></div>
                  </div>
                  <div className="overflow-x-auto"><table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700"><thead className="bg-white dark:bg-slate-900"><tr><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('date')}</th><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('appointments_form_type')}</th><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('billing_treasury_table_category')}</th><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('billing_treasury_table_description')}</th><th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">{t('billing_treasury_table_method')}</th><th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">{t('billing_table_header_amount')}</th><th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase">{t('actions')}</th></tr></thead><tbody className="divide-y divide-slate-100 bg-white dark:bg-slate-800">{paginatedTransactions.map((tx) => (<tr key={tx.id}><td className="px-6 py-3 text-sm text-slate-600 dark:text-slate-300">{formatDateSafely(tx.date)}</td><td className="px-6 py-3"><Badge color={tx.type === 'income' ? 'green' : 'red'}>{tx.type === 'income' ? t('billing_treasury_type_income') : t('billing_treasury_type_expense')}</Badge></td><td className="px-6 py-3 text-sm font-medium dark:text-slate-200">{tx.category || '-'}</td><td className="px-6 py-3 text-sm text-slate-500 dark:text-slate-400">{tx.description}</td><td className="px-6 py-3 text-sm dark:text-slate-300">{tx.method}</td><td className={`px-6 py-3 text-sm font-bold text-right ${tx.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>{tx.type === 'income' ? '+' : '-'}${tx.amount.toLocaleString()}</td><td className="px-6 py-3 text-right">{tx.type === 'expense' && isAccountant && (<Button size="sm" variant="ghost" icon={Edit} onClick={() => openExpenseModal(tx)} />)}</td></tr>))}</tbody></table></div>
                  <div className="px-6 py-3 border-t border-slate-200 dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900"><span className="text-sm text-slate-500">{t('patients_pagination_showing')} {treasuryPage} {t('patients_pagination_of')} {totalTreasuryPages || 1}</span><div className="flex gap-2"><button onClick={() => setTreasuryPage(p => Math.max(1, p - 1))} disabled={treasuryPage === 1} className="p-1 rounded hover:bg-slate-100 dark:hover:bg-slate-800 disabled:opacity-50 transition-colors"><ChevronLeft size={16}/></button><button onClick={() => setTreasuryPage(p => Math.min(totalTreasuryPages, p + 1))} disabled={treasuryPage === totalTreasuryPages} className="p-1 rounded hover:bg-slate-100 dark:hover:bg-slate-800 disabled:opacity-50 transition-colors"><ChevronRight size={16}/></button></div></div>
              </Card>
          </div>
      )}

      {/* --- MODALS --- */}
      <Modal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} title={t('billing_modal_create_title')}>
        <form onSubmit={handleCreateSubmit} className="space-y-4">
          <div className="space-y-1 relative">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1.5">{t('billing_modal_create_select_patient')}</label>
            {createForm.patientId ? (
              <div className="flex items-center justify-between p-3 bg-primary-50 dark:bg-primary-900/20 border border-primary-200 dark:border-primary-800 rounded-xl">
                 <div className="flex flex-col">
                   <span className="font-bold text-primary-900 dark:text-primary-200">{createForm.patientName}</span>
                   <span className="text-xs text-primary-600 dark:text-primary-400">ID: {patients.find(p => p.id.toString() === createForm.patientId)?.patientId}</span>
                 </div>
                 <button type="button" onClick={() => { setCreateForm({...createForm, patientId: '', patientName: ''}); setPatientSearch(''); }} className="p-1 hover:bg-primary-100 dark:hover:bg-primary-800 rounded-full transition-colors">
                   <X size={16} className="text-primary-600" />
                 </button>
              </div>
            ) : (
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <input 
                  type="text"
                  placeholder={t('patients_search_placeholder')}
                  className="pl-9 pr-4 py-2.5 w-full rounded-xl border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-900 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                  value={patientSearch}
                  onChange={(e) => { setPatientSearch(e.target.value); setShowPatientResults(true); }}
                  onFocus={() => setShowPatientResults(true)}
                />
                {showPatientResults && filteredPatientsForInvoice.length > 0 && (
                  <div className="absolute z-20 w-full mt-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-xl overflow-hidden">
                    {filteredPatientsForInvoice.map(p => (
                      <button key={p.id} type="button" className="w-full px-4 py-3 text-left hover:bg-slate-50 dark:hover:bg-slate-700 border-b last:border-0 border-slate-100 dark:border-slate-700 flex justify-between items-center" onClick={() => { setCreateForm({ ...createForm, patientId: p.id.toString(), patientName: p.fullName }); setShowPatientResults(false); }}>
                        <span className="font-medium text-slate-900 dark:text-white">{p.fullName}</span>
                        <span className="text-xs text-slate-500 font-mono">ID: {p.patientId}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
          <div>
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1.5">{t('billing_modal_create_items_label')}</label>
            <div className="space-y-2 max-h-60 overflow-y-auto pr-1">
              {createForm.items.map((item, index) => (
                <div key={index} className="flex flex-col sm:flex-row gap-2 items-start sm:items-center bg-slate-50 dark:bg-slate-900 p-2 rounded-lg border border-slate-100 dark:border-slate-800">
                    <select className="w-full sm:w-1/3 text-xs p-2 rounded border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white" onChange={(e) => handleCatalogSelect(index, e.target.value)} defaultValue=""><option value="" disabled>{t('billing_modal_create_quick_add')}</option>{catalogItems.map((c, i) => <option key={i} value={c.label}>{c.label}</option>)}</select>
                    <Input placeholder={t('billing_modal_create_item_placeholder')} value={item.description} onChange={e => handleItemChange(index, 'description', e.target.value)} className="flex-1" />
                    <div className="flex gap-2 w-full sm:w-auto">
                        <Input placeholder="0.00" type="number" value={item.amount} onChange={e => handleItemChange(index, 'amount', e.target.value)} className="w-24" />
                        <button type="button" onClick={() => handleRemoveItem(index)} className="text-red-500 p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg"><Trash2 size={16}/></button>
                    </div>
                </div>
              ))}
            </div>
            <Button size="sm" variant="secondary" onClick={handleAddItem} className="mt-2 w-full" icon={Plus}>{t('billing_modal_create_add_item_button')}</Button>
          </div>
          <div className="grid grid-cols-2 gap-4 border-t dark:border-slate-700 pt-4">
            <div>
              <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">{t('billing_modal_create_tax_rate')}</label>
              <select className="w-full rounded-xl border border-slate-300 dark:border-slate-700 p-2.5 text-sm bg-white dark:bg-slate-900 text-slate-900 dark:text-white" value={createForm.selectedTaxId} onChange={e => setCreateForm({...createForm, selectedTaxId: e.target.value})}>
                <option value="">{t('billing_modal_create_none')}</option>
                {taxRates.filter(t => t.isActive).map(t => (<option key={t.id} value={t.id}>{language === 'ar' ? t.name_ar : t.name_en} ({t.rate}%)</option>))}
              </select>
            </div>
            <div className="text-right flex flex-col justify-center">
              <span className="block text-xs text-slate-500 dark:text-slate-400 uppercase font-bold tracking-wider">{t('billing_modal_create_total_label')}</span>
              <span className="text-3xl font-bold text-primary-600">${(() => { const subtotal = createForm.items.reduce((sum, i) => sum + (parseFloat(i.amount) || 0), 0); const taxRate = taxRates.find(t => t.id === parseInt(createForm.selectedTaxId)); const tax = taxRate ? (subtotal * taxRate.rate) / 100 : 0; return (subtotal + tax).toFixed(2); })()}</span>
            </div>
          </div>
          <div className="flex justify-end pt-4 border-t dark:border-slate-700 gap-3"><Button type="button" variant="secondary" onClick={() => setIsCreateModalOpen(false)}>{t('cancel')}</Button><Button type="submit" disabled={isProcessing || !createForm.patientId}>{isProcessing ? t('processing') : t('billing_modal_create_generate_button')}</Button></div>
        </form>
      </Modal>

      <Modal isOpen={isPaymentModalOpen} onClose={() => setIsPaymentModalOpen(false)} title={t('billing_modal_payment_title')}>
        {payingBill && (
          <form onSubmit={handlePaymentSubmit} className="space-y-6">
            <div className="text-center p-6 bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 shadow-inner">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{t('billing_modal_payment_balance_due')}</p>
                <p className="text-5xl font-black text-slate-900 dark:text-white font-mono tracking-tighter">${(payingBill.totalAmount - (payingBill.paidAmount || 0)).toLocaleString()}</p>
            </div>
            <Select label={t('billing_modal_payment_method')} value={paymentForm.method} onChange={e => setPaymentForm({...paymentForm, method: e.target.value})} required className="text-slate-900 dark:text-white">
                {getFilteredPaymentMethods().map(p => (<option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>))}
            </Select>
            <div className="space-y-4">
                {paymentForm.method.toLowerCase() === 'cash' && (<><Input label={t('billing_table_header_amount')} type="number" value={paymentForm.amount} onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})} required /><Textarea label={t('patients_modal_action_notes')} rows={2} value={paymentForm.notes} onChange={e => setPaymentForm({...paymentForm, notes: e.target.value})} /></>)}
                {paymentForm.method.toLowerCase() === 'insurance' && (<div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl border border-blue-100 dark:border-blue-900/30 animate-in slide-in-from-top-2"><Input label={t('billing_table_header_amount')} type="number" value={paymentForm.amount} onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})} required className="md:col-span-2" /><div className="md:col-span-2"><Select label={t('patients_modal_form_insurance_provider')} value={paymentForm.insuranceProvider} onChange={e => setPaymentForm({...paymentForm, insuranceProvider: e.target.value})} required className="text-slate-900 dark:text-white"><option value="">{t('patients_modal_form_insurance_provider_select')}</option>{insuranceProviders.map(p => <option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>)}</Select></div><Input label={t('patients_modal_form_insurance_policy')} value={paymentForm.policyNumber} onChange={e => setPaymentForm({...paymentForm, policyNumber: e.target.value})} required />
                {/* FIX: Corrected typo in onChange handler where 'expiryDate' was being used instead of 'paymentForm'. */}
                <Input label={t('patients_modal_form_insurance_expiry')} type="date" value={paymentForm.expiryDate} onChange={e => setPaymentForm({...paymentForm, expiryDate: e.target.value})} required /></div>)}
                {paymentForm.method.toLowerCase() !== 'cash' && paymentForm.method.toLowerCase() !== 'insurance' && (<div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 animate-in slide-in-from-top-2"><Input label={t('billing_table_header_amount')} type="number" value={paymentForm.amount} onChange={e => setPaymentForm({...paymentForm, amount: e.target.value})} required className="md:col-span-2" /><Input label={t('billing_modal_payment_ref')} value={paymentForm.transactionId} onChange={e => setPaymentForm({...paymentForm, transactionId: e.target.value})} required /><Input label={t('date')} type="date" value={paymentForm.date} onChange={e => setPaymentForm({...paymentForm, date: e.target.value})} required /></div>)}
            </div>
            <div className="flex justify-end pt-4 border-t dark:border-slate-700 gap-3"><Button type="button" variant="secondary" onClick={() => setIsPaymentModalOpen(false)}>{t('cancel')}</Button><Button type="submit" icon={isProcessing ? undefined : CheckCircle} disabled={isProcessing}>{isProcessing ? t('processing') : t('billing_modal_payment_confirm_button')}</Button></div>
          </form>
        )}
      </Modal>

      <Modal isOpen={isExpenseModalOpen} onClose={() => setIsExpenseModalOpen(false)} title={editingExpenseId ? "Update Expense Entry" : t('billing_modal_expense_title')}>
        <form onSubmit={handleExpenseSubmit} className="space-y-4">
          <Select label={t('billing_modal_expense_category')} value={expenseForm.category} onChange={e => setExpenseForm({...expenseForm, category: e.target.value})} required className="text-slate-900 dark:text-white">
            <option value="General">{t('billing_modal_expense_cat_general')}</option>
            <option value="Pharmacy Refill">Pharmacy Inventory Refill</option>
            <option value="Laboratory Supplies">Lab Reagents & Consumables</option>
            <option value="Medical Supplies">{t('billing_modal_expense_cat_supplies')}</option>
            <option value="Staff Salaries">Staff Monthly Salaries</option>
            <option value="Facility Rent">Facility / Real Estate Rent</option>
            <option value="Utilities">{t('billing_modal_expense_cat_utilities')}</option>
            <option value="Facility Maintenance">{t('billing_modal_expense_cat_maintenance')}</option>
            <option value="Medical Equipment">{t('billing_modal_expense_cat_equipment')}</option>
          </Select>
          <div className="grid grid-cols-2 gap-4">
            <Input label={t('billing_modal_expense_amount')} type="number" required value={expenseForm.amount} onChange={e => setExpenseForm({...expenseForm, amount: e.target.value})} />
            <Input label={t('date')} type="date" required value={expenseForm.date} onChange={e => setExpenseForm({...expenseForm, date: e.target.value})} />
          </div>
          <Select label={t('billing_modal_expense_method')} value={expenseForm.method} onChange={e => setExpenseForm({...expenseForm, method: e.target.value})} required className="text-slate-900 dark:text-white">
            {getFilteredPaymentMethods().length === 0 ? <option value="">No methods configured</option> : getFilteredPaymentMethods().map(p => (<option key={p.id} value={p.name_en}>{language === 'ar' ? p.name_ar : p.name_en}</option>))}
          </Select>
          <Textarea label={t('billing_modal_expense_description')} rows={3} required value={expenseForm.description} onChange={e => setExpenseForm({...expenseForm, description: e.target.value})} />
          <div className="flex justify-end pt-4 gap-3 border-t dark:border-slate-700">
            <Button type="button" variant="secondary" onClick={() => setIsExpenseModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit" disabled={isProcessing}>{isProcessing ? t('processing') : (editingExpenseId ? t('save') : t('billing_modal_expense_save'))}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={!!selectedBill} onClose={() => setSelectedBill(null)} title={t('billing_modal_preview_title')}>
        {selectedBill && (<div><InvoiceView bill={selectedBill} /><div className="mt-6 flex justify-end gap-3 no-print"><Button variant="secondary" onClick={() => setSelectedBill(null)}>{t('close')}</Button><Button icon={Printer} onClick={() => window.print()}>{t('billing_modal_preview_print_button')}</Button></div></div>)}
      </Modal>
      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({ ...confirmState, isOpen: false })} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message} />
    </div>
  );
};

const getTypeColor = (type: string) => {
    switch (type) {
      case 'Admission': return 'orange';
      case 'Operation': return 'red';
      case 'Lab Test': return 'purple';
      case 'Appointment': return 'blue';
      case 'Procedure': return 'cyan';
      default: return 'gray';
    }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Plus, Search, Briefcase, Clock, 
  Calendar, DollarSign, Wallet,
  Loader2, Edit, Trash2, MapPin,
  LogIn, LogOut, CheckCircle, XCircle
} from 'lucide-react';
import { api } from '../services/api';
import { MedicalStaff, Attendance, LeaveRequest, PayrollRecord, FinancialAdjustment } from '../types';
import { hasPermission, Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';
import { useHeader } from '../context/HeaderContext';

const DAYS_OF_WEEK_EN = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
const DAYS_OF_WEEK_AR = ['إث', 'ثل', 'أر', 'خم', 'جم', 'سب', 'أح'];

const roleDepartmentMap: Record<string, string[]> = {
  doctor: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Dermatology', 'Radiology', 'Anesthesiology', 'Internal Medicine'],
  nurse: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Internal Medicine'],
  technician: ['Radiology', 'Laboratory'],
  anesthesiologist: ['Anesthesiology', 'General Surgery'],
  pharmacist: ['Pharmacy'],
  hr_manager: ['Administration', 'HR'],
  accountant: ['Finance', 'Administration'],
  manager: ['Administration', 'Management'],
  staff: ['Administration', 'Maintenance', 'Security', 'Support Services', 'Finance', 'IT Support'],
  medical_assistant: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'General Surgery', 'Internal Medicine'],
  receptionist: ['Administration', 'Front Desk']
};

export const Staff = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'directory' | 'attendance' | 'leaves' | 'payroll' | 'financials'>('directory');
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const { user: currentUser } = useAuth();
  const [loading, setLoading] = useState(true);

  const DAYS_OF_WEEK = language === 'ar' ? DAYS_OF_WEEK_AR : DAYS_OF_WEEK_EN;
  const canManageHR = hasPermission(currentUser, Permissions.MANAGE_HR);

  // Tab specific data
  const [attendance, setAttendance] = useState<Attendance[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>([]);
  const [payroll, setPayroll] = useState<PayrollRecord[]>([]);
  const [financials, setFinancials] = useState<FinancialAdjustment[]>([]);

  // Catalogs for dropdowns
  const [departments, setDepartments] = useState<any[]>([]);
  const [specializations, setSpecializations] = useState<any[]>([]);
  const [banks, setBanks] = useState<any[]>([]);

  // UI States
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false); 
  const [isAdjustmentModalOpen, setIsAdjustmentModalOpen] = useState(false); 
  const [isLeaveModalOpen, setIsLeaveModalOpen] = useState(false); 
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]); 
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7)); 

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  const [staffForm, setStaffForm] = useState<any>({});
  const [adjForm, setAdjForm] = useState({ staffId: '', type: 'bonus', amount: '', reason: '', date: new Date().toISOString().split('T')[0] });
  const [leaveForm, setLeaveForm] = useState({ staffId: '', type: 'sick', startDate: '', endDate: '', reason: '' });
  const [attendanceModal, setAttendanceModal] = useState<any>(null);

  const loadData = async (isBackground = false) => {
    if (!isBackground) setLoading(true);
    try {
      const [data, depts, specs, bankData] = await Promise.all([
        api.getStaff(), api.getDepartments(), api.getSpecializations(), api.getBanks()
      ]);
      setStaff(Array.isArray(data) ? data : []);
      setDepartments(Array.isArray(depts) ? depts : []);
      setSpecializations(Array.isArray(specs) ? specs : []);
      setBanks(Array.isArray(bankData) ? bankData : []);
    } catch (e) { console.error(e); } finally { if (!isBackground) setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  useEffect(() => {
    const fetchTabData = async () => {
        if (activeTab === 'attendance') setAttendance(await api.getAttendance(selectedDate));
        else if (activeTab === 'leaves') setLeaves(await api.getLeaves());
        else if (activeTab === 'payroll') setPayroll(await api.getPayroll(selectedMonth));
        else if (activeTab === 'financials') setFinancials(await api.getFinancials('all'));
    };
    if(activeTab !== 'directory') fetchTabData();
  }, [activeTab, selectedDate, selectedMonth]);

  const handleCreateStaff = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessStatus('processing');
    const { bankName, bankAccount, ...restOfForm } = staffForm;
    const payload = { ...restOfForm, bankDetails: { bankName, bankAccount } };
    try {
      if (staffForm.id) await api.updateStaff(staffForm.id, payload);
      else await api.addStaff(payload);
      setProcessStatus('success');
      await loadData(true);
      setTimeout(() => { setIsModalOpen(false); setProcessStatus('idle'); }, 500);
    } catch (err: any) { setProcessStatus('error'); setProcessMessage(err.response?.data?.error || t('staff_save_fail')); }
  };

  const openStaffModal = (s?: MedicalStaff) => {
      let bankDetailsParsed = { bankName: '', bankAccount: '' };
      if (s?.bankDetails) {
          if (typeof s.bankDetails === 'object' && s.bankDetails !== null) bankDetailsParsed = { bankName: s.bankDetails.bankName, bankAccount: s.bankDetails.bankAccount };
          else if (typeof s.bankDetails === 'string') bankDetailsParsed = { bankName: s.bankDetails, bankAccount: '' };
      }
      setStaffForm(s ? { ...s, address: s.address || '', ...bankDetailsParsed } : { fullName: '', type: 'doctor', status: 'active', baseSalary: '', availableDays: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'], availableTimeStart: '09:00', availableTimeEnd: '17:00', consultationFee: '', joinDate: new Date().toISOString().split('T')[0], address: '', ...bankDetailsParsed });
      setIsModalOpen(true);
  };

  const toggleDay = (day: string) => {
      const currentDays = staffForm.availableDays || [];
      const dayEN = DAYS_OF_WEEK_EN[DAYS_OF_WEEK.indexOf(day)];
      setStaffForm({ ...staffForm, availableDays: currentDays.includes(dayEN) ? currentDays.filter((d: string) => d !== dayEN) : [...currentDays, dayEN] });
  };

  const filteredDepartments = useMemo(() => {
    if (!staffForm.type) return departments;
    const allowedDepts = roleDepartmentMap[staffForm.type];
    return !allowedDepts ? departments : departments.filter(d => allowedDepts.includes(d.name_en));
  }, [staffForm.type, departments]);

  const filteredSpecializations = useMemo(() => {
    return !staffForm.type ? specializations : specializations.filter(s => !s.related_role || s.related_role === staffForm.type);
  }, [staffForm.type, specializations]);

  const handleCheckIn = (staffMember: MedicalStaff) => {
    setConfirmState({
        isOpen: true, title: t('staff_attendance_confirm'), message: t('staff_attendance_checkin_confirm', {name: staffMember.fullName, time: new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}),
        action: async () => {
            setProcessStatus('processing');
            try {
                const now = new Date();
                const timeString = now.toTimeString().slice(0, 5);
                await api.markAttendance({ staffId: staffMember.id, date: selectedDate, status: staffMember.availableTimeStart && timeString > staffMember.availableTimeStart ? 'late' : 'present', checkIn: timeString });
                setAttendance(await api.getAttendance(selectedDate));
                setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) { setProcessStatus('error'); setProcessMessage(e.message || t('staff_attendance_mark_fail')); }
        }
    });
  };

  const handleCheckOut = (record: Attendance) => {
    setConfirmState({
        isOpen: true, title: t('staff_attendance_confirm'), message: t('staff_attendance_checkout_confirm', {name: record.staffName}),
        action: async () => {
            setProcessStatus('processing');
            try {
                await api.markAttendance({ staffId: record.staffId, date: record.date, status: record.status, checkOut: new Date().toTimeString().slice(0, 5) });
                setAttendance(await api.getAttendance(selectedDate));
                setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) { setProcessStatus('error'); }
        }
    });
  };

  const openAttendanceModal = (staffId: number, staffName: string, status: any) => {
      const existing = attendance.find(a => a.staffId === staffId);
      setAttendanceModal({ isOpen: true, staffId, staffName, status: existing?.status || status, checkIn: existing?.checkIn || '', checkOut: existing?.checkOut || '' });
  };

  const handleAttendanceSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      try {
          await api.markAttendance({ staffId: attendanceModal.staffId, date: selectedDate, status: attendanceModal.status, checkIn: attendanceModal.checkIn || null, checkOut: attendanceModal.checkOut || null });
          setAttendance(await api.getAttendance(selectedDate));
          setProcessStatus('success'); setTimeout(() => { setProcessStatus('idle'); setAttendanceModal(null); }, 500);
      } catch (err: any) { setProcessStatus('error'); }
  };

  const handleLeaveRequest = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      try {
        await api.requestLeave(leaveForm);
        setLeaves(await api.getLeaves());
        setProcessStatus('success'); setTimeout(() => { setIsLeaveModalOpen(false); setProcessStatus('idle'); }, 1000);
      } catch (e: any) { setProcessStatus('error'); }
  };

  const updateLeaveStatus = (id: number, status: string) => {
      setConfirmState({
        isOpen: true, title: status === 'approved' ? t('hr_approve') : t('hr_reject'), message: t('confirm'),
        action: async () => {
            setProcessStatus('processing');
            try {
                await api.updateLeaveStatus(id, status);
                setLeaves(await api.getLeaves());
                setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
            } catch (e: any) { setProcessStatus('error'); }
        }
      });
  };

  const handleGeneratePayroll = () => {
      setConfirmState({
          isOpen: true, title: t('staff_tab_payroll'), message: t('staff_generate_payroll_confirm', {month: selectedMonth}),
          action: async () => {
              setProcessStatus('processing');
              try {
                  await api.generatePayroll({ month: selectedMonth });
                  setPayroll(await api.getPayroll(selectedMonth));
                  setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
              } catch(e: any) { setProcessStatus('error'); }
          }
      });
  };

  const handleMarkPaid = (record: PayrollRecord) => {
      setConfirmState({
          isOpen: true, title: t('confirm'), message: t('staff_payroll_paid_confirm', {name: record.staffName}),
          action: async () => {
              setProcessStatus('processing');
              try {
                  await api.updatePayrollStatus(record.id, 'paid');
                  setPayroll(await api.getPayroll(selectedMonth));
                  setProcessStatus('success'); setTimeout(() => setProcessStatus('idle'), 1000);
              } catch(e: any) { setProcessStatus('error'); }
          }
      });
  };

  const handleAdjustmentSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setProcessStatus('processing');
      try {
        await api.addAdjustment({ ...adjForm, amount: parseFloat(adjForm.amount) });
        setFinancials(await api.getFinancials('all'));
        setProcessStatus('success'); setTimeout(() => { setIsAdjustmentModalOpen(false); setProcessStatus('idle'); }, 1000);
      } catch (e: any) { setProcessStatus('error'); }
  };

  /* FIX: Moved useHeader after handleGeneratePayroll and other functions to avoid block-scoped access error during component body evaluation. */
  // Sync Header
  useHeader(
    t('staff_title'),
    t('staff_subtitle'),
    <div className="flex gap-2">
      {activeTab === 'directory' && canManageHR && <Button onClick={() => openStaffModal()} icon={Plus}>{t('staff_add_employee_button')}</Button>}
      {activeTab === 'leaves' && <Button icon={Plus} onClick={() => setIsLeaveModalOpen(true)}>{t('staff_leave_request')}</Button>}
      {activeTab === 'payroll' && canManageHR && <Button icon={DollarSign} onClick={handleGeneratePayroll}>{t('staff_generate_payroll')}</Button>}
      {activeTab === 'financials' && canManageHR && <Button icon={Plus} onClick={() => setIsAdjustmentModalOpen(true)}>{t('staff_financial_add_entry')}</Button>}
    </div>
  );

  const sortedStaff = staff.filter(s => s.fullName.toLowerCase().includes(searchTerm.toLowerCase())).sort((a, b) => (a.status === 'active' ? -1 : 1));

  return (
    <div className="space-y-6">
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <><Loader2 className="w-16 h-16 text-primary-600 animate-spin mb-4" /><h3 className="font-bold">{t('processing')}</h3></>}
            {processStatus === 'success' && <><CheckCircle size={48} className="text-green-600 mb-4" /><h3 className="font-bold">{t('success')}</h3></>}
            {processStatus === 'error' && <><XCircle size={48} className="text-red-600 mb-4" /><h3 className="font-bold">{t('patients_process_title_failed')}</h3><p className="text-sm text-red-500 mt-2">{processMessage}</p><Button variant="secondary" className="mt-4 w-full" onClick={() => setProcessStatus('idle')}>{t('close')}</Button></>}
          </div>
        </div>
      )}

      <div className="flex bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-x-auto w-fit">
          {[
              { id: 'directory', label: t('staff_tab_directory'), icon: Briefcase },
              { id: 'attendance', label: t('staff_tab_attendance'), icon: Clock },
              { id: 'leaves', label: t('staff_tab_leaves'), icon: Calendar },
              { id: 'payroll', label: t('staff_tab_payroll'), icon: DollarSign },
              { id: 'financials', label: t('staff_tab_financials'), icon: Wallet },
          ].map(tab => (
              <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}><tab.icon size={16} /> {tab.label}</button>
          ))}
      </div>

      {activeTab === 'directory' && (
          <div className="animate-in fade-in">
              <div className="relative w-full sm:w-72 mb-6"><Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" /><input type="text" placeholder={t('staff_search_placeholder')} className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/></div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">{sortedStaff.map(person => (<div key={person.id} className="bg-white dark:bg-slate-800 p-5 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm hover:shadow-md transition-all group"><div className="flex justify-between items-start mb-4"><div className="flex items-center gap-3"><div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg text-white bg-slate-400`}>{person.fullName.charAt(0)}</div><div><h3 className="font-bold text-slate-800 dark:text-white line-clamp-1">{person.fullName}</h3><Badge color="blue">{t(`staff_role_${person.type}`)}</Badge></div></div><div className={`w-2 h-2 rounded-full ${person.status === 'active' ? 'bg-green-500' : 'bg-gray-300'}`}></div></div><div className="space-y-2 text-sm text-slate-500 dark:text-slate-400 mb-4"><div className="flex items-center gap-2"><Briefcase size={14}/> {person.department || t('patients_modal_view_na')}</div><div className="flex items-center gap-2"><MapPin size={14}/> {person.phone || t('patients_modal_view_na')}</div></div>{canManageHR && <Button variant="outline" className="w-full" onClick={() => openStaffModal(person)}>{t('edit')}</Button>}</div>))}</div>
          </div>
      )}

      {activeTab === 'attendance' && (
          <div className="animate-in fade-in space-y-4">
              <div className="flex justify-end"><Input type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} className="w-auto" /></div>
              <div className="bg-white dark:bg-slate-800 rounded-xl border overflow-hidden"><table className="w-full text-sm text-left"><thead className="bg-slate-50 dark:bg-slate-900"><tr><th className="px-4 py-3">{t('staff_form_role_title')}</th><th className="px-4 py-3">{t('status')}</th><th className="px-4 py-3">{t('staff_attendance_time')}</th><th className="px-4 py-3">Check Out</th>{canManageHR && <th className="px-4 py-3 text-right">{t('actions')}</th>}</tr></thead><tbody className="divide-y">{staff.filter(s => s.status === 'active').map(s => { const record = attendance.find(a => a.staffId === s.id); return (<tr key={s.id} className="hover:bg-slate-50"><td><div className="px-4 py-3"><div className="font-bold">{s.fullName}</div><div className="text-xs text-slate-400">{t(`staff_role_${s.type}`)}</div></div></td><td className="px-4 py-3">{record ? <Badge color={record.status === 'present' ? 'green' : 'yellow'}>{record.status}</Badge> : '-'}</td><td className="px-4 py-3 font-mono">{record?.checkIn || '-'}</td><td className="px-4 py-3 font-mono">{record?.checkOut || '-'}</td>{canManageHR && <td className="px-4 py-3 text-right"><div className="flex justify-end gap-2">{!record?.checkIn && <Button size="sm" onClick={() => handleCheckIn(s)}>In</Button>}{record?.checkIn && !record?.checkOut && <Button size="sm" variant="secondary" onClick={() => handleCheckOut(record)}>Out</Button>}<Button size="sm" variant="ghost" onClick={() => openAttendanceModal(s.id, s.fullName, 'present')}><Edit size={14}/></Button></div></td>}</tr>)})}</tbody></table></div>
          </div>
      )}

      {activeTab === 'leaves' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 animate-in fade-in">
              {leaves.length === 0 ? <p className="col-span-full text-center text-slate-400 py-10">{t('staff_no_leaves')}</p> : leaves.map(leave => (<div key={leave.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl border shadow-sm relative overflow-hidden"><div className={`absolute top-0 left-0 w-1 h-full ${leave.status === 'approved' ? 'bg-green-500' : 'bg-yellow-500'}`}></div><div className="flex justify-between items-start mb-2"><h4 className="font-bold">{leave.staffName}</h4><Badge color={leave.status === 'approved' ? 'green' : 'yellow'}>{leave.status}</Badge></div><div className="text-sm text-slate-500"><p>{leave.type} • {new Date(leave.startDate).toLocaleDateString()} - {new Date(leave.endDate).toLocaleDateString()}</p><p className="italic mt-2">"{leave.reason}"</p></div>{canManageHR && leave.status === 'pending' && <div className="flex gap-2 mt-4"><Button size="sm" className="flex-1 bg-green-600 border-none text-white" onClick={() => updateLeaveStatus(leave.id, 'approved')}>{t('hr_approve')}</Button><Button size="sm" variant="danger" className="flex-1" onClick={() => updateLeaveStatus(leave.id, 'rejected')}>{t('hr_reject')}</Button></div>}</div>))}
          </div>
      )}

      {activeTab === 'payroll' && (
          <div className="animate-in fade-in space-y-4">
              <div className="flex justify-start"><Input type="month" value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-auto" /></div>
              <div className="overflow-x-auto bg-white dark:bg-slate-800 rounded-xl border"><table className="min-w-full text-sm text-left"><thead className="bg-slate-50 dark:bg-slate-900"><tr><th className="px-4 py-3">{t('staff_form_role_title')}</th><th className="px-4 py-3 text-right">{t('staff_payroll_base')}</th><th className="px-4 py-3 text-right font-bold">{t('staff_payroll_net')}</th><th className="px-4 py-3 text-center">{t('status')}</th>{canManageHR && <th className="px-4 py-3"></th>}</tr></thead><tbody className="divide-y">{payroll.length === 0 ? <tr><td colSpan={5} className="text-center py-8">{t('staff_payroll_empty')}</td></tr> : payroll.map(p => (<tr key={p.id}><td><div className="px-4 py-3 font-medium">{p.staffName}</div></td><td className="px-4 py-3 text-right font-mono">${p.baseSalary.toLocaleString()}</td><td className="px-4 py-3 text-right font-mono font-bold">${p.netSalary.toLocaleString()}</td><td className="px-4 py-3 text-center"><Badge color={p.status === 'paid' ? 'green' : 'yellow'}>{p.status}</Badge></td><td className="px-4 py-3 text-right">{p.status === 'draft' && <Button size="sm" onClick={() => handleMarkPaid(p)}>Pay</Button>}</td></tr>))}</tbody></table></div>
          </div>
      )}

      {activeTab === 'financials' && (
          <div className="bg-white dark:bg-slate-800 rounded-xl border overflow-hidden animate-in fade-in"><table className="min-w-full text-sm text-left"><thead className="bg-slate-50 dark:bg-slate-900"><tr><th className="px-4 py-3">{t('date')}</th><th className="px-4 py-3">{t('staff_form_role_title')}</th><th className="px-4 py-3">{t('appointments_form_type')}</th><th className="px-4 py-3 text-right">{t('billing_table_header_amount')}</th></tr></thead><tbody className="divide-y">{financials.map(f => (<tr key={f.id}><td className="px-4 py-3">{new Date(f.date).toLocaleDateString()}</td><td className="px-4 py-3 font-medium">{f.staffName}</td><td className="px-4 py-3"><Badge color={f.type === 'bonus' ? 'green' : 'red'}>{f.type}</Badge></td><td className={`px-4 py-3 text-right font-mono font-bold ${f.type === 'bonus' ? 'text-green-600' : 'text-red-600'}`}>${f.amount.toLocaleString()}</td></tr>))}</tbody></table></div>
      )}

      {/* MODALS */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={staffForm.id ? t('staff_edit_employee') : t('staff_add_employee_button')}>
        <form onSubmit={handleCreateStaff} className="space-y-4 max-h-[80vh] overflow-y-auto pr-2 custom-scrollbar">
          <div className="grid grid-cols-2 gap-4"><Input label={t('patients_modal_form_fullName')} required value={staffForm.fullName} onChange={e => setStaffForm({...staffForm, fullName: e.target.value})} /><Select label={t('staff_form_role')} value={staffForm.type} onChange={e => setStaffForm({...staffForm, type: e.target.value})}><option value="doctor">{t('staff_role_doctor')}</option><option value="nurse">{t('staff_role_nurse')}</option><option value="technician">{t('staff_role_technician')}</option></Select></div>
          <div className="grid grid-cols-2 gap-4"><Select label={t('staff_form_department')} value={staffForm.department || ''} onChange={e => setStaffForm({...staffForm, department: e.target.value})}><option value="">Select...</option>{departments.map((d: any) => <option key={d.id} value={d.name_en}>{d.name_en}</option>)}</Select><Select label={t('staff_form_specialization')} value={staffForm.specialization || ''} onChange={e => setStaffForm({...staffForm, specialization: e.target.value})}><option value="">Select...</option>{specializations.map((s: any) => <option key={s.id} value={s.name_en}>{s.name_en}</option>)}</Select></div>
          <div className="grid grid-cols-2 gap-4"><Input label={t('staff_form_base_salary')} type="number" required value={staffForm.baseSalary} onChange={e => setStaffForm({...staffForm, baseSalary: e.target.value})} /><Input label={t('staff_form_consultation_fee')} type="number" value={staffForm.consultationFee} onChange={e => setStaffForm({...staffForm, consultationFee: e.target.value})} /></div>
          <div className="pt-4 border-t"><h4 className="text-sm font-bold text-slate-500 mb-2">{t('staff_form_availability')}</h4><div className="flex flex-wrap gap-2 mb-3">{DAYS_OF_WEEK.map((day) => (<button key={day} type="button" onClick={() => toggleDay(day)} className={`w-8 h-8 rounded-full text-xs font-bold ${ (staffForm.availableDays || []).includes(DAYS_OF_WEEK_EN[DAYS_OF_WEEK.indexOf(day)]) ? 'bg-primary-600 text-white' : 'bg-slate-100'}`}>{day}</button>))}</div><div className="grid grid-cols-2 gap-4"><Input label={t('staff_form_start_time')} type="time" value={staffForm.availableTimeStart} onChange={e => setStaffForm({...staffForm, availableTimeStart: e.target.value})} /><Input label={t('staff_form_end_time')} type="time" value={staffForm.availableTimeEnd} onChange={e => setStaffForm({...staffForm, availableTimeEnd: e.target.value})} /></div></div>
          <div className="flex justify-end pt-4 gap-3 border-t"><Button type="button" variant="secondary" onClick={() => setIsModalOpen(false)}>{t('cancel')}</Button><Button type="submit">{t('save')}</Button></div>
        </form>
      </Modal>

      <Modal isOpen={!!attendanceModal} onClose={() => setAttendanceModal(null)} title={t('staff_modal_attendance_title')}>
          {attendanceModal && (<form onSubmit={handleAttendanceSubmit} className="space-y-4"><div className="bg-slate-50 p-3 rounded-lg text-center"><p className="font-bold">{attendanceModal.staffName}</p></div><Select label={t('status')} value={attendanceModal.status} onChange={e => setAttendanceModal({...attendanceModal, status: e.target.value})}><option value="present">Present</option><option value="late">Late</option><option value="absent">Absent</option></Select><div className="grid grid-cols-2 gap-4"><Input label="In" type="time" value={attendanceModal.checkIn} onChange={e => setAttendanceModal({...attendanceModal, checkIn: e.target.value})} /><Input label="Out" type="time" value={attendanceModal.checkOut} onChange={e => setAttendanceModal({...attendanceModal, checkOut: e.target.value})} /></div><div className="flex justify-end pt-4 gap-3"><Button type="button" variant="secondary" onClick={() => setAttendanceModal(null)}>{t('cancel')}</Button><Button type="submit">{t('save')}</Button></div></form>)}
      </Modal>

      <Modal isOpen={isLeaveModalOpen} onClose={() => setIsLeaveModalOpen(false)} title={t('staff_leave_request')}><form onSubmit={handleLeaveRequest} className="space-y-4"><Select label={t('staff_form_role_title')} required value={leaveForm.staffId} onChange={e => setLeaveForm({...leaveForm, staffId: e.target.value})}><option value="">Select Employee...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}</Select><div className="grid grid-cols-2 gap-4"><Input label="Start" type="date" required value={leaveForm.startDate} onChange={e => setLeaveForm({...leaveForm, startDate: e.target.value})} /><Input label="End" type="date" required value={leaveForm.endDate} onChange={e => setLeaveForm({...leaveForm, endDate: e.target.value})} /></div><Textarea label={t('appointments_form_reason')} required value={leaveForm.reason} onChange={e => setLeaveForm({...leaveForm, reason: e.target.value})} /><Button type="submit" className="w-full">{t('submit')}</Button></form></Modal>

      <Modal isOpen={isAdjustmentModalOpen} onClose={() => setIsAdjustmentModalOpen(false)} title={t('staff_financial_add_entry')}><form onSubmit={handleAdjustmentSubmit} className="space-y-4"><Select label={t('staff_form_role_title')} required value={adjForm.staffId} onChange={e => setAdjForm({...adjForm, staffId: e.target.value})}><option value="">Select Employee...</option>{staff.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}</Select><Select label="Type" value={adjForm.type} onChange={e => setAdjForm({...adjForm, type: e.target.value})}><option value="bonus">Bonus</option><option value="fine">Fine</option></Select><Input label="Amount" type="number" required value={adjForm.amount} onChange={e => setAdjForm({...adjForm, amount: e.target.value})} /><Textarea label="Reason" required value={adjForm.reason} onChange={e => setAdjForm({...adjForm, reason: e.target.value})} /><Button type="submit" className="w-full">{t('save')}</Button></form></Modal>

      <ConfirmationDialog isOpen={confirmState.isOpen} onClose={() => setConfirmState({ ...confirmState, isOpen: false })} onConfirm={confirmState.action} title={confirmState.title} message={confirmState.message}/>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Modal, Badge, Input } from '../components/UI';
import { 
  Search, Calendar, Filter, Database, FileText, User, Users, 
  DollarSign, Bed, Activity, Download, Eye, ChevronLeft, ChevronRight,
  FileSpreadsheet, Printer, ChevronDown, Clock, ShieldCheck, Info, X, ExternalLink
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

interface SystemRecord {
  id: string; 
  originalId: number; 
  type: 'Patient' | 'Appointment' | 'Bill' | 'Admission'; 
  reference: string; 
  date: string; 
  primaryEntity: string; 
  associateEntity?: string; 
  status: string; 
  value?: number; 
  details?: any;
}

export const Records = () => {
  const { t, language } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [records, setRecords] = useState<SystemRecord[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedRecord, setSelectedRecord] = useState<SystemRecord | null>(null);

  // Sync Header
  useHeader(
    t('records_title'),
    t('records_subtitle'),
    <div className="relative" ref={exportMenuRef}>
      <Button variant="primary" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
        {t('records_export_button')} <ChevronDown size={14} className={`ml-2 transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
      </Button>
      {showExportMenu && (
        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 z-50 overflow-hidden animate-in fade-in zoom-in-95">
          <div className="px-4 py-2 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
             <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Export Current View</p>
          </div>
          <button onClick={() => { window.print(); setShowExportMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors"><Printer size={16} className="text-primary-500" /><span>Print as PDF Report</span></button>
          <button onClick={handleExportExcel} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors border-t border-slate-100 dark:border-slate-700"><FileSpreadsheet size={16} className="text-emerald-600" /><span>Download CSV (Excel)</span></button>
        </div>
      )}
    </div>
  );

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [pts, apts, bills] = await Promise.all([
          api.getPatients(), 
          api.getAppointments(), 
          api.getBills()
        ]);

        const all: SystemRecord[] = [];

        (pts || []).forEach((p: any) => all.push({ 
          id: `p-${p.id}`, 
          originalId: p.id, 
          type: 'Patient', 
          reference: p.patientId, 
          date: p.createdAt, 
          primaryEntity: p.fullName, 
          status: p.type, 
          details: p 
        }));

        (apts || []).forEach((a: any) => all.push({ 
          id: `a-${a.id}`, 
          originalId: a.id, 
          type: 'Appointment', 
          reference: a.appointmentNumber || `#${a.id}`, 
          date: a.datetime, 
          primaryEntity: a.patientName, 
          associateEntity: a.staffName,
          status: a.status, 
          details: a 
        }));

        (bills || []).forEach((b: any) => all.push({ 
          id: `b-${b.id}`, 
          originalId: b.id, 
          type: 'Bill', 
          reference: b.billNumber, 
          date: b.date, 
          primaryEntity: b.patientName, 
          status: b.status, 
          value: b.totalAmount, 
          details: b 
        }));

        setRecords(all.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
      } catch (e) { 
        console.error(e); 
      } finally { 
        setLoading(false); 
      }
    };
    fetchData();
  }, []);

  const handleExportExcel = () => {
    const headers = ["Type", "Date", "Reference", "Entity", "Associate", "Status", "Value"];
    const rows = filteredRecords.map(r => [
      r.type, 
      new Date(r.date).toLocaleString(), 
      r.reference, 
      r.primaryEntity, 
      r.associateEntity || "N/A", 
      r.status, 
      r.value || 0
    ]);

    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(',')).join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `allcare_system_records_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  const filteredRecords = useMemo(() => records.filter(r => {
      const search = searchTerm.toLowerCase();
      const matchesSearch = 
        r.reference.toLowerCase().includes(search) || 
        r.primaryEntity.toLowerCase().includes(search) ||
        (r.associateEntity && r.associateEntity.toLowerCase().includes(search));

      const matchesType = filterType === 'All' || r.type === filterType;
      const matchesStatus = statusFilter === 'All' || r.status.toLowerCase() === statusFilter.toLowerCase();

      return matchesSearch && matchesType && matchesStatus;
  }), [records, searchTerm, filterType, statusFilter]);

  const totalPages = Math.ceil(filteredRecords.length / itemsPerPage);
  const paginatedRecords = filteredRecords.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const getRecordIcon = (type: string) => {
    switch (type) {
      case 'Patient': return <Users className="text-blue-500" size={18} />;
      case 'Appointment': return <Calendar className="text-violet-500" size={18} />;
      case 'Bill': return <DollarSign className="text-emerald-500" size={18} />;
      default: return <FileText className="text-slate-400" size={18} />;
    }
  };

  const getStatusColor = (status: string) => {
    const s = status.toLowerCase();
    if (s.includes('paid') || s.includes('complete') || s.includes('active')) return 'green';
    if (s.includes('pending') || s.includes('waiting') || s.includes('reserved')) return 'yellow';
    if (s.includes('cancelled') || s.includes('refunded') || s.includes('overdue')) return 'red';
    return 'blue';
  };

  const RecordDetailItem = ({ label, value, icon: Icon }: any) => (
    <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-100 dark:border-slate-800">
      {Icon && <div className="p-2 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-slate-400"><Icon size={16} /></div>}
      <div className="flex-1 min-w-0">
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">{label}</p>
        <p className="text-sm font-bold text-slate-800 dark:text-slate-200 truncate">{value || 'N/A'}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Stats Summary for Records */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 no-print">
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Total Logs</p>
          <p className="text-2xl font-black text-slate-800 dark:text-white">{records.length.toLocaleString()}</p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Found</p>
          <p className="text-2xl font-black text-primary-600">{filteredRecords.length.toLocaleString()}</p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Last 24h</p>
          <p className="text-2xl font-black text-slate-800 dark:text-white">
            {records.filter(r => new Date(r.date).getTime() > Date.now() - 86400000).length}
          </p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">System Health</p>
          <div className="flex items-center gap-2 text-emerald-500 font-bold text-sm mt-1">
             <ShieldCheck size={16} /> Optimal
          </div>
        </Card>
      </div>

      <Card className="!p-0 overflow-hidden shadow-soft border-slate-200 dark:border-slate-700 print:shadow-none print:border-0">
        <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-b border-slate-200 dark:border-slate-700 flex flex-col lg:flex-row gap-4 no-print">
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary-500 transition-colors w-4 h-4" />
            <input 
              type="text" 
              placeholder={t('records_search_placeholder')} 
              className="pl-9 pr-4 py-2.5 w-full rounded-xl border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 outline-none transition-all" 
              value={searchTerm} 
              onChange={e => { setSearchTerm(e.target.value); setCurrentPage(1); }}
            />
          </div>
          <div className="flex gap-3 overflow-x-auto pb-1 lg:pb-0">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shrink-0">
              <Filter size={14} className="text-slate-400" />
              <select 
                className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none cursor-pointer" 
                value={filterType} 
                onChange={e => { setFilterType(e.target.value); setCurrentPage(1); }}
              >
                <option value="All">{t('records_filter_all')}</option>
                <option value="Patient">Patients</option>
                <option value="Appointment">Appointments</option>
                <option value="Bill">Invoices</option>
              </select>
            </div>

            <div className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shrink-0">
              <Clock size={14} className="text-slate-400" />
              <select 
                className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none cursor-pointer" 
                value={statusFilter} 
                onChange={e => { setStatusFilter(e.target.value); setCurrentPage(1); }}
              >
                <option value="All">All Statuses</option>
                <option value="Paid">Paid / Settled</option>
                <option value="Pending">Pending</option>
                <option value="Cancelled">Cancelled</option>
              </select>
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
            <thead className="bg-slate-50 dark:bg-slate-900/80">
              <tr>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Type / Ref</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Event Date</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Primary Entity</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-slate-500 uppercase tracking-widest no-print">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-100 dark:divide-slate-700/50">
              {loading ? (
                <tr><td colSpan={5} className="text-center py-20 text-slate-400 font-medium">{t('records_table_loading')}</td></tr>
              ) : paginatedRecords.length === 0 ? (
                <tr><td colSpan={5} className="text-center py-20 text-slate-400 font-medium">{t('records_table_empty')}</td></tr>
              ) : (
                paginatedRecords.map(r => (
                  <tr key={r.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors group cursor-pointer" onClick={() => { setSelectedRecord(r); setIsModalOpen(true); }}>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-slate-100 dark:bg-slate-700 rounded-lg text-slate-500 transition-colors group-hover:bg-primary-100 group-hover:text-primary-600">
                          {getRecordIcon(r.type)}
                        </div>
                        <div>
                          <p className="font-bold text-sm text-slate-800 dark:text-white">{r.reference}</p>
                          <p className="text-[10px] text-slate-400 font-black uppercase tracking-tight">{r.type}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                       <div className="flex flex-col">
                          <span className="text-sm font-medium text-slate-700 dark:text-slate-300">{new Date(r.date).toLocaleDateString()}</span>
                          <span className="text-[10px] text-slate-400 font-mono">{new Date(r.date).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                       </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-bold text-slate-900 dark:text-slate-200">{r.primaryEntity}</div>
                      {r.associateEntity && <div className="text-[10px] text-slate-500 flex items-center gap-1"><User size={10}/> {r.associateEntity}</div>}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <Badge color={getStatusColor(r.status) as any}>{r.status}</Badge>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right no-print">
                      <div className="flex justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                        <Button size="sm" variant="ghost" icon={Eye} />
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 flex flex-col sm:flex-row justify-between items-center gap-4 bg-slate-50/50 dark:bg-slate-900/30 no-print">
           <div className="text-xs text-slate-500 font-medium">
             Showing <span className="font-bold text-slate-900 dark:text-white">{paginatedRecords.length}</span> of <span className="font-bold text-slate-900 dark:text-white">{filteredRecords.length}</span> records
           </div>
           <div className="flex items-center gap-2">
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage === 1} icon={ChevronLeft}>Prev</Button>
             <div className="flex items-center gap-1 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-lg border text-xs font-bold shadow-sm">
                {currentPage} / {totalPages || 1}
             </div>
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage === totalPages}>Next <ChevronRight size={14} className="ml-1"/></Button>
           </div>
        </div>
      </Card>

      {/* Structured Details Modal */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={`Record Analysis: ${selectedRecord?.reference}`}
      >
        {selectedRecord && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200">
            {/* Header Badge Strip */}
            <div className="flex flex-wrap items-center gap-3 p-4 bg-primary-50 dark:bg-primary-900/20 rounded-2xl border border-primary-100 dark:border-primary-800/50">
              <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm text-primary-600">
                 {getRecordIcon(selectedRecord.type)}
              </div>
              <div className="flex-1">
                 <h3 className="font-black text-slate-900 dark:text-white text-lg leading-tight">{selectedRecord.primaryEntity}</h3>
                 <div className="flex items-center gap-2 mt-1">
                    <Badge color="blue">{selectedRecord.type}</Badge>
                    <Badge color={getStatusColor(selectedRecord.status) as any}>{selectedRecord.status}</Badge>
                 </div>
              </div>
              <div className="text-right hidden sm:block">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Entry Date</p>
                 <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{new Date(selectedRecord.date).toLocaleString()}</p>
              </div>
            </div>

            {/* Content Sections */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <RecordDetailItem label="Reference ID" value={selectedRecord.reference} icon={Hash} />
              <RecordDetailItem label="Original Database ID" value={selectedRecord.originalId} icon={Database} />
              {selectedRecord.associateEntity && (
                <RecordDetailItem label="Associate Entity" value={selectedRecord.associateEntity} icon={User} />
              )}
              {selectedRecord.value !== undefined && (
                <RecordDetailItem label="Transaction Value" value={`$${selectedRecord.value.toLocaleString()}`} icon={DollarSign} />
              )}
            </div>

            {/* Type Specific Context */}
            <div className="space-y-3">
               <h4 className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                 <Info size={14}/> Contextual Data
               </h4>
               <div className="bg-slate-50 dark:bg-slate-900/80 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 min-h-[100px]">
                  {selectedRecord.type === 'Bill' && (
                    <div className="space-y-4">
                       <div className="flex justify-between items-center pb-2 border-b border-slate-200 dark:border-slate-700">
                          <span className="text-sm font-bold">Line Items</span>
                          <span className="text-xs text-slate-500">{(selectedRecord.details?.items || []).length} items</span>
                       </div>
                       <div className="space-y-2">
                          {(selectedRecord.details?.items || []).map((item: any, idx: number) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                               <span className="text-slate-600 dark:text-slate-400">{item.description}</span>
                               <span className="font-mono font-bold">${item.amount.toLocaleString()}</span>
                            </div>
                          ))}
                       </div>
                       <div className="flex justify-between pt-4 border-t border-slate-200 dark:border-slate-700 font-black text-lg">
                          <span>Total Amount</span>
                          <span className="text-primary-600">${selectedRecord.value?.toLocaleString()}</span>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Appointment' && (
                    <div className="grid grid-cols-2 gap-6">
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Service Type</p>
                          <p className="text-sm font-bold">{selectedRecord.details?.type}</p>
                       </div>
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Queue Status</p>
                          <p className="text-sm font-bold">{selectedRecord.status}</p>
                       </div>
                       <div className="col-span-2">
                          <p className="text-xs text-slate-400 font-bold mb-1">Reason for Visit</p>
                          <p className="text-sm italic text-slate-600 dark:text-slate-300">"{selectedRecord.details?.reason || 'No reason provided'}"</p>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Patient' && (
                    <div className="grid grid-cols-3 gap-4 text-center">
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Age</p>
                          <p className="font-black text-lg">{selectedRecord.details?.age}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Gender</p>
                          <p className="font-black text-lg capitalize">{selectedRecord.details?.gender}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Blood</p>
                          <p className="font-black text-lg text-red-500">{selectedRecord.details?.bloodGroup || '-'}</p>
                       </div>
                    </div>
                  )}
               </div>
            </div>

            {/* Actions Footer */}
            <div className="pt-6 border-t border-slate-100 dark:border-slate-700 flex justify-between gap-3">
               <Button variant="ghost" icon={Printer} onClick={() => window.print()}>Print Record Details</Button>
               <div className="flex gap-2">
                 <Button variant="secondary" onClick={() => setIsModalOpen(false)}>Dismiss</Button>
                 <Button icon={ExternalLink}>Jump to Module</Button>
               </div>
            </div>
          </div>
        )}
      </Modal>

      {/* Print styles specifically for report generation */}
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .print-content, .print-content * { visibility: visible; }
          .print-content { position: absolute; left: 0; top: 0; width: 100%; }
          .no-print { display: none !important; }
          header, aside, .button-group { display: none !important; }
          .Card { border: 1px solid #e2e8f0 !important; box-shadow: none !important; }
          table { width: 100%; border-collapse: collapse; }
          th, td { padding: 12px; border-bottom: 1px solid #e2e8f0; text-align: left; }
          th { background-color: #f8fafc !important; }
        }
      `}</style>
    </div>
  );
};

const Hash = ({ size, className }: any) => <span className={className}>#</span>;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Modal, Badge, Input } from '../components/UI';
import { 
  Search, Calendar, Filter, Database, FileText, User, Users, 
  DollarSign, Bed, Activity, Download, Eye, ChevronLeft, ChevronRight,
  FileSpreadsheet, Printer, ChevronDown, Clock, ShieldCheck, Info, X, ExternalLink
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

interface SystemRecord {
  id: string; 
  originalId: number; 
  type: 'Patient' | 'Appointment' | 'Bill' | 'Admission'; 
  reference: string; 
  date: string; 
  primaryEntity: string; 
  associateEntity?: string; 
  status: string; 
  value?: number; 
  details?: any;
}

export const Records = () => {
  const { t, language } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [records, setRecords] = useState<SystemRecord[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedRecord, setSelectedRecord] = useState<SystemRecord | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [pts, apts, bills] = await Promise.all([
          api.getPatients(), 
          api.getAppointments(), 
          api.getBills()
        ]);

        const all: SystemRecord[] = [];

        (pts || []).forEach((p: any) => all.push({ 
          id: `p-${p.id}`, 
          originalId: p.id, 
          type: 'Patient', 
          reference: p.patientId, 
          date: p.createdAt, 
          primaryEntity: p.fullName, 
          status: p.type, 
          details: p 
        }));

        (apts || []).forEach((a: any) => all.push({ 
          id: `a-${a.id}`, 
          originalId: a.id, 
          type: 'Appointment', 
          reference: a.appointmentNumber || `#${a.id}`, 
          date: a.datetime, 
          primaryEntity: a.patientName, 
          associateEntity: a.staffName,
          status: a.status, 
          details: a 
        }));

        (bills || []).forEach((b: any) => all.push({ 
          id: `b-${b.id}`, 
          originalId: b.id, 
          type: 'Bill', 
          reference: b.billNumber, 
          date: b.date, 
          primaryEntity: b.patientName, 
          status: b.status, 
          value: b.totalAmount, 
          details: b 
        }));

        setRecords(all.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
      } catch (e) { 
        console.error(e); 
      } finally { 
        setLoading(false); 
      }
    };
    fetchData();
  }, []);

  const filteredRecords = useMemo(() => records.filter(r => {
      const search = searchTerm.toLowerCase();
      const matchesSearch = 
        r.reference.toLowerCase().includes(search) || 
        r.primaryEntity.toLowerCase().includes(search) ||
        (r.associateEntity && r.associateEntity.toLowerCase().includes(search));

      const matchesType = filterType === 'All' || r.type === filterType;
      const matchesStatus = statusFilter === 'All' || r.status.toLowerCase() === statusFilter.toLowerCase();

      return matchesSearch && matchesType && matchesStatus;
  }), [records, searchTerm, filterType, statusFilter]);

  const handleExportExcel = () => {
    const headers = ["Type", "Date", "Reference", "Entity", "Associate", "Status", "Value"];
    const rows = filteredRecords.map(r => [
      r.type, 
      new Date(r.date).toLocaleString(), 
      r.reference, 
      r.primaryEntity, 
      r.associateEntity || "N/A", 
      r.status, 
      r.value || 0
    ]);

    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(',')).join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `allcare_system_records_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  // FIX: Moved useHeader after handleExportExcel definition to fix temporal dead zone error where the handleExportExcel variable was used before its declaration.
  // Sync Header
  useHeader(
    t('records_title'),
    t('records_subtitle'),
    <div className="relative" ref={exportMenuRef}>
      <Button variant="primary" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
        {t('records_export_button')} <ChevronDown size={14} className={`ml-2 transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
      </Button>
      {showExportMenu && (
        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 z-50 overflow-hidden animate-in fade-in zoom-in-95">
          <div className="px-4 py-2 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
             <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Export Current View</p>
          </div>
          <button onClick={() => { window.print(); setShowExportMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors"><Printer size={16} className="text-primary-500" /><span>Print as PDF Report</span></button>
          <button onClick={handleExportExcel} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors border-t border-slate-100 dark:border-slate-700"><FileSpreadsheet size={16} className="text-emerald-600" /><span>Download CSV (Excel)</span></button>
        </div>
      )}
    </div>
  );

  const totalPages = Math.ceil(filteredRecords.length / itemsPerPage);
  const paginatedRecords = filteredRecords.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const getRecordIcon = (type: string) => {
    switch (type) {
      case 'Patient': return <Users className="text-blue-500" size={18} />;
      case 'Appointment': return <Calendar className="text-violet-500" size={18} />;
      case 'Bill': return <DollarSign className="text-emerald-500" size={18} />;
      default: return <FileText className="text-slate-400" size={18} />;
    }
  };

  const getStatusColor = (status: string) => {
    const s = status.toLowerCase();
    if (s.includes('paid') || s.includes('complete') || s.includes('active')) return 'green';
    if (s.includes('pending') || s.includes('waiting') || s.includes('reserved')) return 'yellow';
    if (s.includes('cancelled') || s.includes('refunded') || s.includes('overdue')) return 'red';
    return 'blue';
  };

  const RecordDetailItem = ({ label, value, icon: Icon }: any) => (
    <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-100 dark:border-slate-800">
      {Icon && <div className="p-2 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-slate-400"><Icon size={16} /></div>}
      <div className="flex-1 min-w-0">
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">{label}</p>
        <p className="text-sm font-bold text-slate-800 dark:text-slate-200 truncate">{value || 'N/A'}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Stats Summary for Records */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 no-print">
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Total Logs</p>
          <p className="text-2xl font-black text-slate-800 dark:text-white">{records.length.toLocaleString()}</p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Found</p>
          <p className="text-2xl font-black text-primary-600">{filteredRecords.length.toLocaleString()}</p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Last 24h</p>
          <p className="text-2xl font-black text-slate-800 dark:text-white">
            {records.filter(r => new Date(r.date).getTime() > Date.now() - 86400000).length}
          </p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">System Health</p>
          <div className="flex items-center gap-2 text-emerald-500 font-bold text-sm mt-1">
             <ShieldCheck size={16} /> Optimal
          </div>
        </Card>
      </div>

      <Card className="!p-0 overflow-hidden shadow-soft border-slate-200 dark:border-slate-700 print:shadow-none print:border-0">
        <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-b border-slate-200 dark:border-slate-700 flex flex-col lg:flex-row gap-4 no-print">
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary-500 transition-colors w-4 h-4" />
            <input 
              type="text" 
              placeholder={t('records_search_placeholder')} 
              className="pl-9 pr-4 py-2.5 w-full rounded-xl border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 outline-none transition-all" 
              value={searchTerm} 
              onChange={e => { setSearchTerm(e.target.value); setCurrentPage(1); }}
            />
          </div>
          <div className="flex gap-3 overflow-x-auto pb-1 lg:pb-0">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shrink-0">
              <Filter size={14} className="text-slate-400" />
              <select 
                className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none cursor-pointer" 
                value={filterType} 
                onChange={e => { setFilterType(e.target.value); setCurrentPage(1); }}
              >
                <option value="All">{t('records_filter_all')}</option>
                <option value="Patient">Patients</option>
                <option value="Appointment">Appointments</option>
                <option value="Bill">Invoices</option>
              </select>
            </div>

            <div className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shrink-0">
              <Clock size={14} className="text-slate-400" />
              <select 
                className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none cursor-pointer" 
                value={statusFilter} 
                onChange={e => { setStatusFilter(e.target.value); setCurrentPage(1); }}
              >
                <option value="All">All Statuses</option>
                <option value="Paid">Paid / Settled</option>
                <option value="Pending">Pending</option>
                <option value="Cancelled">Cancelled</option>
              </select>
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
            <thead className="bg-slate-50 dark:bg-slate-900/80">
              <tr>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Type / Ref</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Event Date</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Primary Entity</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-slate-500 uppercase tracking-widest no-print">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-100 dark:divide-slate-700/50">
              {loading ? (
                <tr><td colSpan={5} className="text-center py-20 text-slate-400 font-medium">{t('records_table_loading')}</td></tr>
              ) : paginatedRecords.length === 0 ? (
                <tr><td colSpan={5} className="text-center py-20 text-slate-400 font-medium">{t('records_table_empty')}</td></tr>
              ) : (
                paginatedRecords.map(r => (
                  <tr key={r.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors group cursor-pointer" onClick={() => { setSelectedRecord(r); setIsModalOpen(true); }}>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-slate-100 dark:bg-slate-700 rounded-lg text-slate-500 transition-colors group-hover:bg-primary-100 group-hover:text-primary-600">
                          {getRecordIcon(r.type)}
                        </div>
                        <div>
                          <p className="font-bold text-sm text-slate-800 dark:text-white">{r.reference}</p>
                          <p className="text-[10px] text-slate-400 font-black uppercase tracking-tight">{r.type}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                       <div className="flex flex-col">
                          <span className="text-sm font-medium text-slate-700 dark:text-slate-300">{new Date(r.date).toLocaleDateString()}</span>
                          <span className="text-[10px] text-slate-400 font-mono">{new Date(r.date).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                       </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-bold text-slate-900 dark:text-slate-200">{r.primaryEntity}</div>
                      {r.associateEntity && <div className="text-[10px] text-slate-500 flex items-center gap-1"><User size={10}/> {r.associateEntity}</div>}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <Badge color={getStatusColor(r.status) as any}>{r.status}</Badge>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right no-print">
                      <div className="flex justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                        <Button size="sm" variant="ghost" icon={Eye} />
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 flex flex-col sm:flex-row justify-between items-center gap-4 bg-slate-50/50 dark:bg-slate-900/30 no-print">
           <div className="text-xs text-slate-500 font-medium">
             Showing <span className="font-bold text-slate-900 dark:text-white">{paginatedRecords.length}</span> of <span className="font-bold text-slate-900 dark:text-white">{filteredRecords.length}</span> records
           </div>
           <div className="flex items-center gap-2">
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage === 1} icon={ChevronLeft}>Prev</Button>
             <div className="flex items-center gap-1 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-lg border text-xs font-bold shadow-sm">
                {currentPage} / {totalPages || 1}
             </div>
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage === totalPages}>Next <ChevronRight size={14} className="ml-1"/></Button>
           </div>
        </div>
      </Card>

      {/* Structured Details Modal */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={`Record Analysis: ${selectedRecord?.reference}`}
      >
        {selectedRecord && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200">
            {/* Header Badge Strip */}
            <div className="flex flex-wrap items-center gap-3 p-4 bg-primary-50 dark:bg-primary-900/20 rounded-2xl border border-primary-100 dark:border-primary-800/50">
              <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm text-primary-600">
                 {getRecordIcon(selectedRecord.type)}
              </div>
              <div className="flex-1">
                 <h3 className="font-black text-slate-900 dark:text-white text-lg leading-tight">{selectedRecord.primaryEntity}</h3>
                 <div className="flex items-center gap-2 mt-1">
                    <Badge color="blue">{selectedRecord.type}</Badge>
                    <Badge color={getStatusColor(selectedRecord.status) as any}>{selectedRecord.status}</Badge>
                 </div>
              </div>
              <div className="text-right hidden sm:block">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Entry Date</p>
                 <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{new Date(selectedRecord.date).toLocaleString()}</p>
              </div>
            </div>

            {/* Content Sections */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <RecordDetailItem label="Reference ID" value={selectedRecord.reference} icon={Hash} />
              <RecordDetailItem label="Original Database ID" value={selectedRecord.originalId} icon={Database} />
              {selectedRecord.associateEntity && (
                <RecordDetailItem label="Associate Entity" value={selectedRecord.associateEntity} icon={User} />
              )}
              {selectedRecord.value !== undefined && (
                <RecordDetailItem label="Transaction Value" value={`$${selectedRecord.value.toLocaleString()}`} icon={DollarSign} />
              )}
            </div>

            {/* Type Specific Context */}
            <div className="space-y-3">
               <h4 className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                 <Info size={14}/> Contextual Data
               </h4>
               <div className="bg-slate-50 dark:bg-slate-900/80 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 min-h-[100px]">
                  {selectedRecord.type === 'Bill' && (
                    <div className="space-y-4">
                       <div className="flex justify-between items-center pb-2 border-b border-slate-200 dark:border-slate-700">
                          <span className="text-sm font-bold">Line Items</span>
                          <span className="text-xs text-slate-500">{(selectedRecord.details?.items || []).length} items</span>
                       </div>
                       <div className="space-y-2">
                          {(selectedRecord.details?.items || []).map((item: any, idx: number) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                               <span className="text-slate-600 dark:text-slate-400">{item.description}</span>
                               <span className="font-mono font-bold">${item.amount.toLocaleString()}</span>
                            </div>
                          ))}
                       </div>
                       <div className="flex justify-between pt-4 border-t border-slate-200 dark:border-slate-700 font-black text-lg">
                          <span>Total Amount</span>
                          <span className="text-primary-600">${selectedRecord.value?.toLocaleString()}</span>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Appointment' && (
                    <div className="grid grid-cols-2 gap-6">
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Service Type</p>
                          <p className="text-sm font-bold">{selectedRecord.details?.type}</p>
                       </div>
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Queue Status</p>
                          <p className="text-sm font-bold">{selectedRecord.status}</p>
                       </div>
                       <div className="col-span-2">
                          <p className="text-xs text-slate-400 font-bold mb-1">Reason for Visit</p>
                          <p className="text-sm italic text-slate-600 dark:text-slate-300">"{selectedRecord.details?.reason || 'No reason provided'}"</p>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Patient' && (
                    <div className="grid grid-cols-3 gap-4 text-center">
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Age</p>
                          <p className="font-black text-lg">{selectedRecord.details?.age}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Gender</p>
                          <p className="font-black text-lg capitalize">{selectedRecord.details?.gender}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Blood</p>
                          <p className="font-black text-lg text-red-500">{selectedRecord.details?.bloodGroup || '-'}</p>
                       </div>
                    </div>
                  )}
               </div>
            </div>

            {/* Actions Footer */}
            <div className="pt-6 border-t border-slate-100 dark:border-slate-700 flex justify-between gap-3">
               <Button variant="ghost" icon={Printer} onClick={() => window.print()}>Print Record Details</Button>
               <div className="flex gap-2">
                 <Button variant="secondary" onClick={() => setIsModalOpen(false)}>Dismiss</Button>
                 <Button icon={ExternalLink}>Jump to Module</Button>
               </div>
            </div>
          </div>
        )}
      </Modal>

      {/* Print styles specifically for report generation */}
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .print-content, .print-content * { visibility: visible; }
          .print-content { position: absolute; left: 0; top: 0; width: 100%; }
          .no-print { display: none !important; }
          header, aside, .button-group { display: none !important; }
          .Card { border: 1px solid #e2e8f0 !important; box-shadow: none !important; }
          table { width: 100%; border-collapse: collapse; }
          th, td { padding: 12px; border-bottom: 1px solid #e2e8f0; text-align: left; }
          th { background-color: #f8fafc !important; }
