                       </div>
                       <div className="flex-1 min-w-0">
                          <div className="flex justify-between items-start">
                             <h4 className="font-bold text-slate-900 dark:text-white truncate">{act.name}</h4>
                             <span className="text-[10px] font-bold text-slate-400 whitespace-nowrap uppercase tracking-widest">{new Date(act.date).toLocaleString()}</span>
                          </div>
                          <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">
                             {(act as any).sub && <span className="font-bold text-slate-700 dark:text-slate-300">{(act as any).sub} • </span>}
                             {act.meta}
                          </p>
                       </div>
                    </div>
                  ))
                )}
             </div>
          </Card>
        )}
      </div>

      {/* Global CSS for Report Printing */}
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .print-content, .print-content * { visibility: visible; }
          .print-content { 
            position: absolute; 
            left: 0; 
            top: 0; 
            width: 100%; 
            background: white !important;
            padding: 40px !important;
          }
          .no-print { display: none !important; }
          .Card { border: 1px solid #eee !important; box-shadow: none !important; margin-bottom: 20px; page-break-inside: avoid; }
          .recharts-legend-wrapper { position: static !important; }
          header, aside { display: none !important; }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Input, Badge, Modal } from '../components/UI';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area, PieChart, Pie, Cell, Legend, LineChart, Line
} from 'recharts';
import { 
  TrendingUp, Users, Calendar, DollarSign, Download, 
  Activity, ArrowUpRight, ArrowDownRight, Filter, CheckCircle,
  FilePlus, Clock, CreditCard, Shield, Printer, ChevronDown, 
  UserCheck, Stethoscope, Landmark, Layers, History, 
  TrendingDown, Zap, BarChart3, PieChart as PieIcon, Info, User, Hash, ExternalLink, X
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

export const Reports = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'financial' | 'operational' | 'demographics' | 'activity'>('financial');
  const [rangeType, setRangeType] = useState('30');
  const [customRange, setCustomRange] = useState({ start: '', end: '' });
  const [loading, setLoading] = useState(true);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  const [bills, setBills] = useState<any[]>([]);
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // Event Detail State
  const [selectedEvent, setSelectedEvent] = useState<any>(null);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);

  // Date Range Logic
  const dateRange = useMemo(() => {
    if (rangeType === 'custom') {
        const start = customRange.start ? new Date(customRange.start + 'T00:00:00') : new Date(0); 
        const end = customRange.end ? new Date(customRange.end + 'T23:59:59.999') : new Date();
        return { start, end };
    }
    const end = new Date(); 
    const start = new Date();
    start.setDate(end.getDate() - parseInt(rangeType));
    start.setHours(0,0,0,0); 
    end.setHours(23,59,59,999);
    return { start, end };
  }, [rangeType, customRange]);

  const filterByDate = (data: any[], dateField: string) => data.filter(item => {
    if (!item[dateField]) return false;
    const d = new Date(item[dateField]);
    return d >= dateRange.start && d <= dateRange.end;
  });

  // --- ANALYTICS CALCULATIONS ---

  const financialStats = useMemo(() => {
    const fb = filterByDate(bills, 'date');
    const ft = filterByDate(transactions, 'date');

    const trMap = new Map();
    fb.forEach(b => {
      const key = new Date(b.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      trMap.set(key, (trMap.get(key) || 0) + (b.paidAmount || 0));
    });

    const methodMap: Record<string, number> = {};
    ft.filter(tx => tx.type === 'income').forEach(tx => {
      const method = tx.method || 'Unknown';
      methodMap[method] = (methodMap[method] || 0) + tx.amount;
    });

    const serviceMap: Record<string, number> = {};
    fb.forEach(bill => {
      (bill.items || []).forEach((item: any) => {
        serviceMap[item.description] = (serviceMap[item.description] || 0) + item.amount;
      });
    });

    const totalIncome = ft.filter(tx => tx.type === 'income').reduce((sum, tx) => sum + tx.amount, 0);
    const totalExpenses = ft.filter(tx => tx.type === 'expense').reduce((sum, tx) => sum + tx.amount, 0);

    return {
      totalRevenue: totalIncome,
      totalExpenses: totalExpenses,
      netProfit: totalIncome - totalExpenses,
      outstanding: fb.reduce((sum, b) => sum + ((b.totalAmount || 0) - (b.paidAmount || 0)), 0),
      avgInvoice: fb.length ? Math.round(fb.reduce((sum, b) => sum + (b.totalAmount || 0), 0) / fb.length) : 0,
      revenueTrend: Array.from(trMap).map(([name, value]) => ({ name, value })),
      incomeByMethod: Object.entries(methodMap).map(([name, value]) => ({ name, value })),
      topServices: Object.entries(serviceMap)
        .map(([name, value]) => ({ name, value }))
        .sort((a,b) => b.value - a.value)
        .slice(0, 5)
    };
  }, [bills, transactions, dateRange]);

  const operationalStats = useMemo(() => {
    const fa = filterByDate(appointments, 'datetime');
    const deptMap: Record<string, number> = {};
    const doctorMap: Record<string, number> = {};

    fa.forEach(a => {
      deptMap[a.type] = (deptMap[a.type] || 0) + 1;
      doctorMap[a.staffName] = (doctorMap[a.staffName] || 0) + 1;
    });

    const completionRate = fa.length ? Math.round((fa.filter(a => a.status === 'completed').length / fa.length) * 100) : 0;

    return {
      total: fa.length,
      completionRate,
      deptRank: Object.entries(deptMap).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value).slice(0, 5),
      doctorRank: Object.entries(doctorMap).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value).slice(0, 5)
    };
  }, [appointments, dateRange]);

  const patientStats = useMemo(() => {
    const fp = filterByDate(patients, 'createdAt');

    const growthMap = new Map();
    fp.forEach(p => {
        const key = new Date(p.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
        growthMap.set(key, (growthMap.get(key) || 0) + 1);
    });

    const male = fp.filter(p => p.gender === 'male').length;
    const female = fp.filter(p => p.gender === 'female').length;

    const pediatric = fp.filter(p => p.age < 18).length;
    const adult = fp.filter(p => p.age >= 18 && p.age < 60).length;
    const senior = fp.filter(p => p.age >= 60).length;

    return {
      total: patients.length,
      newCount: fp.length,
      growthTrend: Array.from(growthMap).map(([name, count]) => ({ name, count })),
      genderSplit: [
        { name: 'Male', value: male },
        { name: 'Female', value: female }
      ],
      ageDist: [
        { name: 'Pediatric', value: pediatric },
        { name: 'Adult', value: adult },
        { name: 'Senior', value: senior }
      ]
    };
  }, [patients, dateRange]);

  const activityStream = useMemo(() => {
    const stream = [
      ...patients.map(p => ({ type: 'patient', name: p.fullName, date: p.createdAt, meta: 'New Registration', id: `p-${p.id}`, raw: p })),
      ...appointments.map(a => ({ type: 'appointment', name: a.patientName, sub: a.staffName, date: a.datetime, meta: a.status, id: `a-${a.id}`, raw: a })),
      ...bills.map(b => ({ type: 'bill', name: b.patientName, sub: `$${b.totalAmount.toLocaleString()}`, date: b.date, meta: b.status, id: `b-${b.id}`, raw: b }))
    ];
    return stream.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 20);
  }, [patients, appointments, bills]);

  const handleExportCSV = () => {
    const headers = ["Metric", "Value", "Context"];
    let rows = [];
    const dateStr = `${dateRange.start.toLocaleDateString()} - ${dateRange.end.toLocaleDateString()}`;

    if (activeTab === 'financial') {
        rows = [
            ["Total Revenue", financialStats.totalRevenue, dateStr],
            ["Total Expenses", financialStats.totalExpenses, dateStr],
            ["Net Profit", financialStats.netProfit, dateStr],
            ["Outstanding Bills", financialStats.outstanding, dateStr]
        ];
    } else {
        rows = [
            ["Total Registered", patientStats.total, "All Time"],
            ["New in Period", patientStats.newCount, dateStr]
        ];
    }

    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(',')).join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `AllCare_HMS_Report_${activeTab}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  // Sync Header
  useHeader(
    t('reports_title'), 
    t('reports_subtitle'), 
    <div className="relative" ref={exportMenuRef}>
      <Button variant="primary" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
        {t('reports_export_button')} <ChevronDown size={14} className={`ml-2 transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
      </Button>
      {showExportMenu && (
        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 z-50 overflow-hidden animate-in fade-in zoom-in-95">
          <button onClick={() => { window.print(); setShowExportMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors">
            <Printer size={16} className="text-primary-500" />
            <span>Export as PDF Report</span>
          </button>
          <button onClick={handleExportCSV} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors border-t border-slate-100 dark:border-slate-700">
            <Landmark size={16} className="text-emerald-600" />
            <span>Download CSV (Excel)</span>
          </button>
        </div>
      )}
    </div>
  );

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [b, a, p, t_data, s] = await Promise.all([
            api.getBills(), 
            api.getAppointments(), 
            api.getPatients(), 
            api.getTransactions(), 
            api.getStaff()
        ]);
        setBills(b || []); 
        setAppointments(a || []); 
        setPatients(p || []); 
        setTransactions(t_data || []); 
        setStaff(s || []);
      } catch (e) { 
        console.error(e); 
      } finally { 
        setLoading(false); 
      }
    };
    fetchData();
  }, []);

  const openEventDetails = (event: any) => {
    setSelectedEvent(event);
    setIsEventModalOpen(true);
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center h-96 gap-4">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      <p className="text-slate-500 font-medium">{t('loading')}</p>
    </div>
  );

  const StatCard = ({ title, value, subtitle, icon: Icon, colorClass, trend }: any) => (
    <Card className="!p-6 bg-white dark:bg-slate-800 shadow-soft border-slate-100 dark:border-slate-700 hover:shadow-lg transition-all duration-300">
      <div className="flex justify-between items-start">
        <div className={`p-3 rounded-2xl ${colorClass} text-white shadow-lg`}>
          <Icon size={24} />
        </div>
        {trend && (
           <div className={`flex items-center gap-1 text-[10px] font-black px-2 py-0.5 rounded-full ${trend > 0 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
              {trend > 0 ? <ArrowUpRight size={10}/> : <ArrowDownRight size={10}/>}
              {Math.abs(trend)}%
           </div>
        )}
      </div>
      <div className="mt-4">
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{title}</p>
        <h3 className="text-2xl font-black text-slate-900 dark:text-white leading-none">{value}</h3>
        {subtitle && <p className="text-[10px] text-slate-500 mt-2 font-bold">{subtitle}</p>}
      </div>
    </Card>
  );

  const RecordDetailItem = ({ label, value, icon: Icon }: any) => (
    <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-100 dark:border-slate-800">
      {Icon && <div className="p-2 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-slate-400"><Icon size={16} /></div>}
      <div className="flex-1 min-w-0">
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">{label}</p>
        <p className="text-sm font-bold text-slate-800 dark:text-slate-200 truncate">{value || 'N/A'}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Filters Bar */}
      <div className="flex flex-col md:flex-row justify-between items-center bg-white dark:bg-slate-800 p-4 rounded-2xl border shadow-soft gap-4 no-print">
        <div className="flex flex-wrap gap-3 items-center w-full md:w-auto">
          <div className="relative group">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary-500 w-4 h-4 transition-colors" />
            <select 
              className="pl-9 pr-4 py-2.5 bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-700 dark:text-slate-200 focus:ring-2 focus:ring-primary-500/20 outline-none transition-all cursor-pointer" 
              value={rangeType} 
              onChange={e => setRangeType(e.target.value)}
            >
              <option value="7">{t('reports_time_week')}</option>
              <option value="30">{t('reports_time_month')}</option>
              <option value="90">Quarterly (90 Days)</option>
              <option value="custom">{t('reports_time_custom')}</option>
            </select>
          </div>
          {rangeType === 'custom' && (
            <div className="flex items-center gap-2 animate-in slide-in-from-left-2 duration-300">
              <Input type="date" value={customRange.start} onChange={e => setCustomRange({...customRange, start: e.target.value})} className="!py-2 w-36 shadow-none" />
              <span className="text-slate-400 font-bold">-</span>
              <Input type="date" value={customRange.end} onChange={e => setCustomRange({...customRange, end: e.target.value})} className="!py-2 w-36 shadow-none" />
            </div>
          )}
        </div>

        <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1.5 rounded-2xl shrink-0 w-full md:w-auto overflow-x-auto">
          {[
              { id: 'financial', label: t('reports_tab_financial'), icon: DollarSign },
              { id: 'operational', label: t('reports_tab_operational'), icon: Activity },
              { id: 'demographics', label: t('reports_tab_demographics'), icon: Users },
              { id: 'activity', label: 'Activity Log', icon: History }
          ].map(tab => (
            <button 
              key={tab.id} 
              onClick={() => setActiveTab(tab.id as any)} 
              className={`flex items-center gap-2 px-5 py-2 text-xs font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white dark:bg-slate-800 shadow-soft text-primary-600' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
            >
              <tab.icon size={14}/> {tab.label}
            </button>
          ))}
        </div>
      </div>

      <div className="print-content">
        {/* --- FINANCIAL VIEW --- */}
        {activeTab === 'financial' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              <StatCard title="Net Profit/Loss" value={`$${financialStats.netProfit.toLocaleString()}`} subtitle="Revenue vs Expenses" icon={TrendingUp} colorClass={financialStats.netProfit >= 0 ? "bg-emerald-500" : "bg-rose-500"} />
              <StatCard title="Gross Revenue" value={`$${financialStats.totalRevenue.toLocaleString()}`} subtitle="Payments collected" icon={CreditCard} colorClass="bg-blue-500" trend={12} />
              <StatCard title="Outstanding" value={`$${financialStats.outstanding.toLocaleString()}`} subtitle="Awaiting settlement" icon={Clock} colorClass="bg-orange-500" />
              <StatCard title="Avg per Patient" value={`$${financialStats.avgInvoice.toLocaleString()}`} subtitle="Invoice average" icon={Zap} colorClass="bg-violet-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <Card className="lg:col-span-2 !p-0" title="Revenue Realization Trend">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={financialStats.revenueTrend}>
                      <defs>
                        <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.2}/>
                          <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                      <XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <YAxis tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 20px -2px rgba(0,0,0,0.1)' }} />
                      <Area type="monotone" dataKey="value" stroke="#3b82f6" strokeWidth={3} fillOpacity={1} fill="url(#colorRev)" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </Card>

              <Card className="!p-0" title="Income by Method">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie data={financialStats.incomeByMethod} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                        {financialStats.incomeByMethod.map((entry, index) => <Cell key={index} fill={COLORS[index % COLORS.length]} />)}
                      </Pie>
                      <Tooltip formatter={(val: number) => `$${val.toLocaleString()}`} />
                      <Legend verticalAlign="bottom" height={36}/>
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </Card>

              <Card className="lg:col-span-3 !p-0" title="Top Services by Generated Revenue">
                <div className="h-64 w-full p-6">
                   <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={financialStats.topServices} layout="vertical" margin={{ left: 40, right: 40 }}>
                        <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                        <XAxis type="number" hide />
                        <YAxis dataKey="name" type="category" tick={{fontSize: 11, fontWeight: 'bold'}} width={150} axisLine={false} tickLine={false} />
                        <Tooltip formatter={(val: number) => `$${val.toLocaleString()}`} />
                        <Bar dataKey="value" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={24} />
                      </BarChart>
                   </ResponsiveContainer>
                </div>
              </Card>
            </div>
          </div>
        )}

        {/* --- OPERATIONAL VIEW --- */}
        {activeTab === 'operational' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard title="Total Volume" value={operationalStats.total} subtitle="Appointments scheduled" icon={Calendar} colorClass="bg-blue-500" />
              <StatCard title="Fulfillment Rate" value={`${operationalStats.completionRate}%`} subtitle="Completed consultations" icon={UserCheck} colorClass="bg-emerald-500" />
              <StatCard title="Busiest Service" value={operationalStats.deptRank[0]?.name || '-'} subtitle="Primary demand driver" icon={BarChart3} colorClass="bg-orange-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <Card title="Department Utilization Split">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie data={operationalStats.deptRank} cx="50%" cy="50%" outerRadius={100} dataKey="value" label>
                        {operationalStats.deptRank.map((entry, index) => <Cell key={index} fill={COLORS[index % COLORS.length]} />)}
                      </Pie>
                      <Tooltip />
                      <Legend />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </Card>

              <Card title="Medical Staff Performance (Consultations)">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={operationalStats.doctorRank}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <YAxis tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <Tooltip cursor={{fill: 'transparent'}} />
                      <Bar dataKey="value" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </Card>
            </div>
          </div>
        )}

        {/* --- DEMOGRAPHICS VIEW --- */}
        {activeTab === 'demographics' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard title="Registry Size" value={patientStats.total} subtitle="Total registered patients" icon={Users} colorClass="bg-blue-500" />
              <StatCard title="Acquisition" value={patientStats.newCount} subtitle="New registrations in period" icon={FilePlus} colorClass="bg-emerald-500" trend={8} />
              <StatCard title="Primary Segment" value={patientStats.ageDist.sort((a,b)=>b.value-a.value)[0]?.name || '-'} subtitle="Largest patient base" icon={Layers} colorClass="bg-violet-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <Card className="lg:col-span-2" title="Daily Growth Trend">
                 <div className="h-80 w-full p-4">
                    <ResponsiveContainer width="100%" height="100%">
                       <LineChart data={patientStats.growthTrend}>
                          <CartesianGrid strokeDasharray="3 3" vertical={false} />
                          <XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                          <YAxis tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                          <Tooltip />
                          <Line type="monotone" dataKey="count" stroke="#10b981" strokeWidth={3} dot={{ r: 4, fill: '#10b981' }} />
                       </LineChart>
                    </ResponsiveContainer>
                 </div>
              </Card>

              <Card className="!p-0" title="Patient Age Groups">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie data={patientStats.ageDist} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                        {patientStats.ageDist.map((entry, index) => <Cell key={index} fill={COLORS[index % COLORS.length]} />)}
                      </Pie>
                      <Tooltip />
                      <Legend verticalAlign="bottom" height={36}/>
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </Card>
            </div>
          </div>
        )}

        {/* --- ACTIVITY STREAM --- */}
        {activeTab === 'activity' && (
          <Card className="!p-0 overflow-hidden animate-in fade-in duration-500" title="Recent Hospital Events Log">
             <div className="divide-y divide-slate-100 dark:divide-slate-700/50">
                {activityStream.length === 0 ? (
                  <div className="p-20 text-center text-slate-400 font-medium">No activity recorded for this period.</div>
                ) : (
                  activityStream.map((act, i) => (
                    <div 
                      key={act.id} 
                      onClick={() => openEventDetails(act)}
                      className="flex gap-4 p-5 items-start hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-all cursor-pointer group/item"
                    >
                       <div className={`p-3 rounded-xl shrink-0 transition-transform group-hover/item:scale-110 ${
                         act.type === 'patient' ? 'bg-blue-100 text-blue-600' : 
                         act.type === 'appointment' ? 'bg-violet-100 text-violet-600' : 
                         'bg-emerald-100 text-emerald-600'
                       }`}>
                          {act.type === 'patient' ? <Users size={20}/> : act.type === 'appointment' ? <Calendar size={20}/> : <CreditCard size={20}/>}
                       </div>
                       <div className="flex-1 min-w-0">
                          <div className="flex justify-between items-start">
                             <h4 className="font-bold text-slate-900 dark:text-white truncate group-hover/item:text-primary-600 transition-colors">{act.name}</h4>
                             <span className="text-[10px] font-bold text-slate-400 whitespace-nowrap uppercase tracking-widest">{new Date(act.date).toLocaleString()}</span>
                          </div>
                          <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">
                             {(act as any).sub && <span className="font-bold text-slate-700 dark:text-slate-300">{(act as any).sub} • </span>}
                             {act.meta}
                          </p>
                       </div>
                       <div className="self-center opacity-0 group-hover/item:opacity-100 transition-opacity">
                          <ChevronRight className="text-slate-300" size={18} />
                       </div>
                    </div>
                  ))
                )}
             </div>
          </Card>
        )}
      </div>

      {/* Structured Details Modal */}
      <Modal 
        isOpen={isEventModalOpen} 
        onClose={() => setIsEventModalOpen(false)} 
        title={`Audit Log: ${selectedEvent?.type.toUpperCase()}`}
      >
        {selectedEvent && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200">
            {/* Header Badge Strip */}
            <div className={`flex flex-wrap items-center gap-3 p-4 rounded-2xl border ${
              selectedEvent.type === 'patient' ? 'bg-blue-50 border-blue-100 dark:bg-blue-900/20' : 
              selectedEvent.type === 'appointment' ? 'bg-violet-50 border-violet-100 dark:bg-violet-900/20' : 
              'bg-emerald-50 border-emerald-100 dark:bg-emerald-900/20'
            }`}>
              <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm text-primary-600">
                 {selectedEvent.type === 'patient' ? <Users size={24}/> : selectedEvent.type === 'appointment' ? <Calendar size={24}/> : <DollarSign size={24}/>}
              </div>
              <div className="flex-1">
                 <h3 className="font-black text-slate-900 dark:text-white text-lg leading-tight">{selectedEvent.name}</h3>
                 <div className="flex items-center gap-2 mt-1">
                    <Badge color="blue" className="capitalize">{selectedEvent.type}</Badge>
                    <Badge color="gray">{selectedEvent.meta}</Badge>
                 </div>
              </div>
              <div className="text-right hidden sm:block">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Logged Time</p>
                 <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{new Date(selectedEvent.date).toLocaleString()}</p>
              </div>
            </div>

            {/* Content Sections */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {selectedEvent.type === 'patient' && (
                <>
                  <RecordDetailItem label="Patient ID" value={selectedEvent.raw.patientId} icon={Hash} />
                  <RecordDetailItem label="Contact" value={selectedEvent.raw.phone} icon={Stethoscope} />
                  <RecordDetailItem label="Age" value={`${selectedEvent.raw.age} years`} icon={Users} />
                  <RecordDetailItem label="Gender" value={selectedEvent.raw.gender} icon={Users} />
                </>
              )}
              {selectedEvent.type === 'appointment' && (
                <>
                  <RecordDetailItem label="Doctor" value={selectedEvent.raw.staffName} icon={User} />
                  <RecordDetailItem label="Appt ID" value={`#${selectedEvent.raw.id}`} icon={Hash} />
                  <RecordDetailItem label="Time Slot" value={new Date(selectedEvent.raw.datetime).toLocaleTimeString()} icon={Clock} />
                  <RecordDetailItem label="Status" value={selectedEvent.raw.status} icon={Info} />
                </>
              )}
              {selectedEvent.type === 'bill' && (
                <>
                  <RecordDetailItem label="Bill Number" value={selectedEvent.raw.billNumber} icon={Hash} />
                  <RecordDetailItem label="Total Amount" value={`$${selectedEvent.raw.totalAmount.toLocaleString()}`} icon={DollarSign} />
                  <RecordDetailItem label="Paid" value={`$${selectedEvent.raw.paidAmount.toLocaleString()}`} icon={CreditCard} />
                  <RecordDetailItem label="Status" value={selectedEvent.raw.status} icon={Info} />
                </>
              )}
            </div>

            {/* Sub Details Table / Context */}
            <div className="space-y-3">
               <h4 className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                 <Activity size={14}/> Technical Context
               </h4>
               <div className="bg-slate-50 dark:bg-slate-900/80 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                  {selectedEvent.type === 'bill' && (
                    <div className="space-y-3">
                       <div className="flex justify-between items-center pb-2 border-b border-slate-200 dark:border-slate-700">
                          <span className="text-sm font-bold">Line Items</span>
                          <span className="text-xs text-slate-500">{(selectedEvent.raw.items || []).length} entries</span>
                       </div>
                       <div className="space-y-2 max-h-40 overflow-y-auto">
                          {(selectedEvent.raw.items || []).map((item: any, idx: number) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                               <span className="text-slate-600 dark:text-slate-400">{item.description}</span>
                               <span className="font-mono font-bold">${item.amount.toLocaleString()}</span>
                            </div>
                          ))}
                       </div>
                    </div>
                  )}

                  {selectedEvent.type === 'appointment' && (
                    <div className="space-y-3">
                       <p className="text-xs font-bold text-slate-400 uppercase">Reason for visit</p>
                       <p className="text-sm italic text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 p-3 rounded-lg border">
                          "{selectedEvent.raw.reason || 'No clinical notes provided.'}"
                       </p>
                    </div>
                  )}

                  {selectedEvent.type === 'patient' && (
                    <div className="space-y-3">
                       <p className="text-xs font-bold text-slate-400 uppercase">Registered Address</p>
                       <p className="text-sm text-slate-700 dark:text-slate-300">
                          {selectedEvent.raw.address || 'No address provided.'}
                       </p>
                    </div>
                  )}
               </div>
            </div>

            {/* Actions Footer */}
            <div className="pt-6 border-t border-slate-100 dark:border-slate-700 flex justify-between gap-3">
               <Button variant="ghost" icon={Printer} onClick={() => window.print()}>Print Entry</Button>
               <div className="flex gap-2">
                 <Button variant="secondary" onClick={() => setIsEventModalOpen(false)}>Close</Button>
                 <Button icon={ExternalLink} variant="primary">Audit Records</Button>
               </div>
            </div>
          </div>
        )}
      </Modal>

      {/* Global CSS for Report Printing */}
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .print-content, .print-content * { visibility: visible; }
          .print-content { 
            position: absolute; 
            left: 0; 
            top: 0; 
            width: 100%; 
            background: white !important;
            padding: 40px !important;
          }
          .no-print { display: none !important; }
          .Card { border: 1px solid #eee !important; box-shadow: none !important; margin-bottom: 20px; page-break-inside: avoid; }
          .recharts-legend-wrapper { position: static !important; }
          header, aside { display: none !important; }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Input, Badge, Modal } from '../components/UI';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area, PieChart, Pie, Cell, Legend, LineChart, Line
} from 'recharts';
import { 
  TrendingUp, Users, Calendar, DollarSign, Download, 
  Activity, ArrowUpRight, ArrowDownRight, Filter, CheckCircle,
  FilePlus, Clock, CreditCard, Shield, Printer, ChevronDown, ChevronRight,
  UserCheck, Stethoscope, Landmark, Layers, History, 
  TrendingDown, Zap, BarChart3, PieChart as PieIcon, Info, User, Hash, ExternalLink, X
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

export const Reports = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'financial' | 'operational' | 'demographics' | 'activity'>('financial');
  const [rangeType, setRangeType] = useState('30');
  const [customRange, setCustomRange] = useState({ start: '', end: '' });
  const [loading, setLoading] = useState(true);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  const [bills, setBills] = useState<any[]>([]);
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // Event Detail State
  const [selectedEvent, setSelectedEvent] = useState<any>(null);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);

  // Date Range Logic
  const dateRange = useMemo(() => {
    if (rangeType === 'custom') {
        const start = customRange.start ? new Date(customRange.start + 'T00:00:00') : new Date(0); 
        const end = customRange.end ? new Date(customRange.end + 'T23:59:59.999') : new Date();
        return { start, end };
    }
    const end = new Date(); 
    const start = new Date();
    start.setDate(end.getDate() - parseInt(rangeType));
    start.setHours(0,0,0,0); 
    end.setHours(23,59,59,999);
    return { start, end };
  }, [rangeType, customRange]);

  const filterByDate = (data: any[], dateField: string) => data.filter(item => {
    if (!item[dateField]) return false;
    const d = new Date(item[dateField]);
    return d >= dateRange.start && d <= dateRange.end;
  });

  // --- ANALYTICS CALCULATIONS ---

  const financialStats = useMemo(() => {
    const fb = filterByDate(bills, 'date');
    const ft = filterByDate(transactions, 'date');

    const trMap = new Map();
    fb.forEach(b => {
      const key = new Date(b.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      trMap.set(key, (trMap.get(key) || 0) + (b.paidAmount || 0));
    });

    const methodMap: Record<string, number> = {};
    ft.filter(tx => tx.type === 'income').forEach(tx => {
      const method = tx.method || 'Unknown';
      methodMap[method] = (methodMap[method] || 0) + tx.amount;
    });

    const serviceMap: Record<string, number> = {};
    fb.forEach(bill => {
      (bill.items || []).forEach((item: any) => {
        serviceMap[item.description] = (serviceMap[item.description] || 0) + item.amount;
      });
    });

    const totalIncome = ft.filter(tx => tx.type === 'income').reduce((sum, tx) => sum + tx.amount, 0);
    const totalExpenses = ft.filter(tx => tx.type === 'expense').reduce((sum, tx) => sum + tx.amount, 0);

    return {
      totalRevenue: totalIncome,
      totalExpenses: totalExpenses,
      netProfit: totalIncome - totalExpenses,
      outstanding: fb.reduce((sum, b) => sum + ((b.totalAmount || 0) - (b.paidAmount || 0)), 0),
      avgInvoice: fb.length ? Math.round(fb.reduce((sum, b) => sum + (b.totalAmount || 0), 0) / fb.length) : 0,
      revenueTrend: Array.from(trMap).map(([name, value]) => ({ name, value })),
      incomeByMethod: Object.entries(methodMap).map(([name, value]) => ({ name, value })),
      topServices: Object.entries(serviceMap)
        .map(([name, value]) => ({ name, value }))
        .sort((a,b) => b.value - a.value)
        .slice(0, 5)
    };
  }, [bills, transactions, dateRange]);

  const operationalStats = useMemo(() => {
    const fa = filterByDate(appointments, 'datetime');
    const deptMap: Record<string, number> = {};
    const doctorMap: Record<string, number> = {};

    fa.forEach(a => {
      deptMap[a.type] = (deptMap[a.type] || 0) + 1;
      doctorMap[a.staffName] = (doctorMap[a.staffName] || 0) + 1;
    });

    const completionRate = fa.length ? Math.round((fa.filter(a => a.status === 'completed').length / fa.length) * 100) : 0;

    return {
      total: fa.length,
      completionRate,
      deptRank: Object.entries(deptMap).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value).slice(0, 5),
      doctorRank: Object.entries(doctorMap).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value).slice(0, 5)
    };
  }, [appointments, dateRange]);

  const patientStats = useMemo(() => {
    const fp = filterByDate(patients, 'createdAt');

    const growthMap = new Map();
    fp.forEach(p => {
        const key = new Date(p.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
        growthMap.set(key, (growthMap.get(key) || 0) + 1);
    });

    const male = fp.filter(p => p.gender === 'male').length;
    const female = fp.filter(p => p.gender === 'female').length;

    const pediatric = fp.filter(p => p.age < 18).length;
    const adult = fp.filter(p => p.age >= 18 && p.age < 60).length;
    const senior = fp.filter(p => p.age >= 60).length;

    return {
      total: patients.length,
      newCount: fp.length,
      growthTrend: Array.from(growthMap).map(([name, count]) => ({ name, count })),
      genderSplit: [
        { name: 'Male', value: male },
        { name: 'Female', value: female }
      ],
      ageDist: [
        { name: 'Pediatric', value: pediatric },
        { name: 'Adult', value: adult },
        { name: 'Senior', value: senior }
      ]
    };
  }, [patients, dateRange]);

  const activityStream = useMemo(() => {
    const stream = [
      ...patients.map(p => ({ type: 'patient', name: p.fullName, date: p.createdAt, meta: 'New Registration', id: `p-${p.id}`, raw: p })),
      ...appointments.map(a => ({ type: 'appointment', name: a.patientName, sub: a.staffName, date: a.datetime, meta: a.status, id: `a-${a.id}`, raw: a })),
      ...bills.map(b => ({ type: 'bill', name: b.patientName, sub: `$${b.totalAmount.toLocaleString()}`, date: b.date, meta: b.status, id: `b-${b.id}`, raw: b }))
    ];
    return stream.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 20);
  }, [patients, appointments, bills]);

  const handleExportCSV = () => {
    const headers = ["Metric", "Value", "Context"];
    let rows = [];
    const dateStr = `${dateRange.start.toLocaleDateString()} - ${dateRange.end.toLocaleDateString()}`;

    if (activeTab === 'financial') {
        rows = [
            ["Total Revenue", financialStats.totalRevenue, dateStr],
            ["Total Expenses", financialStats.totalExpenses, dateStr],
            ["Net Profit", financialStats.netProfit, dateStr],
            ["Outstanding Bills", financialStats.outstanding, dateStr]
        ];
    } else {
        rows = [
            ["Total Registered", patientStats.total, "All Time"],
            ["New in Period", patientStats.newCount, dateStr]
        ];
    }

    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(',')).join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `AllCare_HMS_Report_${activeTab}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  // Sync Header
  useHeader(
    t('reports_title'), 
    t('reports_subtitle'), 
    <div className="relative" ref={exportMenuRef}>
      <Button variant="primary" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
        {t('reports_export_button')} <ChevronDown size={14} className={`ml-2 transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
      </Button>
      {showExportMenu && (
        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 z-50 overflow-hidden animate-in fade-in zoom-in-95">
          <button onClick={() => { window.print(); setShowExportMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors">
            <Printer size={16} className="text-primary-500" />
            <span>Export as PDF Report</span>
          </button>
          <button onClick={handleExportCSV} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors border-t border-slate-100 dark:border-slate-700">
            <Landmark size={16} className="text-emerald-600" />
            <span>Download CSV (Excel)</span>
          </button>
        </div>
      )}
    </div>
  );

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [b, a, p, t_data, s] = await Promise.all([
            api.getBills(), 
            api.getAppointments(), 
            api.getPatients(), 
            api.getTransactions(), 
            api.getStaff()
        ]);
        setBills(b || []); 
        setAppointments(a || []); 
        setPatients(p || []); 
        setTransactions(t_data || []); 
        setStaff(s || []);
      } catch (e) { 
        console.error(e); 
      } finally { 
        setLoading(false); 
      }
    };
    fetchData();
  }, []);

  const openEventDetails = (event: any) => {
    setSelectedEvent(event);
    setIsEventModalOpen(true);
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center h-96 gap-4">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      <p className="text-slate-500 font-medium">{t('loading')}</p>
    </div>
  );

  const StatCard = ({ title, value, subtitle, icon: Icon, colorClass, trend }: any) => (
    <Card className="!p-6 bg-white dark:bg-slate-800 shadow-soft border-slate-100 dark:border-slate-700 hover:shadow-lg transition-all duration-300">
      <div className="flex justify-between items-start">
        <div className={`p-3 rounded-2xl ${colorClass} text-white shadow-lg`}>
          <Icon size={24} />
        </div>
        {trend && (
           <div className={`flex items-center gap-1 text-[10px] font-black px-2 py-0.5 rounded-full ${trend > 0 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
              {trend > 0 ? <ArrowUpRight size={10}/> : <ArrowDownRight size={10}/>}
              {Math.abs(trend)}%
           </div>
        )}
      </div>
      <div className="mt-4">
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{title}</p>
        <h3 className="text-2xl font-black text-slate-900 dark:text-white leading-none">{value}</h3>
        {subtitle && <p className="text-[10px] text-slate-500 mt-2 font-bold">{subtitle}</p>}
      </div>
    </Card>
  );

  const RecordDetailItem = ({ label, value, icon: Icon }: any) => (
    <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-100 dark:border-slate-800">
      {Icon && <div className="p-2 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-slate-400"><Icon size={16} /></div>}
      <div className="flex-1 min-w-0">
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">{label}</p>
        <p className="text-sm font-bold text-slate-800 dark:text-slate-200 truncate">{value || 'N/A'}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Filters Bar */}
      <div className="flex flex-col md:flex-row justify-between items-center bg-white dark:bg-slate-800 p-4 rounded-2xl border shadow-soft gap-4 no-print">
        <div className="flex flex-wrap gap-3 items-center w-full md:w-auto">
          <div className="relative group">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary-500 w-4 h-4 transition-colors" />
            <select 
              className="pl-9 pr-4 py-2.5 bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-700 dark:text-slate-200 focus:ring-2 focus:ring-primary-500/20 outline-none transition-all cursor-pointer" 
              value={rangeType} 
              onChange={e => setRangeType(e.target.value)}
            >
              <option value="7">{t('reports_time_week')}</option>
              <option value="30">{t('reports_time_month')}</option>
              <option value="90">Quarterly (90 Days)</option>
              <option value="custom">{t('reports_time_custom')}</option>
            </select>
          </div>
          {rangeType === 'custom' && (
            <div className="flex items-center gap-2 animate-in slide-in-from-left-2 duration-300">
              <Input type="date" value={customRange.start} onChange={e => setCustomRange({...customRange, start: e.target.value})} className="!py-2 w-36 shadow-none" />
              <span className="text-slate-400 font-bold">-</span>
              <Input type="date" value={customRange.end} onChange={e => setCustomRange({...customRange, end: e.target.value})} className="!py-2 w-36 shadow-none" />
            </div>
          )}
        </div>

        <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1.5 rounded-2xl shrink-0 w-full md:w-auto overflow-x-auto">
          {[
              { id: 'financial', label: t('reports_tab_financial'), icon: DollarSign },
              { id: 'operational', label: t('reports_tab_operational'), icon: Activity },
              { id: 'demographics', label: t('reports_tab_demographics'), icon: Users },
              { id: 'activity', label: 'Activity Log', icon: History }
          ].map(tab => (
            <button 
              key={tab.id} 
              onClick={() => setActiveTab(tab.id as any)} 
              className={`flex items-center gap-2 px-5 py-2 text-xs font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white dark:bg-slate-800 shadow-soft text-primary-600' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
            >
              <tab.icon size={14}/> {tab.label}
            </button>
          ))}
        </div>
      </div>

      <div className="print-content">
        {/* --- FINANCIAL VIEW --- */}
        {activeTab === 'financial' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              <StatCard title="Net Profit/Loss" value={`$${financialStats.netProfit.toLocaleString()}`} subtitle="Revenue vs Expenses" icon={TrendingUp} colorClass={financialStats.netProfit >= 0 ? "bg-emerald-500" : "bg-rose-500"} />
              <StatCard title="Gross Revenue" value={`$${financialStats.totalRevenue.toLocaleString()}`} subtitle="Payments collected" icon={CreditCard} colorClass="bg-blue-500" trend={12} />
              <StatCard title="Outstanding" value={`$${financialStats.outstanding.toLocaleString()}`} subtitle="Awaiting settlement" icon={Clock} colorClass="bg-orange-500" />
              <StatCard title="Avg per Patient" value={`$${financialStats.avgInvoice.toLocaleString()}`} subtitle="Invoice average" icon={Zap} colorClass="bg-violet-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <Card className="lg:col-span-2 !p-0" title="Revenue Realization Trend">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={financialStats.revenueTrend}>
                      <defs>
                        <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.2}/>
                          <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                      <XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <YAxis tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 20px -2px rgba(0,0,0,0.1)' }} />
                      <Area type="monotone" dataKey="value" stroke="#3b82f6" strokeWidth={3} fillOpacity={1} fill="url(#colorRev)" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </Card>

              <Card className="!p-0" title="Income by Method">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie data={financialStats.incomeByMethod} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                        {financialStats.incomeByMethod.map((entry, index) => <Cell key={index} fill={COLORS[index % COLORS.length]} />)}
                      </Pie>
                      <Tooltip formatter={(val: number) => `$${val.toLocaleString()}`} />
                      <Legend verticalAlign="bottom" height={36}/>
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </Card>

              <Card className="lg:col-span-3 !p-0" title="Top Services by Generated Revenue">
                <div className="h-64 w-full p-6">
                   <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={financialStats.topServices} layout="vertical" margin={{ left: 40, right: 40 }}>
                        <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                        <XAxis type="number" hide />
                        <YAxis dataKey="name" type="category" tick={{fontSize: 11, fontWeight: 'bold'}} width={150} axisLine={false} tickLine={false} />
                        <Tooltip formatter={(val: number) => `$${val.toLocaleString()}`} />
                        <Bar dataKey="value" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={24} />
                      </BarChart>
                   </ResponsiveContainer>
                </div>
              </Card>
            </div>
          </div>
        )}

        {/* --- OPERATIONAL VIEW --- */}
        {activeTab === 'operational' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard title="Total Volume" value={operationalStats.total} subtitle="Appointments scheduled" icon={Calendar} colorClass="bg-blue-500" />
              <StatCard title="Fulfillment Rate" value={`${operationalStats.completionRate}%`} subtitle="Completed consultations" icon={UserCheck} colorClass="bg-emerald-500" />
              <StatCard title="Busiest Service" value={operationalStats.deptRank[0]?.name || '-'} subtitle="Primary demand driver" icon={BarChart3} colorClass="bg-orange-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <Card title="Department Utilization Split">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie data={operationalStats.deptRank} cx="50%" cy="50%" outerRadius={100} dataKey="value" label>
                        {operationalStats.deptRank.map((entry, index) => <Cell key={index} fill={COLORS[index % COLORS.length]} />)}
                      </Pie>
                      <Tooltip />
                      <Legend />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </Card>

              <Card title="Medical Staff Performance (Consultations)">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={operationalStats.doctorRank}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} />
                      <XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <YAxis tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                      <Tooltip cursor={{fill: 'transparent'}} />
                      <Bar dataKey="value" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </Card>
            </div>
          </div>
        )}

        {/* --- DEMOGRAPHICS VIEW --- */}
        {activeTab === 'demographics' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard title="Registry Size" value={patientStats.total} subtitle="Total registered patients" icon={Users} colorClass="bg-blue-500" />
              <StatCard title="Acquisition" value={patientStats.newCount} subtitle="New registrations in period" icon={FilePlus} colorClass="bg-emerald-500" trend={8} />
              <StatCard title="Primary Segment" value={patientStats.ageDist.sort((a,b)=>b.value-a.value)[0]?.name || '-'} subtitle="Largest patient base" icon={Layers} colorClass="bg-violet-500" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <Card className="lg:col-span-2" title="Daily Growth Trend">
                 <div className="h-80 w-full p-4">
                    <ResponsiveContainer width="100%" height="100%">
                       <LineChart data={patientStats.growthTrend}>
                          <CartesianGrid strokeDasharray="3 3" vertical={false} />
                          <XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                          <YAxis tick={{fontSize: 10, fontWeight: 'bold'}} axisLine={false} tickLine={false} />
                          <Tooltip />
                          <Line type="monotone" dataKey="count" stroke="#10b981" strokeWidth={3} dot={{ r: 4, fill: '#10b981' }} />
                       </LineChart>
                    </ResponsiveContainer>
                 </div>
              </Card>

              <Card className="!p-0" title="Patient Age Groups">
                <div className="h-80 w-full p-4">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie data={patientStats.ageDist} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                        {patientStats.ageDist.map((entry, index) => <Cell key={index} fill={COLORS[index % COLORS.length]} />)}
                      </Pie>
                      <Tooltip />
                      <Legend verticalAlign="bottom" height={36}/>
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </Card>
            </div>
          </div>
        )}

        {/* --- ACTIVITY STREAM --- */}
        {activeTab === 'activity' && (
          <Card className="!p-0 overflow-hidden animate-in fade-in duration-500" title="Recent Hospital Events Log">
             <div className="divide-y divide-slate-100 dark:divide-slate-700/50">
                {activityStream.length === 0 ? (
                  <div className="p-20 text-center text-slate-400 font-medium">No activity recorded for this period.</div>
                ) : (
                  activityStream.map((act, i) => (
                    <div 
                      key={act.id} 
                      onClick={() => openEventDetails(act)}
                      className="flex gap-4 p-5 items-start hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-all cursor-pointer group/item"
                    >
                       <div className={`p-3 rounded-xl shrink-0 transition-transform group-hover/item:scale-110 ${
                         act.type === 'patient' ? 'bg-blue-100 text-blue-600' : 
                         act.type === 'appointment' ? 'bg-violet-100 text-violet-600' : 
                         'bg-emerald-100 text-emerald-600'
                       }`}>
                          {act.type === 'patient' ? <Users size={20}/> : act.type === 'appointment' ? <Calendar size={20}/> : <CreditCard size={20}/>}
                       </div>
                       <div className="flex-1 min-w-0">
                          <div className="flex justify-between items-start">
                             <h4 className="font-bold text-slate-900 dark:text-white truncate group-hover/item:text-primary-600 transition-colors">{act.name}</h4>
                             <span className="text-[10px] font-bold text-slate-400 whitespace-nowrap uppercase tracking-widest">{new Date(act.date).toLocaleString()}</span>
                          </div>
                          <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">
                             {(act as any).sub && <span className="font-bold text-slate-700 dark:text-slate-300">{(act as any).sub} • </span>}
                             {act.meta}
                          </p>
                       </div>
                       <div className="self-center opacity-0 group-hover/item:opacity-100 transition-opacity">
                          <ChevronRight className="text-slate-300" size={18} />
                       </div>
                    </div>
                  ))
                )}
             </div>
          </Card>
        )}
      </div>

      {/* Structured Details Modal */}
      <Modal 
        isOpen={isEventModalOpen} 
        onClose={() => setIsEventModalOpen(false)} 
        title={`Audit Log: ${selectedEvent?.type.toUpperCase()}`}
      >
        {selectedEvent && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200">
            {/* Header Badge Strip */}
            <div className={`flex flex-wrap items-center gap-3 p-4 rounded-2xl border ${
              selectedEvent.type === 'patient' ? 'bg-blue-50 border-blue-100 dark:bg-blue-900/20' : 
              selectedEvent.type === 'appointment' ? 'bg-violet-50 border-violet-100 dark:bg-violet-900/20' : 
              'bg-emerald-50 border-emerald-100 dark:bg-emerald-900/20'
            }`}>
              <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm text-primary-600">
                 {selectedEvent.type === 'patient' ? <Users size={24}/> : selectedEvent.type === 'appointment' ? <Calendar size={24}/> : <DollarSign size={24}/>}
              </div>
              <div className="flex-1">
                 <h3 className="font-black text-slate-900 dark:text-white text-lg leading-tight">{selectedEvent.name}</h3>
                 <div className="flex items-center gap-2 mt-1">
                    <Badge color="blue" className="capitalize">{selectedEvent.type}</Badge>
                    <Badge color="gray">{selectedEvent.meta}</Badge>
                 </div>
              </div>
              <div className="text-right hidden sm:block">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Logged Time</p>
                 <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{new Date(selectedEvent.date).toLocaleString()}</p>
              </div>
            </div>

            {/* Content Sections */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {selectedEvent.type === 'patient' && (
                <>
                  <RecordDetailItem label="Patient ID" value={selectedEvent.raw.patientId} icon={Hash} />
                  <RecordDetailItem label="Contact" value={selectedEvent.raw.phone} icon={Stethoscope} />
                  <RecordDetailItem label="Age" value={`${selectedEvent.raw.age} years`} icon={Users} />
                  <RecordDetailItem label="Gender" value={selectedEvent.raw.gender} icon={Users} />
                </>
              )}
              {selectedEvent.type === 'appointment' && (
                <>
                  <RecordDetailItem label="Doctor" value={selectedEvent.raw.staffName} icon={User} />
                  <RecordDetailItem label="Appt ID" value={`#${selectedEvent.raw.id}`} icon={Hash} />
                  <RecordDetailItem label="Time Slot" value={new Date(selectedEvent.raw.datetime).toLocaleTimeString()} icon={Clock} />
                  <RecordDetailItem label="Status" value={selectedEvent.raw.status} icon={Info} />
                </>
              )}
              {selectedEvent.type === 'bill' && (
                <>
                  <RecordDetailItem label="Bill Number" value={selectedEvent.raw.billNumber} icon={Hash} />
                  <RecordDetailItem label="Total Amount" value={`$${selectedEvent.raw.totalAmount.toLocaleString()}`} icon={DollarSign} />
                  <RecordDetailItem label="Paid" value={`$${selectedEvent.raw.paidAmount.toLocaleString()}`} icon={CreditCard} />
                  <RecordDetailItem label="Status" value={selectedEvent.raw.status} icon={Info} />
                </>
              )}
            </div>

            {/* Sub Details Table / Context */}
            <div className="space-y-3">
               <h4 className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                 <Activity size={14}/> Technical Context
               </h4>
               <div className="bg-slate-50 dark:bg-slate-900/80 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                  {selectedEvent.type === 'bill' && (
                    <div className="space-y-3">
                       <div className="flex justify-between items-center pb-2 border-b border-slate-200 dark:border-slate-700">
                          <span className="text-sm font-bold">Line Items</span>
                          <span className="text-xs text-slate-500">{(selectedEvent.raw.items || []).length} entries</span>
                       </div>
                       <div className="space-y-2 max-h-40 overflow-y-auto">
                          {(selectedEvent.raw.items || []).map((item: any, idx: number) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                               <span className="text-slate-600 dark:text-slate-400">{item.description}</span>
                               <span className="font-mono font-bold">${item.amount.toLocaleString()}</span>
                            </div>
                          ))}
                       </div>
                    </div>
                  )}

                  {selectedEvent.type === 'appointment' && (
                    <div className="space-y-3">
                       <p className="text-xs font-bold text-slate-400 uppercase">Reason for visit</p>
                       <p className="text-sm italic text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-800 p-3 rounded-lg border">
                          "{selectedEvent.raw.reason || 'No clinical notes provided.'}"
                       </p>
                    </div>
                  )}

                  {selectedEvent.type === 'patient' && (
                    <div className="space-y-3">
                       <p className="text-xs font-bold text-slate-400 uppercase">Registered Address</p>
                       <p className="text-sm text-slate-700 dark:text-slate-300">
                          {selectedEvent.raw.address || 'No address provided.'}
                       </p>
                    </div>
                  )}
               </div>
            </div>

            {/* Actions Footer */}
            <div className="pt-6 border-t border-slate-100 dark:border-slate-700 flex justify-between gap-3">
               <Button variant="ghost" icon={Printer} onClick={() => window.print()}>Print Entry</Button>
               <div className="flex gap-2">
                 <Button variant="secondary" onClick={() => setIsEventModalOpen(false)}>Close</Button>
                 <Button icon={ExternalLink} variant="primary">Audit Records</Button>
               </div>
            </div>
          </div>
        )}
      </Modal>

      {/* Global CSS for Report Printing */}
      <style>{`
        @media print {
          body * { visibility: hidden; }
          .print-content, .print-content * { visibility: visible; }
          .print-content { 
            position: absolute; 
            left: 0; 
            top: 0; 
            width: 100%; 
            background: white !important;
            padding: 40px !important;
          }
          .no-print { display: none !important; }
          .Card { border: 1px solid #eee !important; box-shadow: none !important; margin-bottom: 20px; page-break-inside: avoid; }
          .recharts-legend-wrapper { position: static !important; }
          header, aside { display: none !important; }
        }
      `}</style>
    </div>
  );
};

const Hash = ({ size, className }: any) => <span className={className}>#</span>;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Modal, Badge, Input } from '../components/UI';
import { 
  Search, Calendar, Filter, Database, FileText, User, Users, 
  DollarSign, Bed, Activity, Download, Eye, ChevronLeft, ChevronRight,
  FileSpreadsheet, Printer, ChevronDown, Clock, ShieldCheck, Info, X, ExternalLink
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

interface SystemRecord {
  id: string; 
  originalId: number; 
  type: 'Patient' | 'Appointment' | 'Bill' | 'Admission'; 
  reference: string; 
  date: string; 
  primaryEntity: string; 
  associateEntity?: string; 
  status: string; 
  value?: number; 
  details?: any;
}

export const Records = () => {
  const { t, language } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [records, setRecords] = useState<SystemRecord[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedRecord, setSelectedRecord] = useState<SystemRecord | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [pts, apts, bills] = await Promise.all([
          api.getPatients(), 
          api.getAppointments(), 
          api.getBills()
        ]);

        const all: SystemRecord[] = [];

        (pts || []).forEach((p: any) => all.push({ 
          id: `p-${p.id}`, 
          originalId: p.id, 
          type: 'Patient', 
          reference: p.patientId, 
          date: p.createdAt, 
          primaryEntity: p.fullName, 
          status: p.type, 
          details: p 
        }));

        (apts || []).forEach((a: any) => all.push({ 
          id: `a-${a.id}`, 
          originalId: a.id, 
          type: 'Appointment', 
          reference: a.appointmentNumber || `#${a.id}`, 
          date: a.datetime, 
          primaryEntity: a.patientName, 
          associateEntity: a.staffName,
          status: a.status, 
          details: a 
        }));

        (bills || []).forEach((b: any) => all.push({ 
          id: `b-${b.id}`, 
          originalId: b.id, 
          type: 'Bill', 
          reference: b.billNumber, 
          date: b.date, 
          primaryEntity: b.patientName, 
          status: b.status, 
          value: b.totalAmount, 
          details: b 
        }));

        setRecords(all.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
      } catch (e) { 
        console.error(e); 
      } finally { 
        setLoading(false); 
      }
    };
    fetchData();
  }, []);

  const filteredRecords = useMemo(() => records.filter(r => {
      const search = searchTerm.toLowerCase();
      const matchesSearch = 
        r.reference.toLowerCase().includes(search) || 
        r.primaryEntity.toLowerCase().includes(search) ||
        (r.associateEntity && r.associateEntity.toLowerCase().includes(search));

      const matchesType = filterType === 'All' || r.type === filterType;
      const matchesStatus = statusFilter === 'All' || r.status.toLowerCase() === statusFilter.toLowerCase();

      return matchesSearch && matchesType && matchesStatus;
  }), [records, searchTerm, filterType, statusFilter]);

  const handleExportExcel = () => {
    const headers = ["Type", "Date", "Reference", "Entity", "Associate", "Status", "Value"];
    const rows = filteredRecords.map(r => [
      r.type, 
      new Date(r.date).toLocaleString(), 
      r.reference, 
      r.primaryEntity, 
      r.associateEntity || "N/A", 
      r.status, 
      r.value || 0
    ]);

    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(',')).join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `allcare_system_records_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  // Sync Header
  useHeader(
    t('records_title'),
    t('records_subtitle'),
    <div className="relative" ref={exportMenuRef}>
      <Button variant="primary" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
        {t('records_export_button')} <ChevronDown size={14} className={`ml-2 transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
      </Button>
      {showExportMenu && (
        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 z-50 overflow-hidden animate-in fade-in zoom-in-95">
          <div className="px-4 py-2 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
             <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Export Current View</p>
          </div>
          <button onClick={() => { window.print(); setShowExportMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors"><Printer size={16} className="text-primary-500" /><span>Print as PDF Report</span></button>
          <button onClick={handleExportExcel} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors border-t border-slate-100 dark:border-slate-700"><FileSpreadsheet size={16} className="text-emerald-600" /><span>Download CSV (Excel)</span></button>
        </div>
      )}
    </div>
  );

  const totalPages = Math.ceil(filteredRecords.length / itemsPerPage);
  const paginatedRecords = filteredRecords.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const getRecordIcon = (type: string) => {
    switch (type) {
      case 'Patient': return <Users className="text-blue-500" size={18} />;
      case 'Appointment': return <Calendar className="text-violet-500" size={18} />;
      case 'Bill': return <DollarSign className="text-emerald-500" size={18} />;
      default: return <FileText className="text-slate-400" size={18} />;
    }
  };

  const getStatusColor = (status: string) => {
    const s = status.toLowerCase();
    if (s.includes('paid') || s.includes('complete') || s.includes('active')) return 'green';
    if (s.includes('pending') || s.includes('waiting') || s.includes('reserved')) return 'yellow';
    if (s.includes('cancelled') || s.includes('refunded') || s.includes('overdue')) return 'red';
    return 'blue';
  };

  const RecordDetailItem = ({ label, value, icon: Icon }: any) => (
    <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-100 dark:border-slate-800">
      {Icon && <div className="p-2 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-slate-400"><Icon size={16} /></div>}
      <div className="flex-1 min-w-0">
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">{label}</p>
        <p className="text-sm font-bold text-slate-800 dark:text-slate-200 truncate">{value || 'N/A'}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 no-print">
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Total Logs</p>
          <p className="text-2xl font-black text-slate-800 dark:text-white">{records.length.toLocaleString()}</p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Found</p>
          <p className="text-2xl font-black text-primary-600">{filteredRecords.length.toLocaleString()}</p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">Last 24h</p>
          <p className="text-2xl font-black text-slate-800 dark:text-white">
            {records.filter(r => new Date(r.date).getTime() > Date.now() - 86400000).length}
          </p>
        </Card>
        <Card className="!p-4 bg-gradient-to-br from-white to-slate-50 dark:from-slate-800 dark:to-slate-900">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-1">System Health</p>
          <div className="flex items-center gap-2 text-emerald-500 font-bold text-sm mt-1">
             <ShieldCheck size={16} /> Optimal
          </div>
        </Card>
      </div>

      <Card className="!p-0 overflow-hidden shadow-soft border-slate-200 dark:border-slate-700 print:shadow-none print:border-0">
        <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border-b border-slate-200 dark:border-slate-700 flex flex-col lg:flex-row gap-4 no-print">
          <div className="relative flex-1 group">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary-500 transition-colors w-4 h-4" />
            <input 
              type="text" 
              placeholder={t('records_search_placeholder')} 
              className="pl-9 pr-4 py-2.5 w-full rounded-xl border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 outline-none transition-all" 
              value={searchTerm} 
              onChange={e => { setSearchTerm(e.target.value); setCurrentPage(1); }}
            />
          </div>
          <div className="flex gap-3 overflow-x-auto pb-1 lg:pb-0">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shrink-0">
              <Filter size={14} className="text-slate-400" />
              <select 
                className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none cursor-pointer" 
                value={filterType} 
                onChange={e => { setFilterType(e.target.value); setCurrentPage(1); }}
              >
                <option value="All">{t('records_filter_all')}</option>
                <option value="Patient">Patients</option>
                <option value="Appointment">Appointments</option>
                <option value="Bill">Invoices</option>
              </select>
            </div>

            <div className="flex items-center gap-2 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shrink-0">
              <Clock size={14} className="text-slate-400" />
              <select 
                className="bg-transparent border-none text-xs font-bold text-slate-700 dark:text-slate-200 outline-none cursor-pointer" 
                value={statusFilter} 
                onChange={e => { setStatusFilter(e.target.value); setCurrentPage(1); }}
              >
                <option value="All">All Statuses</option>
                <option value="Paid">Paid / Settled</option>
                <option value="Pending">Pending</option>
                <option value="Cancelled">Cancelled</option>
              </select>
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
            <thead className="bg-slate-50 dark:bg-slate-900/80">
              <tr>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Type / Ref</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Event Date</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Primary Entity</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-slate-500 uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-slate-500 uppercase tracking-widest no-print">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-100 dark:divide-slate-700/50">
              {loading ? (
                <tr><td colSpan={5} className="text-center py-20 text-slate-400 font-medium">{t('records_table_loading')}</td></tr>
              ) : paginatedRecords.length === 0 ? (
                <tr><td colSpan={5} className="text-center py-20 text-slate-400 font-medium">{t('records_table_empty')}</td></tr>
              ) : (
                paginatedRecords.map(r => (
                  <tr key={r.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors group cursor-pointer" onClick={() => { setSelectedRecord(r); setIsModalOpen(true); }}>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-slate-100 dark:bg-slate-700 rounded-lg text-slate-500 transition-colors group-hover:bg-primary-100 group-hover:text-primary-600">
                          {getRecordIcon(r.type)}
                        </div>
                        <div>
                          <p className="font-bold text-sm text-slate-800 dark:text-white">{r.reference}</p>
                          <p className="text-[10px] text-slate-400 font-black uppercase tracking-tight">{r.type}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                       <div className="flex flex-col">
                          <span className="text-sm font-medium text-slate-700 dark:text-slate-300">{new Date(r.date).toLocaleDateString()}</span>
                          <span className="text-[10px] text-slate-400 font-mono">{new Date(r.date).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                       </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-bold text-slate-900 dark:text-slate-200">{r.primaryEntity}</div>
                      {r.associateEntity && <div className="text-[10px] text-slate-500 flex items-center gap-1"><User size={10}/> {r.associateEntity}</div>}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <Badge color={getStatusColor(r.status) as any}>{r.status}</Badge>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right no-print">
                      <div className="flex justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                        <Button size="sm" variant="ghost" icon={Eye} />
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 flex flex-col sm:flex-row justify-between items-center gap-4 bg-slate-50/50 dark:bg-slate-900/30 no-print">
           <div className="text-xs text-slate-500 font-medium">
             Showing <span className="font-bold text-slate-900 dark:text-white">{paginatedRecords.length}</span> of <span className="font-bold text-slate-900 dark:text-white">{filteredRecords.length}</span> records
           </div>
           <div className="flex items-center gap-2">
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage === 1} icon={ChevronLeft}>Prev</Button>
             <div className="flex items-center gap-1 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-lg border text-xs font-bold shadow-sm">
                {currentPage} / {totalPages || 1}
             </div>
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage === totalPages}>Next <ChevronRight size={14} className="ml-1"/></Button>
           </div>
        </div>
      </Card>

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={`Record Analysis: ${selectedRecord?.reference}`}
      >
        {selectedRecord && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200 print-content">
            <div className="flex flex-wrap items-center gap-3 p-4 bg-primary-50 dark:bg-primary-900/20 rounded-2xl border border-primary-100 dark:border-primary-800/50">
              <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm text-primary-600">
                 {getRecordIcon(selectedRecord.type)}
              </div>
              <div className="flex-1">
                 <h3 className="font-black text-slate-900 dark:text-white text-lg leading-tight">{selectedRecord.primaryEntity}</h3>
                 <div className="flex items-center gap-2 mt-1">
                    <Badge color="blue">{selectedRecord.type}</Badge>
                    <Badge color={getStatusColor(selectedRecord.status) as any}>{selectedRecord.status}</Badge>
                 </div>
              </div>
              <div className="text-right hidden sm:block">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Entry Date</p>
                 <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{new Date(selectedRecord.date).toLocaleString()}</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <RecordDetailItem label="Reference ID" value={selectedRecord.reference} icon={HashIcon} />
              <RecordDetailItem label="Original Database ID" value={selectedRecord.originalId} icon={Database} />
              {selectedRecord.associateEntity && (
                <RecordDetailItem label="Associate Entity" value={selectedRecord.associateEntity} icon={User} />
              )}
              {selectedRecord.value !== undefined && (
                <RecordDetailItem label="Transaction Value" value={`$${selectedRecord.value.toLocaleString()}`} icon={DollarSign} />
              )}
            </div>

            <div className="space-y-3">
               <h4 className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                 <Info size={14}/> Contextual Data
               </h4>
               <div className="bg-slate-50 dark:bg-slate-900/80 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 min-h-[100px]">
                  {selectedRecord.type === 'Bill' && (
                    <div className="space-y-4">
                       <div className="flex justify-between items-center pb-2 border-b border-slate-200 dark:border-slate-700">
                          <span className="text-sm font-bold">Line Items</span>
                          <span className="text-xs text-slate-500">{(selectedRecord.details?.items || []).length} items</span>
                       </div>
                       <div className="space-y-2">
                          {(selectedRecord.details?.items || []).map((item: any, idx: number) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                               <span className="text-slate-600 dark:text-slate-400">{item.description}</span>
                               <span className="font-mono font-bold">${item.amount.toLocaleString()}</span>
                            </div>
                          ))}
                       </div>
                       <div className="flex justify-between pt-4 border-t border-slate-200 dark:border-slate-700 font-black text-lg">
                          <span>Total Amount</span>
                          <span className="text-primary-600">${selectedRecord.value?.toLocaleString()}</span>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Appointment' && (
                    <div className="grid grid-cols-2 gap-6">
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Service Type</p>
                          <p className="text-sm font-bold">{selectedRecord.details?.type}</p>
                       </div>
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Queue Status</p>
                          <p className="text-sm font-bold">{selectedRecord.status}</p>
                       </div>
                       <div className="col-span-2">
                          <p className="text-xs text-slate-400 font-bold mb-1">Reason for Visit</p>
                          <p className="text-sm italic text-slate-600 dark:text-slate-300">"{selectedRecord.details?.reason || 'No reason provided'}"</p>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Patient' && (
                    <div className="grid grid-cols-3 gap-4 text-center">
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Age</p>
                          <p className="font-black text-lg">{selectedRecord.details?.age}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Gender</p>
                          <p className="font-black text-lg capitalize">{selectedRecord.details?.gender}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Blood</p>
                          <p className="font-black text-lg text-red-500">{selectedRecord.details?.bloodGroup || '-'}</p>
                       </div>
                    </div>
                  )}
               </div>
            </div>

            <div className="pt-6 border-t border-slate-100 dark:border-slate-700 flex justify-between gap-3 no-print">
               <Button variant="ghost" icon={Printer} onClick={() => window.print()}>Print Entry Details</Button>
               <div className="flex gap-2">
                 <Button variant="secondary" onClick={() => setIsModalOpen(false)}>Dismiss</Button>
               </div>
            </div>
          </div>
        )}
      </Modal>

      <style>{`
        @media print {
          body * { display: none !important; }
          .print-content, .print-content * { display: block !important; visibility: visible !important; }
          .print-content { 
            position: absolute !important; 
            left: 0 !important; 
            top: 0 !important; 
            width: 100% !important; 
            margin: 0 !important; 
            padding: 20px !important;
            background: white !important;
          }
          .no-print { display: none !important; }
          .badge, .Badge { border: 1px solid #ccc !important; }
        }
      `}</style>
    </div>
  );
};

const HashIcon = ({ size, className }: any) => <span className={className}>#</span>;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Card, Button, Input, Badge, Modal } from '../components/UI';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area, PieChart, Pie, Cell, Legend, LineChart, Line
} from 'recharts';
import { 
  TrendingUp, Users, Calendar, DollarSign, Download, 
  Activity, ArrowUpRight, ArrowDownRight, Filter, CheckCircle,
  FilePlus, Clock, CreditCard, Shield, Printer, ChevronDown, ChevronRight,
  UserCheck, Stethoscope, Landmark, Layers, History, 
  TrendingDown, Zap, BarChart3, PieChart as PieIcon, Info, User, Hash, ExternalLink, X
} from 'lucide-react';
import { api } from '../services/api';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

export const Reports = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'financial' | 'operational' | 'demographics' | 'activity'>('financial');
  const [rangeType, setRangeType] = useState('30');
  const [customRange, setCustomRange] = useState({ start: '', end: '' });
  const [loading, setLoading] = useState(true);
  const [showExportMenu, setShowExportMenu] = useState(false);
  const exportMenuRef = useRef<HTMLDivElement>(null);

  const [bills, setBills] = useState<any[]>([]);
  const [appointments, setAppointments] = useState<any[]>([]);
  const [patients, setPatients] = useState<any[]>([]);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);

  // Event Detail State
  const [selectedEvent, setSelectedEvent] = useState<any>(null);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);

  // Date Range Logic
  const dateRange = useMemo(() => {
    if (rangeType === 'custom') {
        const start = customRange.start ? new Date(customRange.start + 'T00:00:00') : new Date(0); 
        const end = customRange.end ? new Date(customRange.end + 'T23:59:59.999') : new Date();
        return { start, end };
    }
    const end = new Date(); 
    const start = new Date();
    start.setDate(end.getDate() - parseInt(rangeType));
    start.setHours(0,0,0,0); 
    end.setHours(23,59,59,999);
    return { start, end };
  }, [rangeType, customRange]);

  const filterByDate = (data: any[], dateField: string) => data.filter(item => {
    if (!item[dateField]) return false;
    const d = new Date(item[dateField]);
    return d >= dateRange.start && d <= dateRange.end;
  });

  // --- ANALYTICS CALCULATIONS ---

  const financialStats = useMemo(() => {
    const fb = filterByDate(bills, 'date');
    const ft = filterByDate(transactions, 'date');

    const trMap = new Map();
    fb.forEach(b => {
      const key = new Date(b.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      trMap.set(key, (trMap.get(key) || 0) + (b.paidAmount || 0));
    });

    const methodMap: Record<string, number> = {};
    ft.filter(tx => tx.type === 'income').forEach(tx => {
      const method = tx.method || 'Unknown';
      methodMap[method] = (methodMap[method] || 0) + tx.amount;
    });

    const serviceMap: Record<string, number> = {};
    fb.forEach(bill => {
      (bill.items || []).forEach((item: any) => {
        serviceMap[item.description] = (serviceMap[item.description] || 0) + item.amount;
      });
    });

    const totalIncome = ft.filter(tx => tx.type === 'income').reduce((sum, tx) => sum + tx.amount, 0);
    const totalExpenses = ft.filter(tx => tx.type === 'expense').reduce((sum, tx) => sum + tx.amount, 0);

    return {
      totalRevenue: totalIncome,
      totalExpenses: totalExpenses,
      netProfit: totalIncome - totalExpenses,
      outstanding: fb.reduce((sum, b) => sum + ((b.totalAmount || 0) - (b.paidAmount || 0)), 0),
      avgInvoice: fb.length ? Math.round(fb.reduce((sum, b) => sum + (b.totalAmount || 0), 0) / fb.length) : 0,
      revenueTrend: Array.from(trMap).map(([name, value]) => ({ name, value })),
      incomeByMethod: Object.entries(methodMap).map(([name, value]) => ({ name, value })),
      topServices: Object.entries(serviceMap)
        .map(([name, value]) => ({ name, value }))
        .sort((a,b) => b.value - a.value)
        .slice(0, 5)
    };
  }, [bills, transactions, dateRange]);

  const operationalStats = useMemo(() => {
    const fa = filterByDate(appointments, 'datetime');
    const deptMap: Record<string, number> = {};
    const doctorMap: Record<string, number> = {};

    fa.forEach(a => {
      deptMap[a.type] = (deptMap[a.type] || 0) + 1;
      doctorMap[a.staffName] = (doctorMap[a.staffName] || 0) + 1;
    });

    const completionRate = fa.length ? Math.round((fa.filter(a => a.status === 'completed').length / fa.length) * 100) : 0;

    return {
      total: fa.length,
      completionRate,
      deptRank: Object.entries(deptMap).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value).slice(0, 5),
      doctorRank: Object.entries(doctorMap).map(([name, value]) => ({ name, value })).sort((a,b) => b.value - a.value).slice(0, 5)
    };
  }, [appointments, dateRange]);

  const patientStats = useMemo(() => {
    const fp = filterByDate(patients, 'createdAt');

    const growthMap = new Map();
    fp.forEach(p => {
        const key = new Date(p.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
        growthMap.set(key, (growthMap.get(key) || 0) + 1);
    });

    const male = fp.filter(p => p.gender === 'male').length;
    const female = fp.filter(p => p.gender === 'female').length;

    const pediatric = fp.filter(p => p.age < 18).length;
    const adult = fp.filter(p => p.age >= 18 && p.age < 60).length;
    const senior = fp.filter(p => p.age >= 60).length;

    return {
      total: patients.length,
      newCount: fp.length,
      growthTrend: Array.from(growthMap).map(([name, count]) => ({ name, count })),
      genderSplit: [
        { name: 'Male', value: male },
        { name: 'Female', value: female }
      ],
      ageDist: [
        { name: 'Pediatric', value: pediatric },
        { name: 'Adult', value: adult },
        { name: 'Senior', value: senior }
      ]
    };
  }, [patients, dateRange]);

  const activityStream = useMemo(() => {
    const stream = [
      ...patients.map(p => ({ type: 'patient', name: p.fullName, date: p.createdAt, meta: 'New Registration', id: `p-${p.id}`, raw: p })),
      ...appointments.map(a => ({ type: 'appointment', name: a.patientName, sub: a.staffName, date: a.datetime, meta: a.status, id: `a-${a.id}`, raw: a })),
      ...bills.map(b => ({ type: 'bill', name: b.patientName, sub: `$${b.totalAmount.toLocaleString()}`, date: b.date, meta: b.status, id: `b-${b.id}`, raw: b }))
    ];
    return stream.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 20);
  }, [patients, appointments, bills]);

  const handleExportCSV = () => {
    const headers = ["Metric", "Value", "Context"];
    let rows = [];
    const dateStr = `${dateRange.start.toLocaleDateString()} - ${dateRange.end.toLocaleDateString()}`;

    if (activeTab === 'financial') {
        rows = [
            ["Total Revenue", financialStats.totalRevenue, dateStr],
            ["Total Expenses", financialStats.totalExpenses, dateStr],
            ["Net Profit", financialStats.netProfit, dateStr],
            ["Outstanding Bills", financialStats.outstanding, dateStr]
        ];
    } else {
        rows = [
            ["Total Registered", patientStats.total, "All Time"],
            ["New in Period", patientStats.newCount, dateStr]
        ];
    }

    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].map(e => e.join(',')).join('\n');
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `AllCare_HMS_Report_${activeTab}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  // Sync Header
  useHeader(
    t('reports_title'), 
    t('reports_subtitle'), 
    <div className="relative" ref={exportMenuRef}>
      <Button variant="primary" icon={Download} onClick={() => setShowExportMenu(!showExportMenu)}>
        {t('reports_export_button')} <ChevronDown size={14} className={`ml-2 transition-transform ${showExportMenu ? 'rotate-180' : ''}`} />
      </Button>
      {showExportMenu && (
        <div className="absolute right-0 mt-2 w-56 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 z-50 overflow-hidden animate-in fade-in zoom-in-95">
          <button onClick={() => { window.print(); setShowExportMenu(false); }} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors">
            <Printer size={16} className="text-primary-500" />
            <span>Export as PDF Report</span>
          </button>
          <button onClick={handleExportCSV} className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 dark:text-slate-200 hover:bg-primary-50 dark:hover:bg-primary-900/20 transition-colors border-t border-slate-100 dark:border-slate-700">
            <Landmark size={16} className="text-emerald-600" />
            <span>Download CSV (Excel)</span>
          </button>
        </div>
      )}
    </div>
  );

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [b, a, p, t_data, s] = await Promise.all([
            api.getBills(), 
            api.getAppointments(), 
            api.getPatients(), 
            api.getTransactions(), 
            api.getStaff()
        ]);
        setBills(b || []); 
        setAppointments(a || []); 
        setPatients(p || []); 
        setTransactions(t_data || []); 
        setStaff(s || []);
      } catch (e) { 
        console.error(e); 
      } finally { 
        setLoading(false); 
      }
    };
    fetchData();
  }, []);

  const openEventDetails = (event: any) => {
    setSelectedEvent(event);
    setIsEventModalOpen(true);
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center h-96 gap-4">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      <p className="text-slate-500 font-medium">{t('loading')}</p>
    </div>
  );

  const StatCard = ({ title, value, subtitle, icon: Icon, colorClass, trend }: any) => (
    <Card className="!p-6 bg-white dark:bg-slate-800 shadow-soft border-slate-100 dark:border-slate-700 hover:shadow-lg transition-all duration-300">
      <div className="flex justify-between items-start">
        <div className={`p-3 rounded-2xl ${colorClass} text-white shadow-lg`}>
          <Icon size={24} />
        </div>
        {trend && (
           <div className={`flex items-center gap-1 text-[10px] font-black px-2 py-0.5 rounded-full ${trend > 0 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
              {trend > 0 ? <ArrowUpRight size={10}/> : <ArrowDownRight size={10}/>}
              {Math.abs(trend)}%
           </div>
        )}
      </div>
      <div className="mt-4">
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{title}</p>
        <h3 className="text-2xl font-black text-slate-900 dark:text-white leading-none">{value}</h3>
        {subtitle && <p className="text-[10px] text-slate-500 mt-2 font-bold">{subtitle}</p>}
      </div>
    </Card>
  );

  const RecordDetailItem = ({ label, value, icon: Icon }: any) => (
    <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-100 dark:border-slate-800">
      {Icon && <div className="p-2 bg-white dark:bg-slate-800 rounded-lg shadow-sm text-slate-400"><Icon size={16} /></div>}
      <div className="flex-1 min-w-0">
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">{label}</p>
        <p className="text-sm font-bold text-slate-800 dark:text-slate-200 truncate">{value || 'N/A'}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Filters Bar */}
      <div className="flex flex-col md:flex-row justify-between items-center bg-white dark:bg-slate-800 p-4 rounded-2xl border shadow-soft gap-4 no-print">
        <div className="flex flex-wrap gap-3 items-center w-full md:w-auto">
          <div className="relative group">
            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary-500 w-4 h-4 transition-colors" />
            <select 
              className="pl-9 pr-4 py-2.5 bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-700 dark:text-slate-200 focus:ring-2 focus:ring-primary-500/20 outline-none transition-all cursor-pointer" 
              value={rangeType} 
              onChange={e => setRangeType(e.target.value)}
            >
              <option value="7">{t('reports_time_week')}</option>
              <option value="30">{t('reports_time_month')}</option>
              <option value="90">Quarterly (90 Days)</option>
              <option value="custom">{t('reports_time_custom')}</option>
            </select>
          </div>
          {rangeType === 'custom' && (
            <div className="flex items-center gap-2 animate-in slide-in-from-left-2 duration-300">
              <Input type="date" value={customRange.start} onChange={e => setCustomRange({...customRange, start: e.target.value})} className="!py-2 w-36 shadow-none" />
              <span className="text-slate-400 font-bold">-</span>
              <Input type="date" value={customRange.end} onChange={e => setCustomRange({...customRange, end: e.target.value})} className="!py-2 w-36 shadow-none" />
            </div>
          )}
        </div>

        <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1.5 rounded-2xl shrink-0 w-full md:w-auto overflow-x-auto">
          {[
              { id: 'financial', label: t('reports_tab_financial'), icon: DollarSign },
              { id: 'operational', label: t('reports_tab_operational'), icon: Activity },
              { id: 'demographics', label: t('reports_tab_demographics'), icon: Users },
              { id: 'activity', label: 'Activity Log', icon: History }
          ].map(tab => (
            <button 
              key={tab.id} 
              onClick={() => setActiveTab(tab.id as any)} 
              className={`flex items-center gap-2 px-5 py-2 text-xs font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white dark:bg-slate-800 shadow-soft text-primary-600' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
            >
              <tab.icon size={14}/> {tab.label}
            </button>
          ))}
        </div>
      </div>

      <div className="print-content">
        {/* --- FINANCIAL VIEW --- */}
        {activeTab === 'financial' && (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
