        </div>

        <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 flex flex-col sm:flex-row justify-between items-center gap-4 bg-slate-50/50 dark:bg-slate-900/30 no-print">
           <div className="flex flex-col sm:flex-row items-center gap-4">
             <div className="text-xs text-slate-500 font-medium">
               Showing <span className="font-bold text-slate-900 dark:text-white">{paginatedRecords.length}</span> of <span className="font-bold text-slate-900 dark:text-white">{filteredRecords.length}</span> records
             </div>
             <div className="flex items-center gap-2 text-xs text-slate-500 font-medium">
               <span>{t('patients_pagination_rows')}</span>
               <select 
                 className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-2 py-1 outline-none cursor-pointer"
                 value={itemsPerPage}
                 onChange={(e) => { setItemsPerPage(parseInt(e.target.value)); setCurrentPage(1); }}
               >
                 <option value={10}>10</option>
                 <option value={15}>15</option>
                 <option value={20}>20</option>
                 <option value={50}>50</option>
               </select>
             </div>
           </div>
           <div className="flex items-center gap-2">
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage === 1} icon={ChevronLeft}>Prev</Button>
             <div className="flex items-center gap-1 px-3 py-1.5 bg-white dark:bg-slate-800 rounded-lg border text-xs font-bold shadow-sm">
                {currentPage} / {totalPages || 1}
             </div>
             <Button size="sm" variant="outline" onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage === totalPages}>Next <ChevronRight size={14} className="ml-1"/></Button>
           </div>
        </div>
      </Card>

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={`Record Analysis: ${selectedRecord?.reference}`}
      >
        {selectedRecord && (
          <div className="space-y-8 animate-in fade-in zoom-in-95 duration-200 print-content">
            <div className="flex flex-wrap items-center gap-3 p-4 bg-primary-50 dark:bg-primary-900/20 rounded-2xl border border-primary-100 dark:border-primary-800/50">
              <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm text-primary-600">
                 {getRecordIcon(selectedRecord.type)}
              </div>
              <div className="flex-1">
                 <h3 className="font-black text-slate-900 dark:text-white text-lg leading-tight">{selectedRecord.primaryEntity}</h3>
                 <div className="flex items-center gap-2 mt-1">
                    <Badge color="blue">{selectedRecord.type}</Badge>
                    <Badge color={getStatusColor(selectedRecord.status) as any}>{selectedRecord.status}</Badge>
                 </div>
              </div>
              <div className="text-right hidden sm:block">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Entry Date</p>
                 <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{new Date(selectedRecord.date).toLocaleString()}</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <RecordDetailItem label="Reference ID" value={selectedRecord.reference} icon={HashIcon} />
              <RecordDetailItem label="Original Database ID" value={selectedRecord.originalId} icon={Database} />
              {selectedRecord.associateEntity && (
                <RecordDetailItem label="Associate Entity" value={selectedRecord.associateEntity} icon={User} />
              )}
              {selectedRecord.value !== undefined && (
                <RecordDetailItem label="Transaction Value" value={`$${selectedRecord.value.toLocaleString()}`} icon={DollarSign} />
              )}
            </div>

            <div className="space-y-3">
               <h4 className="flex items-center gap-2 text-xs font-black text-slate-400 uppercase tracking-widest px-1">
                 <Info size={14}/> Contextual Data
               </h4>
               <div className="bg-slate-50 dark:bg-slate-900/80 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 min-h-[100px]">
                  {selectedRecord.type === 'Bill' && (
                    <div className="space-y-4">
                       <div className="flex justify-between items-center pb-2 border-b border-slate-200 dark:border-slate-700">
                          <span className="text-sm font-bold">Line Items</span>
                          <span className="text-xs text-slate-500">{(selectedRecord.details?.items || []).length} items</span>
                       </div>
                       <div className="space-y-2">
                          {(selectedRecord.details?.items || []).map((item: any, idx: number) => (
                            <div key={idx} className="flex justify-between items-center text-sm">
                               <span className="text-slate-600 dark:text-slate-400">{item.description}</span>
                               <span className="font-mono font-bold">${item.amount.toLocaleString()}</span>
                            </div>
                          ))}
                       </div>
                       <div className="flex justify-between pt-4 border-t border-slate-200 dark:border-slate-700 font-black text-lg">
                          <span>Total Amount</span>
                          <span className="text-primary-600">${selectedRecord.value?.toLocaleString()}</span>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Appointment' && (
                    <div className="grid grid-cols-2 gap-6">
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Service Type</p>
                          <p className="text-sm font-bold">{selectedRecord.details?.type}</p>
                       </div>
                       <div>
                          <p className="text-xs text-slate-400 font-bold mb-1">Queue Status</p>
                          <p className="text-sm font-bold">{selectedRecord.status}</p>
                       </div>
                       <div className="col-span-2">
                          <p className="text-xs text-slate-400 font-bold mb-1">Reason for Visit</p>
                          <p className="text-sm italic text-slate-600 dark:text-slate-300">"{selectedRecord.details?.reason || 'No reason provided'}"</p>
                       </div>
                    </div>
                  )}

                  {selectedRecord.type === 'Patient' && (
                    <div className="grid grid-cols-3 gap-4 text-center">
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Age</p>
                          <p className="font-black text-lg">{selectedRecord.details?.age}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Gender</p>
                          <p className="font-black text-lg capitalize">{selectedRecord.details?.gender}</p>
                       </div>
                       <div className="p-3 bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800">
                          <p className="text-[10px] text-slate-400 font-bold mb-1 uppercase">Blood</p>
                          <p className="font-black text-lg text-red-500">{selectedRecord.details?.bloodGroup || '-'}</p>
                       </div>
                    </div>
                  )}
               </div>
            </div>

            <div className="pt-6 border-t border-slate-100 dark:border-slate-700 flex justify-between gap-3 no-print">
               <Button variant="ghost" icon={Printer} onClick={() => window.print()}>Print Entry Details</Button>
               <div className="flex gap-2">
                 <Button variant="secondary" onClick={() => setIsModalOpen(false)}>Dismiss</Button>
               </div>
            </div>
          </div>
        )}
      </Modal>

      <style>{`
        @media print {
          body * { display: none !important; }
          .print-content, .print-content * { display: block !important; visibility: visible !important; }
          .print-content { 
            position: absolute !important; 
            left: 0 !important; 
            top: 0 !important; 
            width: 100% !important; 
            margin: 0 !important; 
            padding: 20px !important;
            background: white !important;
          }
          .no-print { display: none !important; }
          .badge, .Badge { border: 1px solid #ccc !important; }
        }
      `}</style>
    </div>
  );
};

const HashIcon = ({ size, className }: any) => <span className={className}>#</span>;

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Wrench, Settings as SettingsIcon, Building, Database, Trash2, Plus, Save, Edit, 
  Bed, Users, Loader2, CheckCircle, XCircle, AlertTriangle, Upload, Download, Server, 
  CreditCard, RotateCcw, Shield, Lock, Activity, RefreshCw, Briefcase, FlaskConical, Stethoscope,
  Landmark, ShieldCheck, Cpu, HardDrive, Clock
} from 'lucide-react';
import { api } from '../services/api';
import { LabTestCatalog, NurseServiceCatalog, OperationCatalog, Bed as BedType, User, Role, TaxRate, PaymentMethod, InsuranceProvider, MedicalStaff } from '../types';
import { Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';
import { useHeader } from '../context/HeaderContext';

type ConfigTab = 'general' | 'users' | 'beds' | 'catalogs' | 'data' | 'financial' | 'diagnostics';
type CatalogType = 'departments' | 'specializations' | 'lab' | 'nurse' | 'ops' | 'insurance' | 'banks';

export const Configuration = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<ConfigTab>('general');
  const [activeCatalog, setActiveCatalog] = useState<CatalogType>('departments');
  const [loading, setLoading] = useState(true);

  // Data States
  const [settings, setSettings] = useState({ hospitalName: '', hospitalAddress: '', hospitalPhone: '' });
  const [users, setUsers] = useState<User[]>([]);
  const [rolePermissions, setRolePermissions] = useState<Record<string, string[]>>({});
  const [beds, setBeds] = useState<BedType[]>([]);
  const [taxRates, setTaxRates] = useState<TaxRate[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [catalogData, setCatalogData] = useState<any[]>([]);
  const [healthData, setHealthData] = useState<any>(null);

  // UI States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<string>('');
  const [selectedItem, setSelectedItem] = useState<any>(null);
  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');
  const [confirmState, setConfirmState] = useState<any>({ isOpen: false, title: '', message: '', action: () => {} });

  // Sync Header
  useHeader(t('config_title'), '');

  const loadData = async () => {
    setLoading(true);
    try {
      const hospitalName = localStorage.getItem('h_name') || 'AllCare Hospital';
      const hospitalAddress = localStorage.getItem('h_address') || '';
      const hospitalPhone = localStorage.getItem('h_phone') || '';
      setSettings({ hospitalName, hospitalAddress, hospitalPhone });

      const [u, p, b, tax, pm] = await Promise.all([
        api.getSystemUsers(),
        api.getRolePermissions(),
        api.getBeds(),
        api.getTaxRates(),
        api.getPaymentMethods()
      ]);

      setUsers(u || []);
      setRolePermissions(p || {});
      setBeds(b || []);
      setTaxRates(tax || []);
      setPaymentMethods(pm || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const loadCatalog = async (type: CatalogType) => {
    setLoading(true);
    try {
      let data = [];
      switch(type) {
        case 'departments': data = await api.getDepartments(); break;
        case 'specializations': data = await api.getSpecializations(); break;
        case 'lab': data = await api.getLabTests(); break;
        case 'nurse': data = await api.getNurseServices(); break;
        case 'ops': data = await api.getOperations(); break;
        case 'insurance': data = await api.getInsuranceProviders(); break;
        case 'banks': data = await api.getBanks(); break;
      }
      setCatalogData(data || []);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);
  useEffect(() => { if (activeTab === 'catalogs') loadCatalog(activeCatalog); }, [activeTab, activeCatalog]);

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    setProcessStatus('processing');
    localStorage.setItem('h_name', settings.hospitalName);
    localStorage.setItem('h_address', settings.hospitalAddress);
    localStorage.setItem('h_phone', settings.hospitalPhone);
    setTimeout(() => {
      setProcessStatus('success');
      setProcessMessage(t('config_toast_settings_saved'));
      setTimeout(() => setProcessStatus('idle'), 1500);
    }, 500);
  };

  const handleBackup = async () => {
    try {
      await api.downloadBackup();
    } catch (e) {
      setProcessStatus('error');
      setProcessMessage("Backup failed.");
    }
  };

  const handleRestore = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setConfirmState({
      isOpen: true,
      title: t('config_dialog_overwrite_db_title'),
      message: t('config_dialog_overwrite_db_msg'),
      action: async () => {
        setProcessStatus('processing');
        try {
          await api.restoreDatabase(file);
          setProcessStatus('success');
          setProcessMessage(t('config_toast_db_restored'));
          setTimeout(() => window.location.reload(), 1500);
        } catch (err: any) {
          setProcessStatus('error');
          setProcessMessage(err.response?.data?.error || "Restore failed.");
        }
      }
    });
  };

  const handleReset = () => {
    setConfirmState({
      isOpen: true,
      title: t('config_dialog_factory_reset_title'),
      message: t('config_dialog_factory_reset_msg'),
      action: async () => {
        setProcessStatus('processing');
        try {
          await api.resetDatabase();
          setProcessStatus('success');
          setProcessMessage(t('config_toast_db_reset'));
          setTimeout(() => window.location.reload(), 1500);
        } catch (e) {
          setProcessStatus('error');
          setProcessMessage("Reset failed.");
        }
      }
    });
  };

  const runDiagnostics = async () => {
    setProcessStatus('processing');
    setProcessMessage("Analyzing system nodes...");
    try {
      const data = await api.checkSystemHealth();
      setHealthData(data);
      setProcessStatus('idle');
    } catch (e) {
      setProcessStatus('error');
      setProcessMessage("Health check failed.");
    }
  };

  const togglePermission = async (role: string, perm: string) => {
    const current = rolePermissions[role] || [];
    const updated = current.includes(perm) ? current.filter(p => p !== perm) : [...current, perm];
    try {
      await api.updateRolePermissions(role, updated);
      setRolePermissions({ ...rolePermissions, [role]: updated });
    } catch (e) {
      console.error("Failed to update permission");
    }
  };

  const getPermissionLabel = (perm: string) => {
    return perm.split('_').map(w => w.charAt(0) + w.slice(1).toLowerCase()).join(' ');
  };

  const permissionGroups = [
    { name: t('permission_group_general'), perms: [Permissions.VIEW_DASHBOARD, Permissions.VIEW_REPORTS, Permissions.VIEW_RECORDS] },
    { name: t('permission_group_patients'), perms: [Permissions.VIEW_PATIENTS, Permissions.MANAGE_PATIENTS, Permissions.DELETE_PATIENTS] },
    { name: t('permission_group_appointments'), perms: [Permissions.VIEW_APPOINTMENTS, Permissions.MANAGE_APPOINTMENTS, Permissions.DELETE_APPOINTMENTS] },
    { name: t('permission_group_billing'), perms: [Permissions.VIEW_BILLING, Permissions.MANAGE_BILLING, Permissions.DELETE_BILLING] },
    { name: t('permission_group_hr'), perms: [Permissions.VIEW_HR, Permissions.MANAGE_HR, Permissions.DELETE_HR] },
    { name: t('permission_group_admissions'), perms: [Permissions.VIEW_ADMISSIONS, Permissions.MANAGE_ADMISSIONS, Permissions.DELETE_ADMISSIONS] },
    { name: t('permission_group_laboratory'), perms: [Permissions.VIEW_LABORATORY, Permissions.MANAGE_LABORATORY, Permissions.DELETE_LABORATORY] },
    { name: t('permission_group_operations'), perms: [Permissions.VIEW_OPERATIONS, Permissions.MANAGE_OPERATIONS, Permissions.DELETE_OPERATIONS] },
    { name: t('permission_group_system'), perms: [Permissions.VIEW_SETTINGS, Permissions.MANAGE_SETTINGS, Permissions.MANAGE_CONFIGURATION] },
  ];

  if (loading && !catalogData.length && !users.length) return (
    <div className="flex flex-col items-center justify-center h-96 gap-4">
      <Loader2 className="animate-spin text-primary-600" size={40} />
      <p className="text-slate-500 font-medium">{t('loading')}</p>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Processing HUD */}
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 text-center">
            {processStatus === 'processing' && <Loader2 className="w-16 h-16 text-primary-600 animate-spin mb-4" />}
            {processStatus === 'success' && <CheckCircle size={48} className="text-green-600 mb-4" />}
            {processStatus === 'error' && <XCircle size={48} className="text-red-600 mb-4" />}
            <h3 className="text-xl font-bold">{processStatus === 'processing' ? t('processing') : processStatus === 'success' ? t('success') : t('error')}</h3>
            <p className="text-sm text-slate-500 mt-2">{processMessage}</p>
